window.trendingPapers = {
    "today": [{"paper": {"id": "2606.27377", "authors": [{"_id": "6a3dda9a3b43e283349ec108", "name": "Wei Zhou", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec109", "name": "Xiongwei Zhu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10a", "name": "Zelin Xu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10b", "name": "Bo Dong", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10c", "name": "Lixue Gong", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10d", "name": "Yongyuan Liang", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10e", "name": "Meng Chu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10f", "name": "Leigang Qu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec110", "name": "Lingdong Kong", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec111", "name": "Wei Liu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec112", "name": "Tat-Seng Chua", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/T73l6bcCjjqWVVvz1mioW.qt"], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "DanceOPD: On-Policy Generative Field Distillation", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Modern image generation demands a single model that unifies diverse capabilities, including text-to-image (T2I), local editing, and global editing. However, these capabilities are rarely naturally aligned and often conflict. For instance, editing tends to degrade T2I performance, while global and local editing interfere with each other. Consequently, effectively composing these capabilities has become a central challenge for image generation model training. To tackle this, we introduce DanceOPD, an on-policy generative field distillation framework for flow-matching models that routes each sample to one capability field, queries one low-noise student-induced state, and trains with a simple velocity MSE objective. With each capability source defined as a velocity field over the shared flow state space, the student learns from fields queried on its own rollout states to compose expert capabilities. This formulation also absorbs operator-defined fields such as classifier-free guidance. Comprehensive experiments on T2I, editing, realism-field absorption, and CFG absorption show that our approach improves multi-capability composition, strengthening target capabilities while preserving anchor generation quality. We believe this work establishes a practical route for generative field distillation in flow-matching models.", "upvotes": 54, "discussionId": "6a3dda9a3b43e283349ec113", "projectPage": "https://danceopd.github.io/", "ai_summary": "A novel on-policy generative field distillation framework called DanceOPD is proposed to unify text-to-image generation, local editing, and global editing capabilities in flow-matching models through capability-specific routing and velocity-based training.", "ai_keywords": ["generative field distillation", "flow-matching models", "on-policy", "velocity MSE objective", "velocity field", "classifier-free guidance", "text-to-image", "local editing", "global editing", "student model", "expert capabilities"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u4ee3\u56fe\u50cf\u751f\u6210\u9700\u8981\u4e00\u4e2a\u7edf\u4e00\u7684\u6a21\u578b\uff0c\u5177\u5907\u6587\u672c\u5230\u56fe\u50cf\u751f\u6210\u3001\u5c40\u90e8\u7f16\u8f91\u548c\u5168\u5c40\u7f16\u8f91\u7b49\u591a\u79cd\u529f\u80fd\u3002</li>\n    <li>\u8fd9\u4e9b\u529f\u80fd\u4e4b\u95f4\u5f80\u5f80\u4e0d\u517c\u5bb9\uff0c\u53ef\u80fd\u5bfc\u81f4\u6027\u80fd\u4e0b\u964d\uff0c\u5982\u7f16\u8f91\u4f1a\u5f71\u54cd\u6587\u672c\u5230\u56fe\u50cf\u751f\u6210\u7684\u6548\u679c\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u8fd9\u4e2a\u95ee\u9898\uff0c\u63d0\u51fa\u4e86DanceOPD\u6846\u67b6\uff0c\u901a\u8fc7\u6d41\u5339\u914d\u6a21\u578b\u6765\u6709\u6548\u7ec4\u5408\u8fd9\u4e9b\u529f\u80fd\u3002</li>\n    <li>\u8be5\u6846\u67b6\u901a\u8fc7\u7b80\u5355\u7684\u901f\u5ea6\u5747\u65b9\u8bef\u5dee\u76ee\u6807\u6765\u8bad\u7ec3\u6a21\u578b\uff0c\u4f7f\u5176\u80fd\u591f\u5b66\u4e60\u548c\u6574\u5408\u4e0d\u540c\u7684\u529f\u80fd\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cDanceOPD\u5728\u591a\u529f\u80fd\u7ec4\u5408\u65b9\u9762\u8868\u73b0\u4f18\u5f02\uff0c\u540c\u65f6\u4fdd\u6301\u751f\u6210\u8d28\u91cf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Modern image generation needs a single model that can handle different tasks like text-to-image, local editing, and global editing.</li>\n    <li>These tasks often conflict with each other, making it hard to combine them effectively.</li>\n    <li>To address this, the researchers developed DanceOPD, a new framework that focuses on training models efficiently for these tasks.</li>\n    <li>DanceOPD uses a technique where each sample is assigned to one specific capability, allowing the model to learn better from each task.</li>\n    <li>Experiments show that this approach improves the model's ability to combine different tasks while maintaining high-quality image generation.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "DanceOPD: On-Policy Generative Field Distillation", "summary": "Modern image generation demands a single model that unifies diverse capabilities, including text-to-image (T2I), local editing, and global editing. However, these capabilities are rarely naturally aligned and often conflict. For instance, editing tends to degrade T2I performance, while global and local editing interfere with each other. Consequently, effectively composing these capabilities has become a central challenge for image generation model training. To tackle this, we introduce DanceOPD, an on-policy generative field distillation framework for flow-matching models that routes each sample to one capability field, queries one low-noise student-induced state, and trains with a simple velocity MSE objective. With each capability source defined as a velocity field over the shared flow state space, the student learns from fields queried on its own rollout states to compose expert capabilities. This formulation also absorbs operator-defined fields such as classifier-free guidance. Comprehensive experiments on T2I, editing, realism-field absorption, and CFG absorption show that our approach improves multi-capability composition, strengthening target capabilities while preserving anchor generation quality. We believe this work establishes a practical route for generative field distillation in flow-matching models.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/T73l6bcCjjqWVVvz1mioW.qt"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.27377.png", "numComments": 2, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 323, "isUserFollowing": false}, "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.27313", "authors": [{"_id": "6a3de2d23b43e283349ec181", "name": "Xumin Yu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec182", "name": "Zuyan Liu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec183", "name": "Zhenyu Yang", "hidden": false}, {"_id": "6a3de2d23b43e283349ec184", "name": "Yuhao Dong", "hidden": false}, {"_id": "6a3de2d23b43e283349ec185", "name": "Shengsheng Qian", "hidden": false}, {"_id": "6a3de2d23b43e283349ec186", "name": "Jiwen Lu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec187", "name": "Han Hu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec188", "name": "Yongming Rao", "hidden": false}], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "ViQ: Text-Aligned Visual Quantized Representations at Any Resolution", "submittedOnDailyBy": {"_id": "64f001bfabd9fb1914398bd5", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64f001bfabd9fb1914398bd5/9teH82hkBI4csIz_WQh5q.jpeg", "isPro": false, "fullname": "liuzuyan", "user": "Zuyan", "type": "user", "name": "Zuyan"}, "summary": "A unified representation for text and vision is a natural pursuit, as it enables simpler multimodal modeling and more efficient training. However, representing images as discrete signals in the same way as text inevitably introduces severe information loss. Existing work struggles to balance low-level details and high-level semantics in discrete representations: reconstruction-oriented representations often lack semantic information, whereas semantically stronger features typically suffer from severe loss of detail. We present ViQ, a Visual Quantized Representations framework, which is designed to balance semantics and details in discrete representations while supporting inputs at native resolutions, thereby enabling it to serve as a unified and general discrete representation for arbitrary visual inputs. Our approach structures quantization learning into two stages: text-aligned pre-training and feature discretization. With text-aligned pre-training, we enhance the visual encoder semantic-rich supervision from the pretrained language model and enable it to process native-resolution visual inputs. During discretization, we propose a proximal representation learning strategy to progressively compact the feature space, along with a position-aware head-wise quantization mechanism that enables flexible processing of arbitrary resolutions. Extensive experiments on multimodal tasks demonstrate that ViQ achieves competitive performance compared to state-of-the-art multimodal vision encoders with continuous and high-dimensional visual features, while maintaining high precision in low-level reconstruction. We also show that multimodal training with visual quantized representations largely improves efficiency, yielding up to 20\\%-70\\% acceleration with different base LLMs and training recipes.", "upvotes": 36, "discussionId": "6a3de2d33b43e283349ec189", "githubRepo": "https://github.com/yuxumin/ViQ", "githubRepoAddedBy": "user", "ai_summary": "ViQ presents a visual quantization framework that balances semantic richness and detail preservation in discrete representations, enabling efficient multimodal training with native-resolution inputs.", "ai_keywords": ["visual quantized representations", "text-aligned pre-training", "feature discretization", "proximal representation learning", "position-aware head-wise quantization", "multimodal modeling", "visual encoder", "discrete representations", "semantic richness", "low-level reconstruction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 36, "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86ViQ\u6846\u67b6\uff0c\u65e8\u5728\u5e73\u8861\u79bb\u6563\u8868\u793a\u4e2d\u7684\u8bed\u4e49\u548c\u7ec6\u8282\uff0c\u540c\u65f6\u652f\u6301\u539f\u59cb\u5206\u8fa8\u7387\u7684\u8f93\u5165\u3002</li>\n    <li>\u8be5\u6846\u67b6\u901a\u8fc7\u6587\u672c\u5bf9\u9f50\u7684\u9884\u8bad\u7ec3\u548c\u7279\u5f81\u79bb\u6563\u5316\u4e24\u4e2a\u9636\u6bb5\u6765\u7ed3\u6784\u5316\u91cf\u5316\u5b66\u4e60\u3002</li>\n    <li>\u5728\u6587\u672c\u5bf9\u9f50\u7684\u9884\u8bad\u7ec3\u4e2d\uff0c\u589e\u5f3a\u4e86\u89c6\u89c9\u7f16\u7801\u5668\u7684\u8bed\u4e49\u4e30\u5bcc\u6027\uff0c\u4f7f\u5176\u80fd\u591f\u5904\u7406\u539f\u59cb\u5206\u8fa8\u7387\u7684\u89c6\u89c9\u8f93\u5165\u3002</li>\n    <li>\u79bb\u6563\u5316\u9636\u6bb5\u4f7f\u7528\u4e86\u4e00\u79cd\u6e10\u8fdb\u5f0f\u7279\u5f81\u7a7a\u95f4\u538b\u7f29\u7684\u7b56\u7565\uff0c\u5e76\u5f15\u5165\u4e86\u4f4d\u7f6e\u611f\u77e5\u7684\u91cf\u5316\u673a\u5236\uff0c\u4ee5\u7075\u6d3b\u5904\u7406\u4e0d\u540c\u5206\u8fa8\u7387\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cViQ\u5728\u591a\u6a21\u6001\u4efb\u52a1\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u8bad\u7ec3\u6548\u7387\u63d0\u5347\u53ef\u8fbe20%-70%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>ViQ is a new framework that connects text and images effectively for better training and modeling.</li>\n    <li>It aims to maintain a balance between detailed image information and meaningful semantic content.</li>\n    <li>The framework uses a two-step process: first, it aligns visual data with text for better understanding, then it compresses the image features carefully.</li>\n    <li>ViQ allows for processing images at their original quality and shows strong performance in various tasks compared to other models.</li>\n    <li>It also significantly speeds up training, improving efficiency by 20% to 70% with different language models and methods.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "ViQ: Text-Aligned Visual Quantized Representations at Any Resolution", "summary": "A unified representation for text and vision is a natural pursuit, as it enables simpler multimodal modeling and more efficient training. However, representing images as discrete signals in the same way as text inevitably introduces severe information loss. Existing work struggles to balance low-level details and high-level semantics in discrete representations: reconstruction-oriented representations often lack semantic information, whereas semantically stronger features typically suffer from severe loss of detail. We present ViQ, a Visual Quantized Representations framework, which is designed to balance semantics and details in discrete representations while supporting inputs at native resolutions, thereby enabling it to serve as a unified and general discrete representation for arbitrary visual inputs. Our approach structures quantization learning into two stages: text-aligned pre-training and feature discretization. With text-aligned pre-training, we enhance the visual encoder semantic-rich supervision from the pretrained language model and enable it to process native-resolution visual inputs. During discretization, we propose a proximal representation learning strategy to progressively compact the feature space, along with a position-aware head-wise quantization mechanism that enables flexible processing of arbitrary resolutions. Extensive experiments on multimodal tasks demonstrate that ViQ achieves competitive performance compared to state-of-the-art multimodal vision encoders with continuous and high-dimensional visual features, while maintaining high precision in low-level reconstruction. We also show that multimodal training with visual quantized representations largely improves efficiency, yielding up to 20\\%-70\\% acceleration with different base LLMs and training recipes.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.27313.png", "numComments": 1, "submittedBy": {"_id": "64f001bfabd9fb1914398bd5", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64f001bfabd9fb1914398bd5/9teH82hkBI4csIz_WQh5q.jpeg", "fullname": "liuzuyan", "name": "Zuyan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.26790", "authors": [{"_id": "6a3de03c3b43e283349ec169", "name": "Shuo Yang", "hidden": false}, {"_id": "6a3de03c3b43e283349ec16a", "name": "Jinyang Wu", "hidden": false}, {"_id": "6a3de03c3b43e283349ec16b", "name": "Zhengxi Lu", "hidden": false}, {"_id": "6a3de03c3b43e283349ec16c", "name": "Yuhao Shen", "hidden": false}, {"_id": "6a3de03c3b43e283349ec16d", "name": "Fan Zhang", "hidden": false}, {"_id": "6a3de03c3b43e283349ec16e", "name": "Lang Feng", "hidden": false}, {"_id": "6a3de03c3b43e283349ec16f", "name": "Shuai Zhang", "hidden": false}, {"_id": "6a3de03c3b43e283349ec170", "name": "Haoran Luo", "hidden": false}, {"_id": "6a3de03c3b43e283349ec171", "name": "Zheng Lian", "hidden": false}, {"_id": "6a3de03c3b43e283349ec172", "name": "Zhengqi Wen", "hidden": false}, {"_id": "6a3de03c3b43e283349ec173", "name": "Jianhua Tao", "hidden": false}], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "OPID: On-Policy Skill Distillation for Agentic Reinforcement Learning", "submittedOnDailyBy": {"_id": "6747de57f8cab58c22ec94a2", "avatarUrl": "/avatars/5bae0341862fac24564781c0fa32aac5.svg", "isPro": false, "fullname": "Jinyang Wu", "user": "Jinyang23", "type": "user", "name": "Jinyang23"}, "summary": "Outcome-based reinforcement learning provides a stable optimization backbone for language agents, but its sparse trajectory-level rewards provide little guidance on which intermediate decisions should be reinforced or suppressed. On-policy self-distillation offers dense token-level supervision, yet existing skill-conditioned variants often rely on external skill memories or retrieved privileged context, which are costly to maintain and can be mismatched with the state distribution induced by the current policy in multi-turn interaction. We propose OPID (On-Policy Skill Distillation), a framework that extracts skill supervision directly from completed on-policy trajectories. OPID represents trajectory hindsight as hierarchical skills: episode-level skills capture global workflows or failure-avoidance rules, while step-level skills capture local decision knowledge at critical timesteps. A critical-first routing mechanism uses step-level skills when critical decisions are identified and falls back to episode-level skills as default guidance otherwise. The selected skill is injected into the interaction history, allowing the old policy to re-score the same sampled response under both original and skill-augmented contexts. The resulting log-probability shift yields a token-level self-distillation advantage, which is combined with the outcome advantage for policy optimization. OPID thus preserves RL as the primary training objective while introducing dense, distribution-matched hindsight supervision. Experiments on ALFWorld, WebShop and Search-based QA demonstrate that OPID generally improves agent performance, sample efficiency, and robustness over outcome-only RL and existing skill-distillation baselines. Our code is available at https://github.com/jinyangwu/OPID/tree/main.", "upvotes": 35, "discussionId": "6a3de03d3b43e283349ec174", "githubRepo": "https://github.com/jinyangwu/OPID", "githubRepoAddedBy": "user", "ai_summary": "On-policy skill distillation framework extracts dense hindsight supervision from completed trajectories to improve language agent training efficiency and performance.", "ai_keywords": ["reinforcement learning", "self-distillation", "skill-conditioned variants", "on-policy trajectories", "hierarchical skills", "critical-first routing", "token-level supervision", "policy optimization", "outcome-based reinforcement learning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 26, "summary_zh": "<ul>\n    <li>OPID\u662f\u4e00\u4e2a\u57fa\u4e8e\u7b56\u7565\u7684\u6280\u80fd\u84b8\u998f\u6846\u67b6\uff0c\u4ece\u5b8c\u6210\u7684\u7b56\u7565\u8f68\u8ff9\u4e2d\u63d0\u53d6\u6280\u80fd\u76d1\u7763\u3002</li>\n    <li>\u8be5\u6846\u67b6\u4f7f\u7528\u5c42\u6b21\u5316\u6280\u80fd\u6765\u8868\u793a\u8f68\u8ff9\u540e\u89c1\uff0c\u5206\u4e3a\u5168\u5c40\u6280\u80fd\u548c\u5c40\u90e8\u51b3\u7b56\u77e5\u8bc6\u3002</li>\n    <li>\u901a\u8fc7\u5173\u952e\u51b3\u7b56\u8bc6\u522b\u673a\u5236\uff0cOPID\u5728\u5173\u952e\u65f6\u523b\u4f7f\u7528\u5c40\u90e8\u6280\u80fd\uff0c\u5176\u4ed6\u65f6\u5019\u5219\u4f7f\u7528\u5168\u5c40\u6280\u80fd\u63d0\u4f9b\u6307\u5bfc\u3002</li>\n    <li>OPID\u7ed3\u5408\u4e86\u81ea\u84b8\u998f\u7684\u4f18\u52bf\u548c\u7ed3\u679c\u4f18\u52bf\uff0c\u4f18\u5316\u4e86\u7b56\u7565\u8bad\u7ec3\u76ee\u6807\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u8868\u660e\uff0cOPID\u5728\u591a\u4e2a\u4efb\u52a1\u4e0a\u63d0\u5347\u4e86\u4ee3\u7406\u7684\u8868\u73b0\u3001\u6837\u672c\u6548\u7387\u548c\u9c81\u68d2\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Outcome-based reinforcement learning helps language agents optimize performance, but it lacks detailed guidance for intermediate decisions.</li>\n    <li>On-policy self-distillation provides more detailed feedback at the token level, but often depends on external memories that can be difficult to manage.</li>\n    <li>OPID (On-Policy Skill Distillation) is a new framework that extracts skills directly from completed interactions to enhance decision-making.</li>\n    <li>It uses two levels of skills: episode-level for overall strategies and step-level for specific decisions, allowing for more effective learning.</li>\n    <li>Tests show that OPID improves agent performance and efficiency compared to traditional methods and existing skill distillation approaches.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "OPID: On-Policy Skill Distillation for Agentic Reinforcement Learning", "summary": "Outcome-based reinforcement learning provides a stable optimization backbone for language agents, but its sparse trajectory-level rewards provide little guidance on which intermediate decisions should be reinforced or suppressed. On-policy self-distillation offers dense token-level supervision, yet existing skill-conditioned variants often rely on external skill memories or retrieved privileged context, which are costly to maintain and can be mismatched with the state distribution induced by the current policy in multi-turn interaction. We propose OPID (On-Policy Skill Distillation), a framework that extracts skill supervision directly from completed on-policy trajectories. OPID represents trajectory hindsight as hierarchical skills: episode-level skills capture global workflows or failure-avoidance rules, while step-level skills capture local decision knowledge at critical timesteps. A critical-first routing mechanism uses step-level skills when critical decisions are identified and falls back to episode-level skills as default guidance otherwise. The selected skill is injected into the interaction history, allowing the old policy to re-score the same sampled response under both original and skill-augmented contexts. The resulting log-probability shift yields a token-level self-distillation advantage, which is combined with the outcome advantage for policy optimization. OPID thus preserves RL as the primary training objective while introducing dense, distribution-matched hindsight supervision. Experiments on ALFWorld, WebShop and Search-based QA demonstrate that OPID generally improves agent performance, sample efficiency, and robustness over outcome-only RL and existing skill-distillation baselines. Our code is available at https://github.com/jinyangwu/OPID/tree/main.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.26790.png", "numComments": 1, "submittedBy": {"_id": "6747de57f8cab58c22ec94a2", "avatarUrl": "/avatars/5bae0341862fac24564781c0fa32aac5.svg", "fullname": "Jinyang Wu", "name": "Jinyang23", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 11, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.26907", "authors": [{"_id": "6a3ddcfb3b43e283349ec11d", "name": "Zekai Zhang", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec11e", "name": "Jiahao Li", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec11f", "name": "Jie Zhang", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec120", "name": "Kaiyuan Gao", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec121", "name": "Kun Yan", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec122", "name": "Lihan Jiang", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec123", "name": "Ningyuan Tang", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec124", "name": "Shengming Yin", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec125", "name": "Tianhe Wu", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec126", "name": "Xiaoyue Chen", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec127", "name": "Xiao Xu", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec128", "name": "Yan Shu", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec129", "name": "Yanran Zhang", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec12a", "name": "Yixian Xu", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec12b", "name": "Yuxiang Chen", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec12c", "name": "Zhendong Wang", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec12d", "name": "Zihao Liu", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec12e", "name": "Zikai Zhou", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec12f", "name": "Huishuai Zhang", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec130", "name": "Dongyan Zhao", "hidden": false}, {"_id": "6a3ddcfb3b43e283349ec131", "name": "Chenfei Wu", "hidden": false}], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "Qwen-Image-Agent: Bridging the Context Gap in Real-World Image Generation", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "While text-to-image (T2I) models have achieved remarkable progress, they struggle with real-world requests that are often underspecified, implicit, or dependent on up-to-date knowledge. We identify this challenge as the Context Gap: the mismatch between the user context and the sufficient generation context for T2I models. To bridge this gap, we propose Qwen-Image-Agent, a unified agentic framework that integrates plan, reason, search, memory and feedback in a context-centric manner. Qwen-Image-Agent treats user input as partial context and progressively constructs the generation context through Context-Aware Planning and Context Grounding. Specifically, Context-Aware Planning identifies missing context and plans how it should be acquired and used, while Context Grounding gathers this context from reason, search, memory, and feedback. To evaluate agentic image generation, we further introduce Image Agent Bench (IA-Bench), a benchmark covering four core image agent capabilities: Plan, Reason, Search, and Memory. Experiments on IA-Bench, Mindbench and WISE-Verified show that Qwen-Image-Agent outperforms strong baselines and achieves state-of-the-art performance.", "upvotes": 34, "discussionId": "6a3ddcfc3b43e283349ec132", "ai_summary": "A unified agentic framework called Qwen-Image-Agent is proposed to address the context gap in text-to-image generation by progressively constructing complete generation context through planning, reasoning, searching, and memory mechanisms.", "ai_keywords": ["text-to-image models", "context gap", "agentic framework", "context-aware planning", "context grounding", "image agent bench", "image agent capabilities", "plan", "reason", "search", "memory"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6215ca5692c0ecfba9186921/hrRM50-6XcdWgg2AKpENG.jpeg"}, "summary_zh": "<ul>\n    <li>\u6587\u672c\u5230\u56fe\u50cf\u6a21\u578b\u5728\u5904\u7406\u771f\u5b9e\u4e16\u754c\u8bf7\u6c42\u65f6\u9762\u4e34\u6311\u6218\uff0c\u7279\u522b\u662f\u5f53\u8bf7\u6c42\u4e0d\u660e\u786e\u6216\u4f9d\u8d56\u6700\u65b0\u77e5\u8bc6\u65f6\u3002</li>\n    <li>\u63d0\u51fa\u4e86Qwen-Image-Agent\uff0c\u8fd9\u662f\u4e00\u4e2a\u7edf\u4e00\u7684\u6846\u67b6\uff0c\u901a\u8fc7\u8ba1\u5212\u3001\u63a8\u7406\u3001\u641c\u7d22\u3001\u8bb0\u5fc6\u548c\u53cd\u9988\u6765\u5f25\u8865\u7528\u6237\u4e0a\u4e0b\u6587\u4e0e\u751f\u6210\u4e0a\u4e0b\u6587\u4e4b\u95f4\u7684\u5dee\u8ddd\u3002</li>\n    <li>Qwen-Image-Agent\u5c06\u7528\u6237\u8f93\u5165\u89c6\u4e3a\u90e8\u5206\u4e0a\u4e0b\u6587\uff0c\u5e76\u901a\u8fc7\u4e0a\u4e0b\u6587\u611f\u77e5\u89c4\u5212\u548c\u4e0a\u4e0b\u6587\u5b9a\u4f4d\u9010\u6b65\u6784\u5efa\u751f\u6210\u4e0a\u4e0b\u6587\u3002</li>\n    <li>\u5f15\u5165\u4e86IA-Bench\u57fa\u51c6\u6d4b\u8bd5\uff0c\u8bc4\u4f30\u56fe\u50cf\u751f\u6210\u7684\u56db\u4e2a\u6838\u5fc3\u80fd\u529b\uff1a\u8ba1\u5212\u3001\u63a8\u7406\u3001\u641c\u7d22\u548c\u8bb0\u5fc6\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u8868\u660e\uff0cQwen-Image-Agent\u5728\u5404\u9879\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u4e8e\u5176\u4ed6\u5f3a\u57fa\u7ebf\uff0c\u8fbe\u5230\u4e86\u6700\u5148\u8fdb\u7684\u6027\u80fd\u6c34\u5e73\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Text-to-image models often struggle with vague or outdated user requests due to a \"Context Gap.\"</li>\n    <li>Qwen-Image-Agent is a new framework designed to improve how these models understand and generate images based on user input.</li>\n    <li>It uses two main processes: Context-Aware Planning to identify what information is missing, and Context Grounding to gather that information.</li>\n    <li>To test its effectiveness, a new benchmark called Image Agent Bench (IA-Bench) was created, focusing on key image generation skills.</li>\n    <li>Experiments show that Qwen-Image-Agent performs better than existing models and achieves top results in image generation tasks.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "Qwen-Image-Agent: Bridging the Context Gap in Real-World Image Generation", "summary": "While text-to-image (T2I) models have achieved remarkable progress, they struggle with real-world requests that are often underspecified, implicit, or dependent on up-to-date knowledge. We identify this challenge as the Context Gap: the mismatch between the user context and the sufficient generation context for T2I models. To bridge this gap, we propose Qwen-Image-Agent, a unified agentic framework that integrates plan, reason, search, memory and feedback in a context-centric manner. Qwen-Image-Agent treats user input as partial context and progressively constructs the generation context through Context-Aware Planning and Context Grounding. Specifically, Context-Aware Planning identifies missing context and plans how it should be acquired and used, while Context Grounding gathers this context from reason, search, memory, and feedback. To evaluate agentic image generation, we further introduce Image Agent Bench (IA-Bench), a benchmark covering four core image agent capabilities: Plan, Reason, Search, and Memory. Experiments on IA-Bench, Mindbench and WISE-Verified show that Qwen-Image-Agent outperforms strong baselines and achieves state-of-the-art performance.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.26907.png", "numComments": 1, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 323, "isUserFollowing": false}, "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6215ca5692c0ecfba9186921/hrRM50-6XcdWgg2AKpENG.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.26300", "authors": [{"_id": "6a3dfe523b43e283349ec252", "name": "Binghai Wang", "hidden": false}, {"_id": "6a3dfe523b43e283349ec253", "name": "Chenlong Zhang", "hidden": false}, {"_id": "6a3dfe523b43e283349ec254", "name": "Dayiheng Liu", "hidden": false}, {"_id": "6a3dfe523b43e283349ec255", "name": "Jiajun Zhang", "hidden": false}, {"_id": "6a3dfe523b43e283349ec256", "name": "Jiawei Chen", "hidden": false}, {"_id": "6a3dfe523b43e283349ec257", "name": "Mouxiang Chen", "hidden": false}, {"_id": "6a3dfe523b43e283349ec258", "name": "Rongyao Fang", "hidden": false}, {"_id": "6a3dfe523b43e283349ec259", "name": "Siyuan Zhang", "hidden": false}, {"_id": "6a3dfe523b43e283349ec25a", "name": "Xuwu Wang", "hidden": false}, {"_id": "6a3dfe523b43e283349ec25b", "name": "Yuheng Jing", "hidden": false}, {"_id": "6a3dfe523b43e283349ec25c", "name": "Zeyao Ma", "hidden": false}, {"_id": "6a3dfe523b43e283349ec25d", "name": "Zeyu Cui", "hidden": false}], "publishedAt": "2026-06-24T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "The Verification Horizon: No Silver Bullet for Coding Agent Rewards", "submittedOnDailyBy": {"_id": "660297295c467e8c06c684b0", "avatarUrl": "/avatars/b721b512148ae118cd99464ae909bb3a.svg", "isPro": false, "fullname": "zjj", "user": "zjj1233", "type": "user", "name": "zjj1233"}, "summary": "A classical intuition holds that verifying a solution is easier than producing one. For today's coding agents, this intuition is being inverted: as foundation models develop stronger reasoning capabilities and engineering harnesses grow more sophisticated, generating complex candidate solutions is no longer difficult -- reliably verifying them has become the harder problem. Every verifier we can build is only a proxy for human intent, never the intent itself. This makes verification subject to a twofold difficulty: first, intent is underspecified by nature, making it inherently hard to faithfully check whether it has been fulfilled; second, during model training, optimization widens the gap between proxy and intent -- manifesting as reward hacking or signal saturation. To address this, we characterize the quality of verification signals along three dimensions -- scalability, faithfulness, and robustness -- and argue that achieving all three simultaneously is the central challenge. We further study four reward constructions: a test verifier for general coding tasks, a rubric verifier for frontend tasks, the user as verifier for real-world agent tasks, and an automated agent verifier for long-horizon tasks. Across different task types and policy capability levels, we conduct in-depth analysis and experiments on the core challenges of reward design and how to more effectively leverage reward signals. Experiments show that targeted verification design can effectively suppress reward hacking, improve task completion quality, and achieve significant gains across multiple internal and public benchmarks. These experiences collectively point to a core observation: no fixed reward function can remain effective as policy capability continues to grow; and verification must co-evolve with the generator.", "upvotes": 33, "discussionId": "6a3dfe523b43e283349ec25e", "ai_summary": "Verification challenges in AI agents arise from the difficulty of aligning proxy signals with human intent, requiring adaptive verification systems that evolve alongside generative capabilities.", "ai_keywords": ["reward hacking", "signal saturation", "verification signals", "reward design", "policy capability", "generative capabilities", "proxy signals", "human intent"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6215ca5692c0ecfba9186921/hrRM50-6XcdWgg2AKpENG.jpeg"}, "summary_zh": "<ul>\n    <li>\u9a8c\u8bc1\u4e00\u4e2a\u89e3\u51b3\u65b9\u6848\u6bd4\u4ea7\u751f\u4e00\u4e2a\u89e3\u51b3\u65b9\u6848\u66f4\u5bb9\u6613\u7684\u4f20\u7edf\u89c2\u70b9\u6b63\u5728\u88ab\u98a0\u8986\u3002</li>\n    <li>\u968f\u7740\u57fa\u7840\u6a21\u578b\u63a8\u7406\u80fd\u529b\u7684\u589e\u5f3a\uff0c\u751f\u6210\u590d\u6742\u89e3\u51b3\u65b9\u6848\u53d8\u5f97\u5bb9\u6613\uff0c\u800c\u9a8c\u8bc1\u8fd9\u4e9b\u89e3\u51b3\u65b9\u6848\u5374\u53d8\u5f97\u66f4\u52a0\u56f0\u96be\u3002</li>\n    <li>\u9a8c\u8bc1\u8fc7\u7a0b\u9762\u4e34\u4e24\u65b9\u9762\u7684\u6311\u6218\uff1a\u610f\u56fe\u4e0d\u660e\u786e\u548c\u6a21\u578b\u8bad\u7ec3\u4e2d\u4ee3\u7406\u4e0e\u610f\u56fe\u4e4b\u95f4\u7684\u5dee\u8ddd\u6269\u5927\u3002</li>\n    <li>\u6211\u4eec\u5206\u6790\u4e86\u9a8c\u8bc1\u4fe1\u53f7\u7684\u4e09\u4e2a\u7ef4\u5ea6\uff1a\u53ef\u6269\u5c55\u6027\u3001\u53ef\u4fe1\u6027\u548c\u9c81\u68d2\u6027\uff0c\u5e76\u8ba4\u4e3a\u540c\u65f6\u5b9e\u73b0\u8fd9\u4e09\u8005\u662f\u4e3b\u8981\u6311\u6218\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u9488\u5bf9\u6027\u7684\u9a8c\u8bc1\u8bbe\u8ba1\u53ef\u4ee5\u6709\u6548\u6291\u5236\u5956\u52b1\u9ed1\u5ba2\u884c\u4e3a\uff0c\u63d0\u9ad8\u4efb\u52a1\u5b8c\u6210\u8d28\u91cf\uff0c\u5e76\u5728\u591a\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u53d6\u5f97\u663e\u8457\u8fdb\u5c55\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>It is becoming easier for coding agents to generate solutions, but verifying those solutions has become more challenging.</li>\n    <li>Verification struggles because it relies on understanding human intent, which is often unclear or incomplete.</li>\n    <li>During training, differences between what we want (intent) and what the model produces can lead to problems like reward hacking.</li>\n    <li>The quality of verification is important and can be assessed based on scalability, faithfulness, and robustness.</li>\n    <li>Experiments show that better verification methods can reduce issues like reward hacking and improve the quality of task completion.</li>\n</ul>"}, "publishedAt": "2026-06-23T20:00:00.000Z", "title": "The Verification Horizon: No Silver Bullet for Coding Agent Rewards", "summary": "A classical intuition holds that verifying a solution is easier than producing one. For today's coding agents, this intuition is being inverted: as foundation models develop stronger reasoning capabilities and engineering harnesses grow more sophisticated, generating complex candidate solutions is no longer difficult -- reliably verifying them has become the harder problem. Every verifier we can build is only a proxy for human intent, never the intent itself. This makes verification subject to a twofold difficulty: first, intent is underspecified by nature, making it inherently hard to faithfully check whether it has been fulfilled; second, during model training, optimization widens the gap between proxy and intent -- manifesting as reward hacking or signal saturation. To address this, we characterize the quality of verification signals along three dimensions -- scalability, faithfulness, and robustness -- and argue that achieving all three simultaneously is the central challenge. We further study four reward constructions: a test verifier for general coding tasks, a rubric verifier for frontend tasks, the user as verifier for real-world agent tasks, and an automated agent verifier for long-horizon tasks. Across different task types and policy capability levels, we conduct in-depth analysis and experiments on the core challenges of reward design and how to more effectively leverage reward signals. Experiments show that targeted verification design can effectively suppress reward hacking, improve task completion quality, and achieve significant gains across multiple internal and public benchmarks. These experiences collectively point to a core observation: no fixed reward function can remain effective as policy capability continues to grow; and verification must co-evolve with the generator.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.26300.png", "numComments": 3, "submittedBy": {"_id": "660297295c467e8c06c684b0", "avatarUrl": "/avatars/b721b512148ae118cd99464ae909bb3a.svg", "fullname": "zjj", "name": "zjj1233", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6215ca5692c0ecfba9186921/hrRM50-6XcdWgg2AKpENG.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.18394", "authors": [{"_id": "6a3e0c903b43e283349ec26b", "name": "Lanxiang Hu", "hidden": false}, {"_id": "6a3e0c903b43e283349ec26c", "name": "Zhaoxiang Feng", "hidden": false}, {"_id": "6a3e0c903b43e283349ec26d", "name": "Yulun Wu", "hidden": false}, {"_id": "6a3e0c903b43e283349ec26e", "name": "Haoran Yuan", "hidden": false}, {"_id": "6a3e0c903b43e283349ec26f", "name": "Yujie Zhao", "hidden": false}, {"_id": "6a3e0c903b43e283349ec270", "name": "Yu-Yang Qian", "hidden": false}, {"_id": "6a3e0c903b43e283349ec271", "name": "Bojun Wang", "hidden": false}, {"_id": "6a3e0c903b43e283349ec272", "name": "Peng Zhao", "hidden": false}, {"_id": "6a3e0c903b43e283349ec273", "name": "Daxin Jiang", "hidden": false}, {"_id": "6a3e0c903b43e283349ec274", "name": "Yibo Zhu", "hidden": false}, {"_id": "6a3e0c903b43e283349ec275", "name": "Tajana Rosing", "hidden": false}, {"_id": "6a3e0c903b43e283349ec276", "name": "Hao Zhang", "hidden": false}], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "JetSpec: Breaking the Scaling Ceiling of Speculative Decoding with Parallel Tree Drafting", "submittedOnDailyBy": {"_id": "6301d6455e305a35cb0846a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6301d6455e305a35cb0846a7/aT2AtzRMSY_T3y02MIUap.jpeg", "isPro": true, "fullname": "Lanxiang Hu", "user": "Snyhlxde", "type": "user", "name": "Snyhlxde"}, "summary": "Speculative decoding (SD) accelerates autoregressive Large Language Models (LLMs) by drafting multiple tokens and verifying them in parallel, but it faces a scaling limitation: increasing the draft budget improves speed only when acceptance remains high and drafting overhead stays low. This ceiling has been difficult to break because prior head-based SD methods face a causality-efficiency dilemma. Autoregressive drafters produce path-conditioned candidates that are effective for tree speculative decoding with higher acceptance length, but their drafting cost grows with tree depth. Bidirectional block-diffusion drafters generate all positions in one pass, but their branch-agnostic marginals can form individually plausible yet mutually inconsistent trees, wasting budget and reducing acceptance. We propose JetSpec, a head-based SD framework that combines one-forward drafting efficiency with branch-wise causal conditioning. JetSpec trains a causal parallel draft head over fused hidden states from the frozen target model, producing candidate trees whose scores align with the target model's autoregressive factorization. This enables JetSpec to convert larger draft budgets into longer accepted prefixes and higher end-to-end speedup. Across math, coding, and chat benchmarks on dense and MoE Qwen3 models, JetSpec consistently outperforms bidirectional-head and tree-based SD baselines. On H100 GPUs, JetSpec achieves up to 9.64x speedup on MATH-500 and 4.58x on open-ended conversational workloads, with further latency gains demonstrated through vLLM integration under realistic serving loads. Our code and models are available at https://github.com/hao-ai-lab/JetSpec.", "upvotes": 24, "discussionId": "6a3e0c903b43e283349ec277", "projectPage": "https://jetspec-project.github.io/jetspec-web/", "githubRepo": "https://github.com/hao-ai-lab/JetSpec", "githubRepoAddedBy": "user", "ai_summary": "JetSpec is a speculative decoding framework that combines efficient forward drafting with causal conditioning to improve LLM inference speed and acceptance rates across various benchmarks.", "ai_keywords": ["speculative decoding", "autoregressive Large Language Models", "draft budget", "acceptance rate", "causality-efficiency dilemma", "tree speculative decoding", "bidirectional block-diffusion", "branch-agnostic marginals", "causal parallel draft head", "fused hidden states", "autoregressive factorization", "end-to-end speedup", "MoE Qwen3", "vLLM integration"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 35, "summary_zh": "<ul>\n    <li>\u731c\u6d4b\u89e3\u7801\uff08SD\uff09\u901a\u8fc7\u5e76\u884c\u8349\u62df\u591a\u4e2a\u4ee4\u724c\u6765\u52a0\u901f\u81ea\u56de\u5f52\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\uff0c\u4f46\u9762\u4e34\u6269\u5c55\u9650\u5236\u3002</li>\n    <li>\u589e\u52a0\u8349\u62df\u9884\u7b97\u4ec5\u5728\u63a5\u53d7\u7387\u9ad8\u4e14\u8349\u62df\u5f00\u9500\u4f4e\u65f6\u624d\u80fd\u63d0\u9ad8\u901f\u5ea6\u3002</li>\n    <li>JetSpec\u662f\u4e00\u4e2a\u65b0\u7684\u5934\u90e8\u57fa\u7840SD\u6846\u67b6\uff0c\u7ed3\u5408\u4e86\u4e00\u6b21\u6027\u8349\u62df\u7684\u6548\u7387\u548c\u5206\u652f\u6761\u4ef6\u3002</li>\n    <li>JetSpec\u901a\u8fc7\u8bad\u7ec3\u56e0\u679c\u5e76\u884c\u8349\u62df\u5934\uff0c\u751f\u6210\u4e0e\u76ee\u6807\u6a21\u578b\u4e00\u81f4\u7684\u5019\u9009\u6811\uff0c\u4ece\u800c\u63d0\u9ad8\u63a5\u53d7\u7387\u548c\u901f\u5ea6\u3002</li>\n    <li>\u5728\u6570\u5b66\u3001\u7f16\u7801\u548c\u804a\u5929\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cJetSpec\u5728\u6027\u80fd\u4e0a\u4f18\u4e8e\u5176\u4ed6SD\u65b9\u6cd5\uff0c\u5e76\u5728H100 GPU\u4e0a\u5b9e\u73b0\u4e86\u663e\u8457\u7684\u52a0\u901f\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Speculative decoding (SD) speeds up language models by drafting multiple tokens at once but can slow down if not managed well.</li>\n    <li>Current methods struggle with efficiency and often waste resources, leading to lower acceptance rates of token drafts.</li>\n    <li>JetSpec is a new SD framework that combines efficient drafting with better organization of token choices, improving overall performance.</li>\n    <li>JetSpec allows for larger budgets to be used effectively, resulting in longer accepted outputs and faster processing speeds.</li>\n    <li>Tests show JetSpec significantly outperforms existing methods, achieving impressive speed boosts in various tasks.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "JetSpec: Breaking the Scaling Ceiling of Speculative Decoding with Parallel Tree Drafting", "summary": "Speculative decoding (SD) accelerates autoregressive Large Language Models (LLMs) by drafting multiple tokens and verifying them in parallel, but it faces a scaling limitation: increasing the draft budget improves speed only when acceptance remains high and drafting overhead stays low. This ceiling has been difficult to break because prior head-based SD methods face a causality-efficiency dilemma. Autoregressive drafters produce path-conditioned candidates that are effective for tree speculative decoding with higher acceptance length, but their drafting cost grows with tree depth. Bidirectional block-diffusion drafters generate all positions in one pass, but their branch-agnostic marginals can form individually plausible yet mutually inconsistent trees, wasting budget and reducing acceptance. We propose JetSpec, a head-based SD framework that combines one-forward drafting efficiency with branch-wise causal conditioning. JetSpec trains a causal parallel draft head over fused hidden states from the frozen target model, producing candidate trees whose scores align with the target model's autoregressive factorization. This enables JetSpec to convert larger draft budgets into longer accepted prefixes and higher end-to-end speedup. Across math, coding, and chat benchmarks on dense and MoE Qwen3 models, JetSpec consistently outperforms bidirectional-head and tree-based SD baselines. On H100 GPUs, JetSpec achieves up to 9.64x speedup on MATH-500 and 4.58x on open-ended conversational workloads, with further latency gains demonstrated through vLLM integration under realistic serving loads. Our code and models are available at https://github.com/hao-ai-lab/JetSpec.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.18394.png", "numComments": 1, "submittedBy": {"_id": "6301d6455e305a35cb0846a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6301d6455e305a35cb0846a7/aT2AtzRMSY_T3y02MIUap.jpeg", "fullname": "Lanxiang Hu", "name": "Snyhlxde", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 10, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.24551", "authors": [{"_id": "6a3b4b060a86ac3098d5d715", "user": {"_id": "685b93ba200d37039025b89d", "avatarUrl": "/avatars/e8963b6ab8e6a248d701891e5cedd43e.svg", "isPro": false, "fullname": "Xiao Zhou", "user": "rebeccazzzz", "type": "user", "name": "rebeccazzzz"}, "name": "Xiao Zhou", "status": "claimed_verified", "statusLastChangedAt": "2026-06-25T09:30:22.665Z", "hidden": false}, {"_id": "6a3b4b060a86ac3098d5d716", "name": "Siyue Zhang", "hidden": false}, {"_id": "6a3b4b060a86ac3098d5d717", "name": "Yilun Zhao", "hidden": false}, {"_id": "6a3b4b060a86ac3098d5d718", "name": "Jinbiao Wei", "hidden": false}, {"_id": "6a3b4b060a86ac3098d5d719", "name": "Tingyu Song", "hidden": false}, {"_id": "6a3b4b060a86ac3098d5d71a", "name": "Arman Cohan", "hidden": false}, {"_id": "6a3b4b060a86ac3098d5d71b", "name": "Chen Zhao", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "GUI vs. CLI: Execution Bottlenecks in Screen-Only and Skill-Mediated Computer-Use Agents", "submittedOnDailyBy": {"_id": "685b93ba200d37039025b89d", "avatarUrl": "/avatars/e8963b6ab8e6a248d701891e5cedd43e.svg", "isPro": false, "fullname": "Xiao Zhou", "user": "rebeccazzzz", "type": "user", "name": "rebeccazzzz"}, "summary": "Computer-use agents can execute software tasks through either graphical interfaces or programmatic command interfaces, but existing evaluations confound interaction modality with differences in tasks, initial states, verifiers, and permitted actions. We introduce a matched execution-layer benchmark of 440 desktop tasks across 18 applications and 12 workflow categories, where screen-only GUI agents and skill-mediated CLI agents receive identical goals, states, and final-state verifiers while being restricted to modality-native actions. In this controlled setting, the strongest GUI agent reaches a 59.1% full pass rate, outperforming the strongest original-skill CLI agent at 48.2%; however, verifier-guided skill augmentation raises CLI success to 69.3%, showing that much of the CLI deficit comes from incomplete skill coverage rather than model capability alone. These results suggest that GUI and CLI expose different execution bottlenecks: GUI agents are limited by reliable grounded interaction over long-horizon workflows, whereas CLI agents are limited by the coverage and scalability of their skill interfaces.", "upvotes": 23, "discussionId": "6a3b4b070a86ac3098d5d71c", "githubRepo": "https://github.com/rebeccaz4/gui-vs-cli", "githubRepoAddedBy": "user", "githubStars": 1, "summary_zh": "<ul>\n    <li>\u7814\u7a76\u6bd4\u8f83\u4e86\u56fe\u5f62\u7528\u6237\u754c\u9762\uff08GUI\uff09\u4ee3\u7406\u548c\u547d\u4ee4\u884c\u63a5\u53e3\uff08CLI\uff09\u4ee3\u7406\u5728\u6267\u884c\u8f6f\u4ef6\u4efb\u52a1\u65f6\u7684\u8868\u73b0\u3002</li>\n    <li>\u521b\u5efa\u4e86\u4e00\u4e2a\u5305\u542b440\u4e2a\u684c\u9762\u4efb\u52a1\u7684\u57fa\u51c6\u6d4b\u8bd5\uff0c\u786e\u4fdd\u4e24\u79cd\u4ee3\u7406\u5728\u76f8\u540c\u7684\u76ee\u6807\u548c\u72b6\u6001\u4e0b\u8fdb\u884c\u6bd4\u8f83\u3002</li>\n    <li>\u6700\u5f3a\u7684GUI\u4ee3\u7406\u901a\u8fc7\u7387\u4e3a59.1%\uff0c\u800c\u6700\u5f3a\u7684\u539f\u6280\u80fdCLI\u4ee3\u7406\u4e3a48.2%\u3002</li>\n    <li>\u901a\u8fc7\u6539\u8fdb\u6280\u80fd\uff0cCLI\u7684\u6210\u529f\u7387\u63d0\u9ad8\u523069.3%\uff0c\u8868\u660eCLI\u7684\u4e0d\u8db3\u4e3b\u8981\u6765\u81ea\u4e8e\u6280\u80fd\u8986\u76d6\u4e0d\u5168\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793aGUI\u548cCLI\u5728\u6267\u884c\u4efb\u52a1\u65f6\u9762\u4e34\u4e0d\u540c\u7684\u74f6\u9888\uff0cGUI\u5728\u957f\u671f\u5de5\u4f5c\u6d41\u7a0b\u4e2d\u9762\u4e34\u4ea4\u4e92\u53ef\u9760\u6027\u7684\u95ee\u9898\uff0cCLI\u5219\u53d7\u9650\u4e8e\u6280\u80fd\u63a5\u53e3\u7684\u8986\u76d6\u548c\u53ef\u6269\u5c55\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The study compares how computer agents perform tasks using graphical interfaces (GUI) and command line interfaces (CLI) with a standardized set of 440 tasks.</li>\n    <li>Both types of agents are given the same goals and conditions to ensure a fair evaluation.</li>\n    <li>The best GUI agent has a success rate of 59.1%, while the best CLI agent initially scores 48.2%, but can increase to 69.3% with additional skill support.</li>\n    <li>The results show that GUI agents struggle with handling complex tasks over time, while CLI agents have issues with the range and effectiveness of their skills.</li>\n    <li>This research highlights different challenges faced by GUI and CLI agents when completing tasks.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "GUI vs. CLI: Execution Bottlenecks in Screen-Only and Skill-Mediated Computer-Use Agents", "summary": "Computer-use agents can execute software tasks through either graphical interfaces or programmatic command interfaces, but existing evaluations confound interaction modality with differences in tasks, initial states, verifiers, and permitted actions. We introduce a matched execution-layer benchmark of 440 desktop tasks across 18 applications and 12 workflow categories, where screen-only GUI agents and skill-mediated CLI agents receive identical goals, states, and final-state verifiers while being restricted to modality-native actions. In this controlled setting, the strongest GUI agent reaches a 59.1% full pass rate, outperforming the strongest original-skill CLI agent at 48.2%; however, verifier-guided skill augmentation raises CLI success to 69.3%, showing that much of the CLI deficit comes from incomplete skill coverage rather than model capability alone. These results suggest that GUI and CLI expose different execution bottlenecks: GUI agents are limited by reliable grounded interaction over long-horizon workflows, whereas CLI agents are limited by the coverage and scalability of their skill interfaces.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.24551.png", "numComments": 1, "submittedBy": {"_id": "685b93ba200d37039025b89d", "avatarUrl": "/avatars/e8963b6ab8e6a248d701891e5cedd43e.svg", "fullname": "Xiao Zhou", "name": "rebeccazzzz", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.26217", "authors": [{"_id": "6a3ddd943b43e283349ec159", "name": "Yuntian Gao", "hidden": false}, {"_id": "6a3ddd943b43e283349ec15a", "name": "Xiangyu Xu", "hidden": false}], "publishedAt": "2026-06-24T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "Fast LeWorldModel", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Joint-Embedding Predictive Architectures (JEPAs), including recent LeWorldModel (LeWM), have become a promising foundation for reconstruction-free visual world models. For visual planning, however, LeWM evaluates candidate action sequences by repeatedly applying a local one-step latent transition model. This autoregressive rollout makes planning computationally expensive and exposes the predicted trajectory to accumulated latent errors as the horizon grows. We propose Fast LeWorldModel (Fast-LeWM), a fast latent world model that replaces repeated local rollout with action-prefix prediction. Given the current latent and a candidate action sequence, Fast-LeWM encodes its prefixes and predicts the future latents reached after executing those prefixes in parallel. By making action prefixes the basic prediction unit, Fast-LeWM directly models action effects accumulated to different extents over multiple horizons. This prefix-level supervision forces the model to learn how states continuously evolve under different action prefixes, rather than only fitting one-step state transitions. During planning, the predictor can use the last prefix token from the encoded action sequence to evaluate the corresponding future latent without explicitly rolling through each intermediate imagined state. Across multiple tasks, Fast-LeWM improves average success over LeWM while substantially reducing planning time, achieving lower open-loop latent loss whose growth becomes significantly slower as the rollout horizon increases.", "upvotes": 16, "discussionId": "6a3ddd953b43e283349ec15b", "githubRepo": "https://github.com/Yuntian-Gao/Fast-LeWorldModel", "githubRepoAddedBy": "user", "ai_summary": "Fast-LeWM accelerates visual planning by replacing autoregressive rollout with parallel action-prefix prediction, reducing computational costs and latency accumulation during long-horizon predictions.", "ai_keywords": ["Joint-Embedding Predictive Architectures", "LeWorldModel", "latent world model", "visual planning", "autoregressive rollout", "action-prefix prediction", "latent transition model", "prefix-level supervision", "open-loop latent loss"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 3, "summary_zh": "<ul>\n    <li>Joint-Embedding Predictive Architectures (JEPAs) \u548c LeWorldModel (LeWM) \u662f\u89c6\u89c9\u4e16\u754c\u6a21\u578b\u7684\u57fa\u7840\u3002</li>\n    <li>LeWM \u901a\u8fc7\u91cd\u590d\u5e94\u7528\u5c40\u90e8\u4e00\u6b65\u6f5c\u5728\u8f6c\u79fb\u6a21\u578b\u6765\u8bc4\u4f30\u5019\u9009\u52a8\u4f5c\u5e8f\u5217\uff0c\u4f46\u8fd9\u79cd\u65b9\u6cd5\u8ba1\u7b97\u6210\u672c\u9ad8\u4e14\u5bb9\u6613\u7d2f\u79ef\u9519\u8bef\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u5feb\u901f LeWorldModel (Fast-LeWM)\uff0c\u4f7f\u7528\u52a8\u4f5c\u524d\u7f00\u9884\u6d4b\u6765\u66ff\u4ee3\u91cd\u590d\u7684\u5c40\u90e8\u63a8\u7406\u3002</li>\n    <li>Fast-LeWM \u5c06\u52a8\u4f5c\u524d\u7f00\u4f5c\u4e3a\u57fa\u672c\u9884\u6d4b\u5355\u5143\uff0c\u53ef\u4ee5\u5e76\u884c\u9884\u6d4b\u6267\u884c\u8fd9\u4e9b\u524d\u7f00\u540e\u7684\u672a\u6765\u72b6\u6001\u3002</li>\n    <li>\u5728\u591a\u4e2a\u4efb\u52a1\u4e2d\uff0cFast-LeWM \u63d0\u9ad8\u4e86\u6210\u529f\u7387\uff0c\u5e76\u663e\u8457\u51cf\u5c11\u4e86\u89c4\u5212\u65f6\u95f4\uff0c\u540c\u65f6\u964d\u4f4e\u4e86\u6f5c\u5728\u635f\u5931\u7684\u589e\u957f\u901f\u5ea6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Joint-Embedding Predictive Architectures (JEPAs), like LeWorldModel (LeWM), are good for visual world models that don't need reconstruction.</li>\n    <li>LeWM has a costly planning process because it uses a local model that builds action sequences step by step, which can lead to errors over time.</li>\n    <li>Fast LeWorldModel (Fast-LeWM) improves this by predicting the effects of action sequences in parallel instead of step-by-step.</li>\n    <li>This new method helps the model understand how states change with different actions over time, rather than just one-step changes.</li>\n    <li>Fast-LeWM is faster and more successful than LeWM in various tasks, reducing planning time and errors significantly as the planning horizon increases.</li>\n</ul>"}, "publishedAt": "2026-06-23T20:00:00.000Z", "title": "Fast LeWorldModel", "summary": "Joint-Embedding Predictive Architectures (JEPAs), including recent LeWorldModel (LeWM), have become a promising foundation for reconstruction-free visual world models. For visual planning, however, LeWM evaluates candidate action sequences by repeatedly applying a local one-step latent transition model. This autoregressive rollout makes planning computationally expensive and exposes the predicted trajectory to accumulated latent errors as the horizon grows. We propose Fast LeWorldModel (Fast-LeWM), a fast latent world model that replaces repeated local rollout with action-prefix prediction. Given the current latent and a candidate action sequence, Fast-LeWM encodes its prefixes and predicts the future latents reached after executing those prefixes in parallel. By making action prefixes the basic prediction unit, Fast-LeWM directly models action effects accumulated to different extents over multiple horizons. This prefix-level supervision forces the model to learn how states continuously evolve under different action prefixes, rather than only fitting one-step state transitions. During planning, the predictor can use the last prefix token from the encoded action sequence to evaluate the corresponding future latent without explicitly rolling through each intermediate imagined state. Across multiple tasks, Fast-LeWM improves average success over LeWM while substantially reducing planning time, achieving lower open-loop latent loss whose growth becomes significantly slower as the rollout horizon increases.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.26217.png", "numComments": 0, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 323, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.26027", "authors": [{"_id": "6a3df1623b43e283349ec1c8", "name": "Yupu Hao", "hidden": false}, {"_id": "6a3df1623b43e283349ec1c9", "name": "Zhuoran Jin", "hidden": false}, {"_id": "6a3df1623b43e283349ec1ca", "name": "Huanxuan Liao", "hidden": false}, {"_id": "6a3df1623b43e283349ec1cb", "name": "Kang Liu", "hidden": false}, {"_id": "6a3df1623b43e283349ec1cc", "name": "Jun Zhao", "hidden": false}], "publishedAt": "2026-06-24T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "Why Multi-Step Tool-Use Reinforcement Learning Collapses and How Supervisory Signals Fix It", "submittedOnDailyBy": {"_id": "643379416c6ecd58798421b3", "avatarUrl": "/avatars/831db7eab2663abc33b176cf386b02f2.svg", "isPro": false, "fullname": "Zhuoran Jin", "user": "jinzhuoran", "type": "user", "name": "jinzhuoran"}, "summary": "Tool use enables large language models (LLMs) to perform complex tasks, and recent agentic reinforcement learning (RL) methods show promise for enhancing model capabilities. However, RL alone often leads to instability or limited gains in tool-use tasks. In our experiments, some models exhibit catastrophic collapse, where performance abruptly drops and tool-invocation structures fail. The analysis reveals that these failures stem from unexpected probability spikes in specific control tokens, disrupting structured execution, yet the underlying tool-use capability remains intact, merely obscured by specific formats. To address this, we systematically investigate a diverse set of supervisory signals, including off-policy supervision, hint-based guidance, erroneous example supervision, and others, applied under both synchronous and interleaved training schemes. We find that interleaving supervised fine-tuning (SFT) with RL substantially improves stability, but exhibits degraded performance under format and content out-of-distribution (OOD) evaluation. We also analyze the impact of learning rates and generalization across settings. These results highlight the importance of understanding RL failures and demonstrate how diverse supervisory signals can guide exploratory learning, enabling robust training of LLMs for complex, multi-step tool-use tasks. Our Code is available at https://github.com/hypasd-art/Tool-RL-Box.", "upvotes": 12, "discussionId": "6a3df1623b43e283349ec1cd", "githubRepo": "https://github.com/hypasd-art/Tool-RL-Box", "githubRepoAddedBy": "user", "ai_summary": "Research investigates how different supervisory signals and training strategies improve the stability and performance of large language models in tool-use tasks, addressing issues like catastrophic collapse and format sensitivity through interleaved supervised fine-tuning and reinforcement learning.", "ai_keywords": ["agentic reinforcement learning", "tool-use tasks", "catastrophic collapse", "control tokens", "supervised fine-tuning", "off-policy supervision", "hint-based guidance", "erroneous example supervision", "interleaved training", "synchronous training", "learning rates", "out-of-distribution evaluation", "exploratory learning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 2, "organization": {"_id": "640a887796aae649741a586f", "name": "CASIA", "fullname": "Chinese Academic of Science Institute of Automation", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1678411888885-6388984e8a5dbe2f3dc5afee.jpeg"}, "summary_zh": "<ul>\n    <li>\u5de5\u5177\u4f7f\u7528\u53ef\u4ee5\u8ba9\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u5b8c\u6210\u590d\u6742\u4efb\u52a1\uff0c\u6700\u8fd1\u7684\u5f3a\u5316\u5b66\u4e60\u65b9\u6cd5\u6709\u52a9\u4e8e\u63d0\u5347\u6a21\u578b\u80fd\u529b\u3002</li>\n    <li>\u5f3a\u5316\u5b66\u4e60\u5355\u72ec\u4f7f\u7528\u65f6\uff0c\u53ef\u80fd\u4f1a\u5bfc\u81f4\u6a21\u578b\u6027\u80fd\u4e0d\u7a33\u5b9a\u6216\u8fdb\u6b65\u6709\u9650\uff0c\u90e8\u5206\u6a21\u578b\u51fa\u73b0\u6027\u80fd\u6025\u5267\u4e0b\u964d\u3002</li>\n    <li>\u8fd9\u4e9b\u5931\u8d25\u6e90\u4e8e\u7279\u5b9a\u63a7\u5236\u4ee4\u724c\u7684\u6982\u7387\u5f02\u5e38\u6ce2\u52a8\uff0c\u5f71\u54cd\u4e86\u7ed3\u6784\u5316\u6267\u884c\uff0c\u4f46\u5de5\u5177\u4f7f\u7528\u80fd\u529b\u4f9d\u7136\u5b58\u5728\u3002</li>\n    <li>\u901a\u8fc7\u7cfb\u7edf\u7814\u7a76\u4e0d\u540c\u7684\u76d1\u7763\u4fe1\u53f7\uff0c\u4ee5\u53ca\u7ed3\u5408\u540c\u6b65\u548c\u4ea4\u9519\u8bad\u7ec3\u65b9\u6cd5\uff0c\u6211\u4eec\u53d1\u73b0\u4ea4\u9519\u7684\u76d1\u7763\u5fae\u8c03\u4e0e\u5f3a\u5316\u5b66\u4e60\u7ed3\u5408\u80fd\u663e\u8457\u63d0\u9ad8\u7a33\u5b9a\u6027\u3002</li>\n    <li>\u7814\u7a76\u7ed3\u679c\u5f3a\u8c03\u4e86\u7406\u89e3\u5f3a\u5316\u5b66\u4e60\u5931\u8d25\u7684\u91cd\u8981\u6027\uff0c\u5e76\u5c55\u793a\u4e86\u591a\u6837\u5316\u7684\u76d1\u7763\u4fe1\u53f7\u5982\u4f55\u6307\u5bfc\u63a2\u7d22\u6027\u5b66\u4e60\uff0c\u4ece\u800c\u589e\u5f3a\u6a21\u578b\u5728\u590d\u6742\u5de5\u5177\u4f7f\u7528\u4efb\u52a1\u4e2d\u7684\u8bad\u7ec3\u6548\u679c\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Using tools helps large language models (LLMs) perform complex tasks, but reinforcement learning (RL) can cause instability.</li>\n    <li>Some models face serious performance drops (catastrophic collapse) when using tools, primarily due to issues with control tokens.</li>\n    <li>The tool-use ability is still there but can be hidden by certain formats.</li>\n    <li>Testing different training methods shows that mixing supervised fine-tuning with RL improves stability but may hurt performance in some situations.</li>\n    <li>The study emphasizes understanding RL issues and using various training signals to improve LLMs for complex tasks.</li>\n</ul>"}, "publishedAt": "2026-06-23T20:00:00.000Z", "title": "Why Multi-Step Tool-Use Reinforcement Learning Collapses and How Supervisory Signals Fix It", "summary": "Tool use enables large language models (LLMs) to perform complex tasks, and recent agentic reinforcement learning (RL) methods show promise for enhancing model capabilities. However, RL alone often leads to instability or limited gains in tool-use tasks. In our experiments, some models exhibit catastrophic collapse, where performance abruptly drops and tool-invocation structures fail. The analysis reveals that these failures stem from unexpected probability spikes in specific control tokens, disrupting structured execution, yet the underlying tool-use capability remains intact, merely obscured by specific formats. To address this, we systematically investigate a diverse set of supervisory signals, including off-policy supervision, hint-based guidance, erroneous example supervision, and others, applied under both synchronous and interleaved training schemes. We find that interleaving supervised fine-tuning (SFT) with RL substantially improves stability, but exhibits degraded performance under format and content out-of-distribution (OOD) evaluation. We also analyze the impact of learning rates and generalization across settings. These results highlight the importance of understanding RL failures and demonstrate how diverse supervisory signals can guide exploratory learning, enabling robust training of LLMs for complex, multi-step tool-use tasks. Our Code is available at https://github.com/hypasd-art/Tool-RL-Box.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.26027.png", "numComments": 1, "submittedBy": {"_id": "643379416c6ecd58798421b3", "avatarUrl": "/avatars/831db7eab2663abc33b176cf386b02f2.svg", "fullname": "Zhuoran Jin", "name": "jinzhuoran", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 11, "isUserFollowing": false}, "organization": {"_id": "640a887796aae649741a586f", "name": "CASIA", "fullname": "Chinese Academic of Science Institute of Automation", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1678411888885-6388984e8a5dbe2f3dc5afee.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.14397", "authors": [{"_id": "6a3e621b0dbbc53604b663df", "name": "Mykola Vysotskyi", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e0", "name": "Runqi Lin", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e1", "name": "Grzegorz Biziel", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e2", "name": "Michal Zakrzewski", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e3", "name": "Sebastian Montagna", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e4", "name": "Damian Rynczak", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e5", "name": "Shreyansh Padarha", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e6", "name": "Kumail Alhamoud", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e7", "name": "Zihao Fu", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e8", "name": "William Lugoloobi", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663e9", "name": "Kai Rawal", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663ea", "name": "Hanna Yershova", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663eb", "name": "Xander Davies", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663ec", "name": "Taras Rumezhak", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663ed", "name": "Guohao Li", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663ee", "name": "Fazl Barez", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663ef", "name": "Baoyuan Wu", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f0", "name": "Arkadiusz Drohomirecki", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f1", "name": "Yarin Gal", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f2", "name": "Chris Russell", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f3", "name": "Christopher Summerfield", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f4", "name": "Adam Mahdi", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f5", "name": "Volodymyr Karpiv", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f6", "name": "Philip Torr", "hidden": false}, {"_id": "6a3e621b0dbbc53604b663f7", "name": "Adel Bibi", "hidden": false}], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "Running the Gauntlet: Re-evaluating the Capabilities of Agents Beyond Familiar Environments", "submittedOnDailyBy": {"_id": "660f6441be6715ca37eda36f", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/660f6441be6715ca37eda36f/f1ajrtPgJDuq7qxFZ_KUr.jpeg", "isPro": false, "fullname": "Runqi Lin", "user": "RunqiLin", "type": "user", "name": "RunqiLin"}, "summary": "As agentic systems continue to evolve and are widely deployed in real-world scenarios, there is a growing demand to faithfully evaluate their capabilities. However, current benchmarks are typically built on popular applications with relatively simple tasks and focus on a narrow set of capabilities while overlooking broader dimensions, resulting in saturated performance on modern agents and failing to probe their limitations. To this end, we introduce GauntletBench, a web-based benchmark for evaluating agent generalisation in challenging scenarios, focusing on three underexplored capabilities (temporal perception, graphical understanding, and 3D reasoning), across five less-covered professional applications (Video Editor, Workflow Builder, 3D Modeller, Flight Analyser, and Circuit Designer), each with 20 vision-intensive tasks (100 in total). Our benchmark provides a modular pipeline that comprises an environment compatible with both open- and closed-source agent frameworks, a controlled web-based application, a well-structured task suite, and an automated evaluation engine with diverse metrics. Contrary to widespread expectations, our empirical results reveal that frontier agentic systems remain far from achieving human-level performance. Even the state-of-the-art agent achieves only a 19.1% success rate on our GauntletBench, highlighting the limitations in these overlooked capabilities and generalisation. By comparison, non-expert human annotators achieve over 80% success on our challenging yet feasible tasks, revealing the substantial gap between current agent capabilities and those required for complex real-world scenarios.", "upvotes": 11, "discussionId": "6a3e621c0dbbc53604b663f8", "projectPage": "https://gauntlet-landing-page.vercel.app/", "githubRepo": "https://github.com/gauntlet-benchmark/evaluation-harness", "githubRepoAddedBy": "user", "ai_summary": "A web-based benchmark evaluates agent generalization across challenging scenarios, revealing significant gaps between current agentic systems and human performance in temporal perception, graphical understanding, and 3D reasoning.", "ai_keywords": ["agentic systems", "benchmark", "agent generalization", "temporal perception", "graphical understanding", "3D reasoning", "web-based benchmark", "automated evaluation engine", "modular pipeline", "vision-intensive tasks"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 1, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "summary_zh": "<ul>\n    <li>\u968f\u7740\u667a\u80fd\u7cfb\u7edf\u7684\u53d1\u5c55\uff0c\u5bf9\u5176\u80fd\u529b\u7684\u8bc4\u4f30\u9700\u6c42\u4e0d\u65ad\u589e\u52a0\u3002</li>\n    <li>\u5f53\u524d\u7684\u8bc4\u4f30\u57fa\u51c6\u901a\u5e38\u53ea\u5173\u6ce8\u7b80\u5355\u4efb\u52a1\u548c\u6709\u9650\u7684\u80fd\u529b\uff0c\u5ffd\u89c6\u4e86\u66f4\u5e7f\u6cdb\u7684\u7ef4\u5ea6\u3002</li>\n    <li>\u6211\u4eec\u63a8\u51fa\u4e86GauntletBench\uff0c\u8fd9\u662f\u4e00\u4e2a\u8bc4\u4f30\u667a\u80fd\u7cfb\u7edf\u5728\u590d\u6742\u573a\u666f\u4e2d\u6cdb\u5316\u80fd\u529b\u7684\u57fa\u51c6\u3002</li>\n    <li>\u8be5\u57fa\u51c6\u7740\u91cd\u4e8e\u4e09\u4e2a\u672a\u88ab\u5145\u5206\u63a2\u7d22\u7684\u80fd\u529b\uff1a\u65f6\u95f4\u611f\u77e5\u3001\u56fe\u5f62\u7406\u89e3\u548c3D\u63a8\u7406\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\uff0c\u5f53\u524d\u6700\u5148\u8fdb\u7684\u667a\u80fd\u7cfb\u7edf\u5728\u8bc4\u4f30\u4e2d\u4ec5\u670919.1%\u7684\u6210\u529f\u7387\uff0c\u800c\u975e\u4e13\u4e1a\u7684\u4eba\u7c7b\u6807\u6ce8\u8005\u6210\u529f\u7387\u8d85\u8fc780%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>There is a need for better evaluation of agent systems as they are used in real life.</li>\n    <li>Current tests focus on simple tasks and miss important skills, leading to misleading performance results.</li>\n    <li>GauntletBench is a new tool designed to assess agents in tougher situations, emphasizing skills like time awareness and 3D reasoning.</li>\n    <li>The benchmark includes five professional applications with 100 challenging tasks, providing a comprehensive evaluation setup.</li>\n    <li>Results show that advanced agents only succeed 19.1% of the time, while non-expert humans perform over 80%, indicating a significant gap in capabilities.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "Running the Gauntlet: Re-evaluating the Capabilities of Agents Beyond Familiar Environments", "summary": "As agentic systems continue to evolve and are widely deployed in real-world scenarios, there is a growing demand to faithfully evaluate their capabilities. However, current benchmarks are typically built on popular applications with relatively simple tasks and focus on a narrow set of capabilities while overlooking broader dimensions, resulting in saturated performance on modern agents and failing to probe their limitations. To this end, we introduce GauntletBench, a web-based benchmark for evaluating agent generalisation in challenging scenarios, focusing on three underexplored capabilities (temporal perception, graphical understanding, and 3D reasoning), across five less-covered professional applications (Video Editor, Workflow Builder, 3D Modeller, Flight Analyser, and Circuit Designer), each with 20 vision-intensive tasks (100 in total). Our benchmark provides a modular pipeline that comprises an environment compatible with both open- and closed-source agent frameworks, a controlled web-based application, a well-structured task suite, and an automated evaluation engine with diverse metrics. Contrary to widespread expectations, our empirical results reveal that frontier agentic systems remain far from achieving human-level performance. Even the state-of-the-art agent achieves only a 19.1% success rate on our GauntletBench, highlighting the limitations in these overlooked capabilities and generalisation. By comparison, non-expert human annotators achieve over 80% success on our challenging yet feasible tasks, revealing the substantial gap between current agent capabilities and those required for complex real-world scenarios.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.14397.png", "numComments": 1, "submittedBy": {"_id": "660f6441be6715ca37eda36f", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/660f6441be6715ca37eda36f/f1ajrtPgJDuq7qxFZ_KUr.jpeg", "fullname": "Runqi Lin", "name": "RunqiLin", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "isAuthorParticipating": false}],
    "week": [{"paper": {"id": "2606.24775", "authors": [{"_id": "6a3c9fedf3facdb67e9ff137", "name": "Wei Zhou", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff138", "name": "Xuanhe Zhou", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff139", "name": "Shaokun Han", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13a", "name": "Hongming Xu", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13b", "name": "Guoliang Li", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13c", "name": "Zhiyu Li", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13d", "name": "Feiyu Xiong", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13e", "name": "Fan Wu", "hidden": false}], "publishedAt": "2026-06-23T00:00:00.000Z", "submittedOnDailyAt": "2026-06-25T00:00:00.000Z", "title": "Are We Ready For An Agent-Native Memory System?", "submittedOnDailyBy": {"_id": "68216c63856b96f869d1d116", "avatarUrl": "/avatars/f69026ca75377e6754ab3e317879e35a.svg", "isPro": false, "fullname": "Wei Zhou", "user": "weizhoudb", "type": "user", "name": "weizhoudb"}, "summary": "Memory for large language model (LLM) agents has rapidly evolved from simple retrieval-augmented mechanisms into a data management system that supports persistent information storage, retrieval, update, consolidation, and dynamic lifecycle governance throughout agent execution. Despite this evolution, existing evaluations still benchmark agent memory mainly through end-to-end task success metrics (e.g., F1, BLEU), while treating the underlying system as a monolithic black box. As a result, critical system-level concerns, including operational costs, architectural trade-offs across memory modules, and robustness under dynamic knowledge updates, remain insufficiently explored. In this paper, we present a systematic experimental study of agent memory from a data management perspective. We propose an analytical framework that decomposes agent memory into four core modules: memory representation and storage, extraction, retrieval and routing, and maintenance. Under this framework, we evaluate 12 representative memory systems and two reference baselines across five benchmark workloads spanning 11 datasets. Our extensive end-to-end evaluation shows that no single architecture dominates across all scenarios; instead, effectiveness depends heavily on how well the memory structure aligns with the workload bottleneck. Furthermore, through fine-grained ablation studies, we quantify their individual effects on representation fidelity, retrieval precision, update correctness, and long-horizon stability. Finally, we reveal cost-performance trade-offs under realistic workloads, showing localized maintenance is more cost-efficient than global reorganization. Based on these findings, we identify promising directions towards building truly agent-native memory systems. The code is publicly available at https://github.com/OpenDataBox/MemoryData.", "upvotes": 89, "discussionId": "6a3c9fedf3facdb67e9ff13f", "projectPage": "https://github.com/OpenDataBox/awesome-agent-memory", "githubRepo": "https://github.com/OpenDataBox/MemoryData", "githubRepoAddedBy": "user", "ai_summary": "Large language model agents' memory systems have evolved into complex data management frameworks requiring systematic evaluation across multiple modules and workloads to understand their performance characteristics and trade-offs.", "ai_keywords": ["large language model agents", "memory representation and storage", "extraction", "retrieval and routing", "maintenance", "agent-native memory systems", "data management perspective", "memory modules", "workload bottleneck", "representation fidelity", "retrieval precision", "update correctness", "long-horizon stability", "cost-performance trade-offs"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 20, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u4ee3\u7406\u7684\u8bb0\u5fc6\u7cfb\u7edf\u5df2\u4ece\u7b80\u5355\u7684\u68c0\u7d22\u673a\u5236\u53d1\u5c55\u4e3a\u652f\u6301\u6301\u4e45\u4fe1\u606f\u5b58\u50a8\u548c\u52a8\u6001\u7ba1\u7406\u7684\u6570\u636e\u7ba1\u7406\u7cfb\u7edf\u3002</li>\n    <li>\u73b0\u6709\u8bc4\u4f30\u4e3b\u8981\u901a\u8fc7\u4efb\u52a1\u6210\u529f\u7387\u6765\u8861\u91cf\u4ee3\u7406\u8bb0\u5fc6\uff0c\u672a\u6df1\u5165\u63a2\u8ba8\u7cfb\u7edf\u7ea7\u522b\u7684\u5173\u952e\u95ee\u9898\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u4e86\u4e00\u4e2a\u5206\u6790\u6846\u67b6\uff0c\u5c06\u4ee3\u7406\u8bb0\u5fc6\u5206\u4e3a\u56db\u4e2a\u6838\u5fc3\u6a21\u5757\uff0c\u5e76\u5bf912\u4e2a\u8bb0\u5fc6\u7cfb\u7edf\u8fdb\u884c\u4e86\u8bc4\u4f30\u3002</li>\n    <li>\u7814\u7a76\u53d1\u73b0\u6ca1\u6709\u5355\u4e00\u67b6\u6784\u5728\u6240\u6709\u573a\u666f\u4e2d\u8868\u73b0\u6700\u4f73\uff0c\u6548\u679c\u4f9d\u8d56\u4e8e\u8bb0\u5fc6\u7ed3\u6784\u4e0e\u5de5\u4f5c\u8d1f\u8f7d\u7684\u5339\u914d\u7a0b\u5ea6\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793a\u5c40\u90e8\u7ef4\u62a4\u6bd4\u5168\u5c40\u91cd\u7ec4\u66f4\u5177\u6210\u672c\u6548\u76ca\uff0c\u5e76\u4e3a\u6784\u5efa\u66f4\u597d\u7684\u4ee3\u7406\u8bb0\u5fc6\u7cfb\u7edf\u63d0\u4f9b\u4e86\u65b9\u5411\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Memory for large language model agents has improved to include persistent storage and management of information.</li>\n    <li>Current evaluations of agent memory focus too much on task success metrics and overlook important system-level issues.</li>\n    <li>This paper introduces a framework that breaks down agent memory into four main components for better analysis.</li>\n    <li>Experiments show that no single memory architecture works best for all tasks; effectiveness varies based on specific workloads.</li>\n    <li>The study highlights cost-performance trade-offs and suggests localized maintenance is more efficient than global changes.</li>\n</ul>"}, "publishedAt": "2026-06-22T20:00:00.000Z", "title": "Are We Ready For An Agent-Native Memory System?", "summary": "Memory for large language model (LLM) agents has rapidly evolved from simple retrieval-augmented mechanisms into a data management system that supports persistent information storage, retrieval, update, consolidation, and dynamic lifecycle governance throughout agent execution. Despite this evolution, existing evaluations still benchmark agent memory mainly through end-to-end task success metrics (e.g., F1, BLEU), while treating the underlying system as a monolithic black box. As a result, critical system-level concerns, including operational costs, architectural trade-offs across memory modules, and robustness under dynamic knowledge updates, remain insufficiently explored. In this paper, we present a systematic experimental study of agent memory from a data management perspective. We propose an analytical framework that decomposes agent memory into four core modules: memory representation and storage, extraction, retrieval and routing, and maintenance. Under this framework, we evaluate 12 representative memory systems and two reference baselines across five benchmark workloads spanning 11 datasets. Our extensive end-to-end evaluation shows that no single architecture dominates across all scenarios; instead, effectiveness depends heavily on how well the memory structure aligns with the workload bottleneck. Furthermore, through fine-grained ablation studies, we quantify their individual effects on representation fidelity, retrieval precision, update correctness, and long-horizon stability. Finally, we reveal cost-performance trade-offs under realistic workloads, showing localized maintenance is more cost-efficient than global reorganization. Based on these findings, we identify promising directions towards building truly agent-native memory systems. The code is publicly available at https://github.com/OpenDataBox/MemoryData.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.24775.png", "numComments": 3, "submittedBy": {"_id": "68216c63856b96f869d1d116", "avatarUrl": "/avatars/f69026ca75377e6754ab3e317879e35a.svg", "fullname": "Wei Zhou", "name": "weizhoudb", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.24597", "authors": [{"_id": "6a3b3b320a86ac3098d5d652", "name": "Yuxin Zuo", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d653", "name": "Zikai Xiao", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d654", "name": "Li Sheng", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d655", "name": "Fei Huang", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d656", "name": "Jianhong Tu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d657", "name": "Yuxuan Liu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d658", "name": "Tianyi Tang", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d659", "name": "Xiaomeng Hu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d65a", "name": "Yang Su", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d65b", "name": "Qingfeng Lan", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d65c", "name": "Yantao Liu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d65d", "name": "Qin Zhu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d65e", "name": "Yinger Zhang", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d65f", "name": "Bowen Yu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d660", "name": "Haiquan Zhao", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d661", "name": "Haiyang Xu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d662", "name": "Jianxin Yang", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d663", "name": "Jiayang Cheng", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d664", "name": "Junyang Wang", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d665", "name": "Lianghao Deng", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d666", "name": "Mingfeng Xue", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d667", "name": "Tianyi Bai", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d668", "name": "Yang Fan", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d669", "name": "Yubo Ma", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d66a", "name": "Yucheng Li", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d66b", "name": "Zeyu Cui", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d66c", "name": "Zhihai Wang", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d66d", "name": "Zhihui Xie", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d66e", "name": "Zhuorui Ye", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d66f", "name": "An Yang", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d670", "name": "Dayiheng Liu", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d671", "name": "Jingren Zhou", "hidden": false}, {"_id": "6a3b3b320a86ac3098d5d672", "name": "Ning Ding", "hidden": false}], "publishedAt": "2026-06-23T00:00:00.000Z", "submittedOnDailyAt": "2026-06-24T00:00:00.000Z", "title": "Qwen-AgentWorld: Language World Models for General Agents", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "A world model predicts environment dynamics based on current observations and actions, serving as a core cognitive mechanism for reasoning and planning. In this work, we investigate how world modeling based on language models can further push the boundaries of general agents. (i) We first focus on building foundation models for agentic environment simulation. We introduce Qwen-AgentWorld-35B-A3B and Qwen-AgentWorld-397B-A17B, the first language world models capable of simulating agentic environments covering 7 domains via long chain-of-thought reasoning. Leveraging more than 10M environment interaction trajectories of 7 domains in real-world environments, we develop Qwen-AgentWorld through a three-stage training pipeline: CPT injects general-purpose world modeling capabilities from the state transition dynamics and augmented professional corpora, SFT activates next-state-prediction reasoning, and RL sharpens simulation fidelity through a tailored framework with hybrid rubric-and-rule rewards. To evaluate language world models, we present AgentWorldBench, a comprehensive benchmark constructed from real-world interactions of 5 frontier models on 9 established benchmarks. Empirical results demonstrate that Qwen-AgentWorld significantly outperforms existing frontier models. (ii) Beyond foundation models, we further investigate two complementary paradigms through which world modeling enhances general agents. First, as a decoupled environment simulator, Qwen-AgentWorld supports scalable and controllable simulation of thousands of real-world environments for agentic RL, yielding gains that surpass real-environment training alone. Second, as a unified agent foundation model, world-model training acts as a highly effective warm-up that improves downstream performance across 7 agentic benchmarks. Code: https://github.com/QwenLM/Qwen-AgentWorld", "upvotes": 88, "discussionId": "6a3b3b330a86ac3098d5d673", "ai_summary": "Language-based world models enable agentic environment simulation across multiple domains and enhance general agent performance through scalable simulation and improved downstream task performance.", "ai_keywords": ["world model", "language models", "agentic environment simulation", "long chain-of-thought reasoning", "foundation models", "state transition dynamics", "next-state-prediction reasoning", "reinforcement learning", "hybrid rubric-and-rule rewards", "AgentWorldBench", "agentic reinforcement learning", "warm-up"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6215ca5692c0ecfba9186921/hrRM50-6XcdWgg2AKpENG.jpeg"}, "summary_zh": "<ul>\n    <li>\u7814\u7a76\u4e86\u57fa\u4e8e\u8bed\u8a00\u6a21\u578b\u7684\u4e16\u754c\u5efa\u6a21\uff0c\u63a8\u52a8\u901a\u7528\u667a\u80fd\u4f53\u7684\u80fd\u529b\u3002</li>\n    <li>\u63a8\u51fa\u4e86Qwen-AgentWorld-35B-A3B\u548cQwen-AgentWorld-397B-A17B\uff0c\u80fd\u591f\u6a21\u62df7\u4e2a\u9886\u57df\u7684\u667a\u80fd\u73af\u5883\u3002</li>\n    <li>\u901a\u8fc7\u4e09\u9636\u6bb5\u8bad\u7ec3\u6d41\u7a0b\u63d0\u9ad8\u6a21\u578b\u6027\u80fd\uff0c\u5229\u7528\u771f\u5b9e\u73af\u5883\u768410M\u4e92\u52a8\u8f68\u8ff9\u3002</li>\n    <li>\u5efa\u7acb\u4e86AgentWorldBench\u57fa\u51c6\u6d4b\u8bd5\uff0cQwen-AgentWorld\u5728\u591a\u4e2a\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u4e8e\u73b0\u6709\u6a21\u578b\u3002</li>\n    <li>\u4f5c\u4e3a\u73af\u5883\u6a21\u62df\u5668\uff0cQwen-AgentWorld\u652f\u6301\u53ef\u6269\u5c55\u7684\u667a\u80fd\u5f3a\u5316\u5b66\u4e60\u8bad\u7ec3\uff0c\u63d0\u5347\u4e86\u6a21\u578b\u7684\u6574\u4f53\u8868\u73b0\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>This research focuses on developing world models that predict how environments change based on observations and actions, which helps in reasoning and planning.</li>\n    <li>They introduced two new language models, Qwen-AgentWorld-35B-A3B and Qwen-AgentWorld-397B-A17B, capable of simulating complex environments across seven different areas.</li>\n    <li>The models were trained using a three-stage process that improves their ability to predict what happens next in a simulation.</li>\n    <li>They created a benchmark called AgentWorldBench to evaluate these models, and the results showed that Qwen-AgentWorld performed better than existing models.</li>\n    <li>Qwen-AgentWorld can simulate thousands of real-world environments, providing better training for agents and improving their performance across multiple tasks.</li>\n</ul>"}, "publishedAt": "2026-06-22T20:00:00.000Z", "title": "Qwen-AgentWorld: Language World Models for General Agents", "summary": "A world model predicts environment dynamics based on current observations and actions, serving as a core cognitive mechanism for reasoning and planning. In this work, we investigate how world modeling based on language models can further push the boundaries of general agents. (i) We first focus on building foundation models for agentic environment simulation. We introduce Qwen-AgentWorld-35B-A3B and Qwen-AgentWorld-397B-A17B, the first language world models capable of simulating agentic environments covering 7 domains via long chain-of-thought reasoning. Leveraging more than 10M environment interaction trajectories of 7 domains in real-world environments, we develop Qwen-AgentWorld through a three-stage training pipeline: CPT injects general-purpose world modeling capabilities from the state transition dynamics and augmented professional corpora, SFT activates next-state-prediction reasoning, and RL sharpens simulation fidelity through a tailored framework with hybrid rubric-and-rule rewards. To evaluate language world models, we present AgentWorldBench, a comprehensive benchmark constructed from real-world interactions of 5 frontier models on 9 established benchmarks. Empirical results demonstrate that Qwen-AgentWorld significantly outperforms existing frontier models. (ii) Beyond foundation models, we further investigate two complementary paradigms through which world modeling enhances general agents. First, as a decoupled environment simulator, Qwen-AgentWorld supports scalable and controllable simulation of thousands of real-world environments for agentic RL, yielding gains that surpass real-environment training alone. Second, as a unified agent foundation model, world-model training acts as a highly effective warm-up that improves downstream performance across 7 agentic benchmarks. Code: https://github.com/QwenLM/Qwen-AgentWorld", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.24597.png", "numComments": 2, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 322, "isUserFollowing": false}, "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6215ca5692c0ecfba9186921/hrRM50-6XcdWgg2AKpENG.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.23654", "authors": [{"_id": "6a3a0213fdcd3514343bb586", "name": "Jincheng Zhong", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb587", "name": "Weizhi Wang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb588", "name": "Che Jiang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb589", "name": "Kai Tian", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58a", "name": "Zhenzhao Yuan", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58b", "name": "Junlin Yang", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58c", "name": "Dianqiao Lei", "hidden": false}, {"_id": "6a3a0213fdcd3514343bb58d", "user": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "isPro": false, "fullname": "Kaiyan Zhang", "user": "iseesaw", "type": "user", "name": "iseesaw"}, "name": "Kaiyan Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:30.920Z", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "EnterpriseClawBench: Benchmarking Agents from Real Workplace Sessions", "submittedOnDailyBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "isPro": false, "fullname": "Kaiyan Zhang", "user": "iseesaw", "type": "user", "name": "iseesaw"}, "summary": "Enterprise agents increasingly operate inside workspaces: they read heterogeneous files, invoke tools, and deliver business artifacts. We introduce EnterpriseClawBench, an enterprise agent benchmark constructed from proprietary, real-world agent sessions. Starting from a large archive of workplace sessions, the EnterpriseClawBench produces 852 reproducible tasks, each paired with recovered fixtures, rewritten prompts, role classes, skill subclasses, hard rules, and semantic rubrics. Because the sessions contain internal enterprise content, we do not release the benchmark data; instead, our reusable contribution is the construction and evaluation protocol. On EnterpriseClawBench, the best configuration reaches only 0.663 (Codex with GPT-5.5). These results show that enterprise agent evaluation must report harness--model combinations, artifact delivery, visual quality, cost, runtime, and skill-transfer behavior, rather than collapsing performance into a single score. Code: https://github.com/FrontisAI/EnterpriseClawBench", "upvotes": 57, "discussionId": "6a3a0213fdcd3514343bb58e", "projectPage": "https://frontisai.github.io/EnterpriseClawBench/", "githubRepo": "https://github.com/FrontisAI/EnterpriseClawBench", "githubRepoAddedBy": "user", "ai_summary": "EnterpriseClawBench presents a benchmark for enterprise agents based on real-world sessions with 852 reproducible tasks, emphasizing comprehensive evaluation metrics beyond single performance scores.", "ai_keywords": ["enterprise agent benchmark", "reproducible tasks", "workplace sessions", "harness--model combinations", "artifact delivery", "skill-transfer behavior"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 28, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "summary_zh": "<ul>\n    <li>\u4f01\u4e1a\u4ee3\u7406\u5728\u5de5\u4f5c\u7a7a\u95f4\u4e2d\u8d8a\u6765\u8d8a\u591a\u5730\u64cd\u4f5c\uff0c\u5904\u7406\u5404\u79cd\u6587\u4ef6\u548c\u5de5\u5177\u3002</li>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86EnterpriseClawBench\uff0c\u8fd9\u662f\u4e00\u4e2a\u57fa\u4e8e\u771f\u5b9e\u4ee3\u7406\u4f1a\u8bdd\u6784\u5efa\u7684\u4f01\u4e1a\u4ee3\u7406\u57fa\u51c6\u3002</li>\n    <li>EnterpriseClawBench\u751f\u6210\u4e86852\u4e2a\u53ef\u91cd\u590d\u7684\u4efb\u52a1\uff0c\u6bcf\u4e2a\u4efb\u52a1\u90fd\u6709\u76f8\u5e94\u7684\u56fa\u5b9a\u6570\u636e\u548c\u8bc4\u4f30\u6807\u51c6\u3002</li>\n    <li>\u7531\u4e8e\u4f1a\u8bdd\u5305\u542b\u5185\u90e8\u4f01\u4e1a\u5185\u5bb9\uff0c\u6211\u4eec\u4e0d\u516c\u5f00\u57fa\u51c6\u6570\u636e\uff0c\u800c\u662f\u63d0\u4f9b\u6784\u5efa\u548c\u8bc4\u4f30\u534f\u8bae\u3002</li>\n    <li>\u8bc4\u4f30\u7ed3\u679c\u663e\u793a\uff0c\u6700\u4f73\u914d\u7f6e\u7684\u5f97\u5206\u4e3a0.663\uff0c\u5f3a\u8c03\u4e86\u8bc4\u4f30\u5e94\u62a5\u544a\u591a\u79cd\u6027\u80fd\u6307\u6807\uff0c\u800c\u975e\u5355\u4e00\u5206\u6570\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Enterprise agents help with tasks in workplaces by reading files, using tools, and delivering business outputs.</li>\n    <li>EnterpriseClawBench is a new benchmark created from real workplace agent sessions, featuring 852 tasks with various supporting materials.</li>\n    <li>The benchmark data is not shared due to confidentiality, but the methods for building and evaluating it are available.</li>\n    <li>Current best performance on this benchmark is 0.663 with a specific model combination (Codex with GPT-5.5).</li>\n    <li>Evaluating enterprise agents should consider multiple factors, not just a single performance score.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "EnterpriseClawBench: Benchmarking Agents from Real Workplace Sessions", "summary": "Enterprise agents increasingly operate inside workspaces: they read heterogeneous files, invoke tools, and deliver business artifacts. We introduce EnterpriseClawBench, an enterprise agent benchmark constructed from proprietary, real-world agent sessions. Starting from a large archive of workplace sessions, the EnterpriseClawBench produces 852 reproducible tasks, each paired with recovered fixtures, rewritten prompts, role classes, skill subclasses, hard rules, and semantic rubrics. Because the sessions contain internal enterprise content, we do not release the benchmark data; instead, our reusable contribution is the construction and evaluation protocol. On EnterpriseClawBench, the best configuration reaches only 0.663 (Codex with GPT-5.5). These results show that enterprise agent evaluation must report harness--model combinations, artifact delivery, visual quality, cost, runtime, and skill-transfer behavior, rather than collapsing performance into a single score. Code: https://github.com/FrontisAI/EnterpriseClawBench", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.23654.png", "numComments": 1, "submittedBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "fullname": "Kaiyan Zhang", "name": "iseesaw", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 11, "isUserFollowing": false}, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.26058", "authors": [{"_id": "6a3c9080f3facdb67e9ff08a", "user": {"_id": "6629d7c9fa14eaccf07d8633", "avatarUrl": "/avatars/dceb2f6c804c583adf15a3536c8c995b.svg", "isPro": false, "fullname": "Nan Chen", "user": "CNcreator0331", "type": "user", "name": "CNcreator0331"}, "name": "Nan Chen", "status": "claimed_verified", "statusLastChangedAt": "2026-06-25T09:15:41.430Z", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff08b", "name": "Yiyang Cai", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff08c", "name": "Rongchang Xie", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff08d", "name": "Junwen Pan", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff08e", "name": "Cheng Chen", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff08f", "name": "Weinan Jia", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff090", "name": "Zhuowei Chen", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff091", "name": "Wen Zhou", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff092", "name": "Zhenbang Sun", "hidden": false}, {"_id": "6a3c9080f3facdb67e9ff093", "name": "Wenhan Luo", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6629d7c9fa14eaccf07d8633/Qa2e7wRuuIQ1ooXGw9tbF.mp4"], "publishedAt": "2026-06-24T00:00:00.000Z", "submittedOnDailyAt": "2026-06-25T00:00:00.000Z", "title": "DomainShuttle: Freeform Open Domain Subject-driven Text-to-video Generation", "submittedOnDailyBy": {"_id": "6629d7c9fa14eaccf07d8633", "avatarUrl": "/avatars/dceb2f6c804c583adf15a3536c8c995b.svg", "isPro": false, "fullname": "Nan Chen", "user": "CNcreator0331", "type": "user", "name": "CNcreator0331"}, "summary": "Open domain subject-driven text-to-video (S2V) generation has drawn significant interest in academia and industry. Open domain S2V mainly involves two scenarios: in-domain, which requires retaining the reference subject features as much as possible, and cross-domain, which preserves the intrinsic features of the subject while allowing subject-irrelevant properties to vary flexibly according to the text prompt. Existing methods primarily focus on maximizing subject fidelity in in-domain scenarios, which limits their editability and adaptability in cross-domain scenarios, such as novel styles, semantic combinations, or domain attributes. In this study, we propose that an ideal S2V method should flexibly shuttle between different domains, achieving strong performance in both in-domain and cross-domain scenarios. To this end, we propose DomainShuttle, which could achieve high fidelity and generative flexibility for open domain video personalization. Specifically, we introduce Domain-MoT, which decouples videos and reference features and introduces the domain-aware AdaLN for domain-specific modeling of reference images. We then introduce the Video-Reference DualRoPE scheme, which places reference image tokens and video tokens in separate RoPE spaces to enable precise subject-level spatial modeling, and Cross-Pair Consistent Loss, which aims to extract intrinsic subject features unaffected by irrelevant features. Extensive experiments demonstrate that DomainShuttle achieves significant performance improvements over existing methods, exhibiting high subject fidelity and generative flexibility across diverse open domain application scenarios.", "upvotes": 55, "discussionId": "6a3c9081f3facdb67e9ff094", "projectPage": "https://cn-makers.github.io/DomainShuttle/", "githubRepo": "https://github.com/HKUST-C4G/DomainShuttle", "githubRepoAddedBy": "user", "ai_summary": "DomainShuttle enables open domain subject-driven text-to-video generation with high fidelity and flexibility across in-domain and cross-domain scenarios through domain-aware modeling and dual RoPE schemes.", "ai_keywords": ["text-to-video generation", "domain-aware AdaLN", "Video-Reference DualRoPE", "Cross-Pair Consistent Loss", "domain-specific modeling", "subject-level spatial modeling", "reference image tokens", "video tokens", "RoPE spaces"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 66, "summary_zh": "<ul>\n    <li>\u5f00\u653e\u9886\u57df\u7684\u6587\u672c\u5230\u89c6\u9891\u751f\u6210\uff08S2V\uff09\u5728\u5b66\u672f\u548c\u5de5\u4e1a\u754c\u53d7\u5230\u5e7f\u6cdb\u5173\u6ce8\u3002</li>\n    <li>S2V\u5305\u62ec\u4e24\u79cd\u573a\u666f\uff1a\u4fdd\u6301\u4e3b\u9898\u7279\u5f81\u7684\u540c\u57df\u573a\u666f\u548c\u5141\u8bb8\u7075\u6d3b\u53d8\u5316\u7684\u8de8\u57df\u573a\u666f\u3002</li>\n    <li>\u73b0\u6709\u65b9\u6cd5\u4e3b\u8981\u4e13\u6ce8\u4e8e\u540c\u57df\u573a\u666f\u4e2d\u7684\u4e3b\u9898\u4fdd\u771f\u5ea6\uff0c\u9650\u5236\u4e86\u8de8\u57df\u573a\u666f\u7684\u53ef\u7f16\u8f91\u6027\u548c\u9002\u5e94\u6027\u3002</li>\n    <li>\u672c\u6587\u63d0\u51faDomainShuttle\uff0c\u80fd\u591f\u5728\u4e0d\u540c\u9886\u57df\u4e4b\u95f4\u7075\u6d3b\u5207\u6362\uff0c\u5b9e\u73b0\u9ad8\u4fdd\u771f\u5ea6\u548c\u751f\u6210\u7075\u6d3b\u6027\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cDomainShuttle\u5728\u5404\u7c7b\u5f00\u653e\u9886\u57df\u5e94\u7528\u4e2d\u663e\u8457\u63d0\u5347\u4e86\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Open domain subject-driven text-to-video (S2V) generation is gaining attention in research and industry.</li>\n    <li>There are two main scenarios: in-domain, which keeps the subject features intact, and cross-domain, which allows for more flexibility in changes based on text prompts.</li>\n    <li>Current methods focus too much on keeping subject features, making them less adaptable to new styles and combinations.</li>\n    <li>The study introduces DomainShuttle, a method that balances strong performance in both in-domain and cross-domain scenarios.</li>\n    <li>DomainShuttle uses new techniques for better video personalization and shows significant improvements over existing methods. </li>\n</ul>"}, "publishedAt": "2026-06-23T20:00:00.000Z", "title": "DomainShuttle: Freeform Open Domain Subject-driven Text-to-video Generation", "summary": "Open domain subject-driven text-to-video (S2V) generation has drawn significant interest in academia and industry. Open domain S2V mainly involves two scenarios: in-domain, which requires retaining the reference subject features as much as possible, and cross-domain, which preserves the intrinsic features of the subject while allowing subject-irrelevant properties to vary flexibly according to the text prompt. Existing methods primarily focus on maximizing subject fidelity in in-domain scenarios, which limits their editability and adaptability in cross-domain scenarios, such as novel styles, semantic combinations, or domain attributes. In this study, we propose that an ideal S2V method should flexibly shuttle between different domains, achieving strong performance in both in-domain and cross-domain scenarios. To this end, we propose DomainShuttle, which could achieve high fidelity and generative flexibility for open domain video personalization. Specifically, we introduce Domain-MoT, which decouples videos and reference features and introduces the domain-aware AdaLN for domain-specific modeling of reference images. We then introduce the Video-Reference DualRoPE scheme, which places reference image tokens and video tokens in separate RoPE spaces to enable precise subject-level spatial modeling, and Cross-Pair Consistent Loss, which aims to extract intrinsic subject features unaffected by irrelevant features. Extensive experiments demonstrate that DomainShuttle achieves significant performance improvements over existing methods, exhibiting high subject fidelity and generative flexibility across diverse open domain application scenarios.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6629d7c9fa14eaccf07d8633/Qa2e7wRuuIQ1ooXGw9tbF.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.26058.png", "numComments": 1, "submittedBy": {"_id": "6629d7c9fa14eaccf07d8633", "avatarUrl": "/avatars/dceb2f6c804c583adf15a3536c8c995b.svg", "fullname": "Nan Chen", "name": "CNcreator0331", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 8, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.27377", "authors": [{"_id": "6a3dda9a3b43e283349ec108", "name": "Wei Zhou", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec109", "name": "Xiongwei Zhu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10a", "name": "Zelin Xu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10b", "name": "Bo Dong", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10c", "name": "Lixue Gong", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10d", "name": "Yongyuan Liang", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10e", "name": "Meng Chu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec10f", "name": "Leigang Qu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec110", "name": "Lingdong Kong", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec111", "name": "Wei Liu", "hidden": false}, {"_id": "6a3dda9a3b43e283349ec112", "name": "Tat-Seng Chua", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/T73l6bcCjjqWVVvz1mioW.qt"], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "DanceOPD: On-Policy Generative Field Distillation", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Modern image generation demands a single model that unifies diverse capabilities, including text-to-image (T2I), local editing, and global editing. However, these capabilities are rarely naturally aligned and often conflict. For instance, editing tends to degrade T2I performance, while global and local editing interfere with each other. Consequently, effectively composing these capabilities has become a central challenge for image generation model training. To tackle this, we introduce DanceOPD, an on-policy generative field distillation framework for flow-matching models that routes each sample to one capability field, queries one low-noise student-induced state, and trains with a simple velocity MSE objective. With each capability source defined as a velocity field over the shared flow state space, the student learns from fields queried on its own rollout states to compose expert capabilities. This formulation also absorbs operator-defined fields such as classifier-free guidance. Comprehensive experiments on T2I, editing, realism-field absorption, and CFG absorption show that our approach improves multi-capability composition, strengthening target capabilities while preserving anchor generation quality. We believe this work establishes a practical route for generative field distillation in flow-matching models.", "upvotes": 54, "discussionId": "6a3dda9a3b43e283349ec113", "projectPage": "https://danceopd.github.io/", "ai_summary": "A novel on-policy generative field distillation framework called DanceOPD is proposed to unify text-to-image generation, local editing, and global editing capabilities in flow-matching models through capability-specific routing and velocity-based training.", "ai_keywords": ["generative field distillation", "flow-matching models", "on-policy", "velocity MSE objective", "velocity field", "classifier-free guidance", "text-to-image", "local editing", "global editing", "student model", "expert capabilities"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u4ee3\u56fe\u50cf\u751f\u6210\u9700\u8981\u4e00\u4e2a\u7edf\u4e00\u7684\u6a21\u578b\uff0c\u5177\u5907\u6587\u672c\u5230\u56fe\u50cf\u751f\u6210\u3001\u5c40\u90e8\u7f16\u8f91\u548c\u5168\u5c40\u7f16\u8f91\u7b49\u591a\u79cd\u529f\u80fd\u3002</li>\n    <li>\u8fd9\u4e9b\u529f\u80fd\u4e4b\u95f4\u5f80\u5f80\u4e0d\u517c\u5bb9\uff0c\u53ef\u80fd\u5bfc\u81f4\u6027\u80fd\u4e0b\u964d\uff0c\u5982\u7f16\u8f91\u4f1a\u5f71\u54cd\u6587\u672c\u5230\u56fe\u50cf\u751f\u6210\u7684\u6548\u679c\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u8fd9\u4e2a\u95ee\u9898\uff0c\u63d0\u51fa\u4e86DanceOPD\u6846\u67b6\uff0c\u901a\u8fc7\u6d41\u5339\u914d\u6a21\u578b\u6765\u6709\u6548\u7ec4\u5408\u8fd9\u4e9b\u529f\u80fd\u3002</li>\n    <li>\u8be5\u6846\u67b6\u901a\u8fc7\u7b80\u5355\u7684\u901f\u5ea6\u5747\u65b9\u8bef\u5dee\u76ee\u6807\u6765\u8bad\u7ec3\u6a21\u578b\uff0c\u4f7f\u5176\u80fd\u591f\u5b66\u4e60\u548c\u6574\u5408\u4e0d\u540c\u7684\u529f\u80fd\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cDanceOPD\u5728\u591a\u529f\u80fd\u7ec4\u5408\u65b9\u9762\u8868\u73b0\u4f18\u5f02\uff0c\u540c\u65f6\u4fdd\u6301\u751f\u6210\u8d28\u91cf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Modern image generation needs a single model that can handle different tasks like text-to-image, local editing, and global editing.</li>\n    <li>These tasks often conflict with each other, making it hard to combine them effectively.</li>\n    <li>To address this, the researchers developed DanceOPD, a new framework that focuses on training models efficiently for these tasks.</li>\n    <li>DanceOPD uses a technique where each sample is assigned to one specific capability, allowing the model to learn better from each task.</li>\n    <li>Experiments show that this approach improves the model's ability to combine different tasks while maintaining high-quality image generation.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "DanceOPD: On-Policy Generative Field Distillation", "summary": "Modern image generation demands a single model that unifies diverse capabilities, including text-to-image (T2I), local editing, and global editing. However, these capabilities are rarely naturally aligned and often conflict. For instance, editing tends to degrade T2I performance, while global and local editing interfere with each other. Consequently, effectively composing these capabilities has become a central challenge for image generation model training. To tackle this, we introduce DanceOPD, an on-policy generative field distillation framework for flow-matching models that routes each sample to one capability field, queries one low-noise student-induced state, and trains with a simple velocity MSE objective. With each capability source defined as a velocity field over the shared flow state space, the student learns from fields queried on its own rollout states to compose expert capabilities. This formulation also absorbs operator-defined fields such as classifier-free guidance. Comprehensive experiments on T2I, editing, realism-field absorption, and CFG absorption show that our approach improves multi-capability composition, strengthening target capabilities while preserving anchor generation quality. We believe this work establishes a practical route for generative field distillation in flow-matching models.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/T73l6bcCjjqWVVvz1mioW.qt"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.27377.png", "numComments": 2, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 323, "isUserFollowing": false}, "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.24530", "authors": [{"_id": "6a3b4a590a86ac3098d5d701", "name": "Yuru Wang", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d702", "name": "Lejun Cheng", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d703", "name": "Yuxin Zuo", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d704", "name": "Sihang Zeng", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d705", "name": "Bingxiang He", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d706", "name": "Che Jiang", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d707", "name": "Junlin Yang", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d708", "name": "Yuchong Wang", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d709", "name": "Kaikai Zhao", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d70a", "name": "Weifeng Huang", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d70b", "name": "Kai Tian", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d70c", "name": "Zhenzhao Yuan", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d70d", "name": "Jincheng Zhong", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d70e", "name": "Weizhi Wang", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d70f", "name": "Ning Ding", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d710", "name": "Bowen Zhou", "hidden": false}, {"_id": "6a3b4a590a86ac3098d5d711", "name": "Kaiyan Zhang", "hidden": false}], "publishedAt": "2026-06-23T00:00:00.000Z", "submittedOnDailyAt": "2026-06-24T00:00:00.000Z", "title": "NatureBench: Can Coding Agents Match the Published SOTA of Nature-Family Papers?", "submittedOnDailyBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "isPro": false, "fullname": "Kaiyan Zhang", "user": "iseesaw", "type": "user", "name": "iseesaw"}, "summary": "We introduce NatureBench, a cross-discipline benchmark of 90 tasks distilled from peer-reviewed Nature-family publications, designed to evaluate whether AI coding agents can move beyond reproduction toward discovery on real scientific problems. NatureBench is built on NatureGym, an automated pipeline that constructs a standardized, per-task containerized environment from a source paper, addressing the environment-fragmentation problem that has limited the credibility of prior agent-on-research benchmarks. Evaluating ten frontier agent configurations under a strict web-search-disabled protocol, we find that the strongest model surpasses SOTA on only 17.8% of tasks under the g>0.1 criterion. Analysis of method pathways reveals that agents succeed primarily through methodological translation, converting scientific tasks into familiar supervised prediction problems, rather than through genuine scientific invention. Failures are dominated by wrong method choice and insufficient compute budget, not by task misunderstanding. We release the benchmark, the NatureGym pipeline, and a public leaderboard with maintainer-side reproduction. Code: https://github.com/FrontisAI/NatureBench", "upvotes": 48, "discussionId": "6a3b4a590a86ac3098d5d712", "projectPage": "https://frontisai.github.io/NatureBench/", "githubRepo": "https://github.com/FrontisAI/NatureBench", "githubRepoAddedBy": "user", "ai_summary": "NatureBench presents a cross-disciplinary benchmark of 90 scientific tasks derived from Nature publications to assess AI coding agents' ability to achieve discovery rather than just reproduction, revealing that current agents primarily rely on methodological translation rather than genuine scientific innovation.", "ai_keywords": ["NatureBench", "NatureGym", "AI coding agents", "scientific discovery", "methodological translation", "supervised prediction problems", "environment-fragmentation problem", "cross-discipline benchmark", "peer-reviewed publications", "containerized environment"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 29, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u63a8\u51fa\u4e86NatureBench\uff0c\u8fd9\u662f\u4e00\u4e2a\u5305\u542b90\u4e2a\u4efb\u52a1\u7684\u8de8\u5b66\u79d1\u57fa\u51c6\uff0c\u65e8\u5728\u8bc4\u4f30AI\u7f16\u7801\u4ee3\u7406\u5728\u79d1\u5b66\u95ee\u9898\u4e0a\u662f\u5426\u80fd\u8d85\u8d8a\u7b80\u5355\u590d\u73b0\uff0c\u5b9e\u73b0\u53d1\u73b0\u3002</li>\n    <li>NatureBench\u57fa\u4e8eNatureGym\u6784\u5efa\uff0c\u8be5\u7cfb\u7edf\u81ea\u52a8\u751f\u6210\u6807\u51c6\u5316\u7684\u73af\u5883\uff0c\u4ee5\u89e3\u51b3\u4ee5\u5f80\u57fa\u51c6\u4e2d\u7684\u73af\u5883\u788e\u7247\u5316\u95ee\u9898\u3002</li>\n    <li>\u5728\u7981\u7528\u7f51\u7edc\u641c\u7d22\u7684\u4e25\u683c\u534f\u8bae\u4e0b\u8bc4\u4f30\u4e86\u5341\u79cd\u524d\u6cbf\u4ee3\u7406\u914d\u7f6e\uff0c\u53d1\u73b0\u6700\u5f3a\u6a21\u578b\u4ec5\u572817.8%\u7684\u4efb\u52a1\u4e2d\u8d85\u8fc7\u73b0\u6709\u6700\u4f73\u6c34\u5e73\u3002</li>\n    <li>\u5206\u6790\u8868\u660e\uff0c\u4ee3\u7406\u4e3b\u8981\u901a\u8fc7\u5c06\u79d1\u5b66\u4efb\u52a1\u8f6c\u5316\u4e3a\u719f\u6089\u7684\u76d1\u7763\u9884\u6d4b\u95ee\u9898\u6765\u53d6\u5f97\u6210\u529f\uff0c\u800c\u975e\u771f\u6b63\u7684\u79d1\u5b66\u521b\u65b0\u3002</li>\n    <li>\u6211\u4eec\u7684\u5de5\u4f5c\u5305\u62ec\u57fa\u51c6\u3001NatureGym\u7ba1\u9053\u4ee5\u53ca\u4e00\u4e2a\u516c\u5171\u6392\u884c\u699c\uff0c\u4ee3\u7801\u53ef\u5728GitHub\u4e0a\u627e\u5230\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>NatureBench is a new benchmark with 90 tasks from Nature publications to test AI coding agents on real scientific problems.</li>\n    <li>It uses NatureGym, which creates standardized environments for each task to improve consistency in testing.</li>\n    <li>Ten different AI models were tested, but only one performed well on a small percentage of tasks (17.8%).</li>\n    <li>Most AI successes came from adapting existing methods rather than creating new scientific ideas.</li>\n    <li>The benchmark and tools are publicly available, along with a leaderboard for tracking performance.</li>\n</ul>"}, "publishedAt": "2026-06-22T20:00:00.000Z", "title": "NatureBench: Can Coding Agents Match the Published SOTA of Nature-Family Papers?", "summary": "We introduce NatureBench, a cross-discipline benchmark of 90 tasks distilled from peer-reviewed Nature-family publications, designed to evaluate whether AI coding agents can move beyond reproduction toward discovery on real scientific problems. NatureBench is built on NatureGym, an automated pipeline that constructs a standardized, per-task containerized environment from a source paper, addressing the environment-fragmentation problem that has limited the credibility of prior agent-on-research benchmarks. Evaluating ten frontier agent configurations under a strict web-search-disabled protocol, we find that the strongest model surpasses SOTA on only 17.8% of tasks under the g>0.1 criterion. Analysis of method pathways reveals that agents succeed primarily through methodological translation, converting scientific tasks into familiar supervised prediction problems, rather than through genuine scientific invention. Failures are dominated by wrong method choice and insufficient compute budget, not by task misunderstanding. We release the benchmark, the NatureGym pipeline, and a public leaderboard with maintainer-side reproduction. Code: https://github.com/FrontisAI/NatureBench", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.24530.png", "numComments": 1, "submittedBy": {"_id": "60bc94cd85a3ab33829b6211", "avatarUrl": "/avatars/b57d36c7577fbbb42ea5b963eef4144a.svg", "fullname": "Kaiyan Zhang", "name": "iseesaw", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 12, "isUserFollowing": false}, "organization": {"_id": "6a32950e4b5c1c0ebee0e552", "name": "FrontisAI", "fullname": "Frontis AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60bc94cd85a3ab33829b6211/1w_MutesbGw4NwNkA_dn5.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.25041", "authors": [{"_id": "6a3c8617f3facdb67e9ff018", "name": "Lianghua Huang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff019", "name": "Zhifan Wu", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff01a", "name": "Wei Wang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff01b", "name": "Yupeng Shi", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff01c", "name": "Mengyang Feng", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff01d", "name": "Junjie He", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff01e", "name": "Chenwei Xie", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff01f", "name": "Yu Liu", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff020", "name": "Jingren Zhou", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff021", "name": "Ang Wang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff022", "name": "Bang Zhang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff023", "name": "Baole Ai", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff024", "name": "Chen Liang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff025", "name": "Cheng Yu", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff026", "name": "Chongyang Zhong", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff027", "name": "Jinwei Qi", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff028", "name": "Kai Zhu", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff029", "name": "Pandeng Li", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff02a", "name": "Peng Zhang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff02b", "name": "Wenyuan Zhang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff02c", "name": "Xinhua Cheng", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff02d", "name": "Yitong Huang", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff02e", "name": "Yun Zheng", "hidden": false}, {"_id": "6a3c8617f3facdb67e9ff02f", "name": "Zoubin Bi", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/Jr9b2HX4c95VLANHcNzuR.webp", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/52JmBBBq3UEDFLQRAdCBP.webp", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/Bqq4XAclY1G62z64jVNDe.mp4"], "publishedAt": "2026-06-23T00:00:00.000Z", "submittedOnDailyAt": "2026-06-25T00:00:00.000Z", "title": "Wan-Streamer v0.1: End-to-end Real-time Interactive Foundation Models", "submittedOnDailyBy": {"_id": "6522cf31777019ca30d85725", "avatarUrl": "/avatars/a180b096e438e429d445b68fe703e43f.svg", "isPro": false, "fullname": "Lianghua Huang", "user": "lhhuang", "type": "user", "name": "lhhuang"}, "summary": "We present Wan-Streamer, a native-streaming, end-to-end interactive foundation model designed from the ground up for real-time, low-latency, full-duplex audio-visual interaction. Wan-Streamer seamlessly models language, audio, and video as both input and output within a single Transformer, where the sequence is represented as interleaved visual, audio, and text input tokens together with visual, audio, and text output tokens, coordinated by block-causal attention for incremental streaming. Unlike cascaded interactive systems that rely on separate VAD, ASR, language, TTS, audio-driven animation, or video-generation modules, Wan-Streamer does not rely on external language, speech, avatar, or video-generation modules: perception, reasoning, generation, response timing, turn management, and cross-modal synchronization are learned jointly within one unified model, reducing pipeline latency and error accumulation. To support natural audio-visual responsiveness, we redesign the entire stack around streamability, including causal encoders, causal decoders, block-causal attention, and low-latency multimodal token scheduling, enabling streaming units as short as 160 ms at 25 fps. Wan-Streamer achieves approximately 200 ms model-side response latency and approximately 550 ms total interaction latency when combined with 350 ms bidirectional network latency, supporting sub-second duplex audio-visual communication. These results position Wan-Streamer as a unified, end-to-end, multimodal interactive foundation model for low-latency streaming interaction.", "upvotes": 42, "discussionId": "6a3c8617f3facdb67e9ff030", "projectPage": "https://wan-streamer.com/", "ai_summary": "Wan-Streamer is a unified, end-to-end multimodal model that enables real-time audio-visual interaction through causal attention mechanisms and integrated processing of visual, audio, and text modalities.", "ai_keywords": ["Transformer", "block-causal attention", "causal encoders", "causal decoders", "multimodal token scheduling", "audio-visual interaction", "real-time streaming", "low-latency"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "67bc7cd418dd753c02a82684", "name": "Wan-AI", "fullname": "Wan-AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67b610677ea7952def8b29c6/N6jQbbeaa_FcUY-wI1dgG.png"}, "summary_zh": "<ul>\n    <li>Wan-Streamer \u662f\u4e00\u4e2a\u4e3a\u5b9e\u65f6\u3001\u4f4e\u5ef6\u8fdf\u97f3\u89c6\u9891\u4e92\u52a8\u8bbe\u8ba1\u7684\u57fa\u7840\u6a21\u578b\u3002</li>\n    <li>\u5b83\u5c06\u8bed\u8a00\u3001\u97f3\u9891\u548c\u89c6\u9891\u6574\u5408\u5728\u4e00\u4e2a\u6a21\u578b\u4e2d\uff0c\u4f7f\u7528 Transformer \u8fdb\u884c\u5904\u7406\u3002</li>\n    <li>\u4e0e\u4f20\u7edf\u7cfb\u7edf\u4e0d\u540c\uff0cWan-Streamer \u4e0d\u9700\u8981\u5916\u90e8\u6a21\u5757\uff0c\u6240\u6709\u529f\u80fd\u5728\u4e00\u4e2a\u7edf\u4e00\u6a21\u578b\u4e2d\u5b9e\u73b0\u3002</li>\n    <li>\u8be5\u6a21\u578b\u652f\u6301\u77ed\u81f3 160 \u6beb\u79d2\u7684\u6d41\u5f0f\u5904\u7406\uff0c\u80fd\u591f\u5b9e\u73b0\u5feb\u901f\u7684\u97f3\u89c6\u9891\u4e92\u52a8\u3002</li>\n    <li>Wan-Streamer \u7684\u54cd\u5e94\u5ef6\u8fdf\u7ea6\u4e3a 200 \u6beb\u79d2\uff0c\u603b\u4ea4\u4e92\u5ef6\u8fdf\u7ea6\u4e3a 550 \u6beb\u79d2\uff0c\u9002\u5408\u5b9e\u65f6\u6c9f\u901a\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Wan-Streamer is a new model designed for real-time audio and video interaction with low delay.</li>\n    <li>It processes language, audio, and video together without needing separate modules, which reduces errors and speeds up responses.</li>\n    <li>The model allows for very quick interactions, with response times around 200 milliseconds, supporting fast communication.</li>\n    <li>It uses advanced techniques for streaming and managing different types of input and output to ensure smooth interaction.</li>\n    <li>Wan-Streamer is positioned as a comprehensive solution for interactive audio-visual communication.</li>\n</ul>"}, "publishedAt": "2026-06-22T20:00:00.000Z", "title": "Wan-Streamer v0.1: End-to-end Real-time Interactive Foundation Models", "summary": "We present Wan-Streamer, a native-streaming, end-to-end interactive foundation model designed from the ground up for real-time, low-latency, full-duplex audio-visual interaction. Wan-Streamer seamlessly models language, audio, and video as both input and output within a single Transformer, where the sequence is represented as interleaved visual, audio, and text input tokens together with visual, audio, and text output tokens, coordinated by block-causal attention for incremental streaming. Unlike cascaded interactive systems that rely on separate VAD, ASR, language, TTS, audio-driven animation, or video-generation modules, Wan-Streamer does not rely on external language, speech, avatar, or video-generation modules: perception, reasoning, generation, response timing, turn management, and cross-modal synchronization are learned jointly within one unified model, reducing pipeline latency and error accumulation. To support natural audio-visual responsiveness, we redesign the entire stack around streamability, including causal encoders, causal decoders, block-causal attention, and low-latency multimodal token scheduling, enabling streaming units as short as 160 ms at 25 fps. Wan-Streamer achieves approximately 200 ms model-side response latency and approximately 550 ms total interaction latency when combined with 350 ms bidirectional network latency, supporting sub-second duplex audio-visual communication. These results position Wan-Streamer as a unified, end-to-end, multimodal interactive foundation model for low-latency streaming interaction.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/Jr9b2HX4c95VLANHcNzuR.webp", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/52JmBBBq3UEDFLQRAdCBP.webp", "https://cdn-uploads.huggingface.co/production/uploads/6522cf31777019ca30d85725/Bqq4XAclY1G62z64jVNDe.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.25041.png", "numComments": 2, "submittedBy": {"_id": "6522cf31777019ca30d85725", "avatarUrl": "/avatars/a180b096e438e429d445b68fe703e43f.svg", "fullname": "Lianghua Huang", "name": "lhhuang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "organization": {"_id": "67bc7cd418dd753c02a82684", "name": "Wan-AI", "fullname": "Wan-AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67b610677ea7952def8b29c6/N6jQbbeaa_FcUY-wI1dgG.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.22807", "authors": [{"_id": "6a39ecbefdcd3514343bb4d0", "user": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "isPro": false, "fullname": "Xinping Zhao", "user": "Yuki131", "type": "user", "name": "Yuki131"}, "name": "Xinping Zhao", "status": "claimed_verified", "statusLastChangedAt": "2026-06-23T13:56:56.498Z", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d1", "name": "Jiaxin Xu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d2", "name": "Ziqi Dai", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d3", "name": "Xin Zhang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d4", "name": "Shouzheng Huang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d5", "name": "Danyu Tang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d6", "name": "Xinshuo Hu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d7", "name": "Meishan Zhang", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d8", "name": "Baotian Hu", "hidden": false}, {"_id": "6a39ecbefdcd3514343bb4d9", "name": "Min Zhang", "hidden": false}], "publishedAt": "2026-06-22T00:00:00.000Z", "submittedOnDailyAt": "2026-06-23T00:00:00.000Z", "title": "KaLM-Reranker-V1: Fast but Not Late Interaction for Compressed Document Reranking", "submittedOnDailyBy": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "isPro": false, "fullname": "Xinping Zhao", "user": "Yuki131", "type": "user", "name": "Yuki131"}, "summary": "As retrieval systems scale, high-quality reranking becomes increasingly important. However, most existing rerankers, whether encoder-based or decoder-based, jointly encode the query and passage, tightly coupling their computation and limiting deployment efficiency as well as flexibility. We present KaLM-Reranker-V1, a fast but not late-interaction (FBNL) reranker that decouples query and passage computation while retaining expressive relevance modeling. Built on an encoder-decoder architecture, KaLM-Reranker-V1 uses the encoder to pre-encode passages with Matryoshka embedding pooling, while the decoder models the system instruction, user instruction, and query intent; cross-attention then captures relevance between the query context and passage representations. This design makes KaLM-Reranker-V1 efficient through decoupled passage encoding, yet not late interaction, by preserving rich relevance modeling through cross-attention. We instantiate KaLM-Reranker-V1 in three sizes, Nano, Small, and Large, with 0.27B, 1B, and 4B activated parameters, respectively. Extensive experiments on BEIR, MIRACL, and LMEB demonstrate that KaLM-Reranker-V1 achieves strong reranking performance with superior efficiency. On BEIR, KaLM-Reranker-V1 achieves state-of-the-art performance, on par with strong industrial models such as the Qwen3-Reranker series; on MIRACL, despite not being extensively trained on multilingual data, KaLM-Reranker-V1 still shows excellent reranking performance. Moreover, on LMEB, reranking models demonstrate a clear advantage, with even the 0.27B Nano model remaining competitive with 7-12B embedding models.", "upvotes": 39, "discussionId": "6a39ecbefdcd3514343bb4da", "projectPage": "https://kalm-embedding.github.io/", "ai_summary": "KaLM-Reranker-V1 is a fast reranker that decouples query and passage computation using encoder-decoder architecture with Matryoshka embedding pooling and cross-attention for efficient relevance modeling.", "ai_keywords": ["reranker", "encoder-decoder architecture", "Matryoshka embedding pooling", "cross-attention", "late-interaction", "parameter-efficient fine-tuning", "BEIR", "MIRACL", "LMEB"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "organization": {"_id": "68b9671dbd700936ab567c04", "name": "KaLM-Embedding", "fullname": "KaLM-Embedding", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/XteH4tcmsR2E4OT89MPxv.jpeg"}, "summary_zh": "<ul>\n    <li>KaLM-Reranker-V1 \u662f\u4e00\u79cd\u5feb\u901f\u7684\u91cd\u6392\u5e8f\u7cfb\u7edf\uff0c\u89e3\u8026\u4e86\u67e5\u8be2\u548c\u6587\u6bb5\u7684\u8ba1\u7b97\uff0c\u63d0\u9ad8\u4e86\u6548\u7387\u548c\u7075\u6d3b\u6027\u3002</li>\n    <li>\u8be5\u7cfb\u7edf\u57fa\u4e8e\u7f16\u7801\u5668-\u89e3\u7801\u5668\u67b6\u6784\uff0c\u901a\u8fc7 Matryoshka \u5d4c\u5165\u6c60\u5316\u9884\u7f16\u7801\u6587\u6bb5\u3002</li>\n    <li>\u5229\u7528\u4ea4\u53c9\u6ce8\u610f\u529b\u673a\u5236\uff0cKaLM-Reranker-V1 \u80fd\u591f\u6709\u6548\u6355\u6349\u67e5\u8be2\u4e0a\u4e0b\u6587\u4e0e\u6587\u6bb5\u8868\u793a\u4e4b\u95f4\u7684\u76f8\u5173\u6027\u3002</li>\n    <li>KaLM-Reranker-V1 \u63d0\u4f9b\u4e86\u4e09\u79cd\u4e0d\u540c\u89c4\u6a21\uff08Nano\u3001Small \u548c Large\uff09\uff0c\u53c2\u6570\u6570\u91cf\u4ece 0.27B \u5230 4B \u4e0d\u7b49\u3002</li>\n    <li>\u5728\u591a\u4e2a\u6570\u636e\u96c6\uff08BEIR\u3001MIRACL \u548c LMEB\uff09\u4e0a\uff0cKaLM-Reranker-V1 \u8868\u73b0\u51fa\u8272\uff0c\u8fbe\u5230\u4e86\u884c\u4e1a\u9876\u5c16\u6c34\u5e73\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>KaLM-Reranker-V1 is a new system that improves how search results are ranked by separating the processing of queries and passages.</li>\n    <li>It uses an encoder-decoder design, where the encoder prepares passages in advance and the decoder focuses on understanding the query and user instructions.</li>\n    <li>This approach allows for efficient processing while maintaining a strong ability to assess relevance between queries and passages.</li>\n    <li>KaLM-Reranker-V1 comes in three sizes (Nano, Small, and Large) with varying numbers of parameters, making it adaptable for different needs.</li>\n    <li>Tests show that it performs very well on multiple benchmarks, achieving top results comparable to leading models, even with fewer resources.</li>\n</ul>"}, "publishedAt": "2026-06-21T20:00:00.000Z", "title": "KaLM-Reranker-V1: Fast but Not Late Interaction for Compressed Document Reranking", "summary": "As retrieval systems scale, high-quality reranking becomes increasingly important. However, most existing rerankers, whether encoder-based or decoder-based, jointly encode the query and passage, tightly coupling their computation and limiting deployment efficiency as well as flexibility. We present KaLM-Reranker-V1, a fast but not late-interaction (FBNL) reranker that decouples query and passage computation while retaining expressive relevance modeling. Built on an encoder-decoder architecture, KaLM-Reranker-V1 uses the encoder to pre-encode passages with Matryoshka embedding pooling, while the decoder models the system instruction, user instruction, and query intent; cross-attention then captures relevance between the query context and passage representations. This design makes KaLM-Reranker-V1 efficient through decoupled passage encoding, yet not late interaction, by preserving rich relevance modeling through cross-attention. We instantiate KaLM-Reranker-V1 in three sizes, Nano, Small, and Large, with 0.27B, 1B, and 4B activated parameters, respectively. Extensive experiments on BEIR, MIRACL, and LMEB demonstrate that KaLM-Reranker-V1 achieves strong reranking performance with superior efficiency. On BEIR, KaLM-Reranker-V1 achieves state-of-the-art performance, on par with strong industrial models such as the Qwen3-Reranker series; on MIRACL, despite not being extensively trained on multilingual data, KaLM-Reranker-V1 still shows excellent reranking performance. Moreover, on LMEB, reranking models demonstrate a clear advantage, with even the 0.27B Nano model remaining competitive with 7-12B embedding models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.22807.png", "numComments": 2, "submittedBy": {"_id": "658c0b0574e79b9a8e9de89a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/8HeMEOT5cLEzauXGlrqF_.jpeg", "fullname": "Xinping Zhao", "name": "Yuki131", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "68b9671dbd700936ab567c04", "name": "KaLM-Embedding", "fullname": "KaLM-Embedding", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/658c0b0574e79b9a8e9de89a/XteH4tcmsR2E4OT89MPxv.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.25763", "authors": [{"_id": "6a3cb91cf3facdb67e9ff240", "user": {"_id": "6a26a58972e3d7254eb93bf8", "avatarUrl": "/avatars/f16576a32a62b4c66ff1741411e2174c.svg", "isPro": false, "fullname": "Lee", "user": "ShutterMuse", "type": "user", "name": "ShutterMuse"}, "name": "Jiayu Li", "status": "claimed_verified", "statusLastChangedAt": "2026-06-25T09:14:37.173Z", "hidden": false}, {"_id": "6a3cb91cf3facdb67e9ff241", "user": {"_id": "647469b9a51711a3b58bda2b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/647469b9a51711a3b58bda2b/yeDf8Sa8IDEQyney1dGC9.jpeg", "isPro": false, "fullname": "Yixiao Fang", "user": "fangyixiao", "type": "user", "name": "fangyixiao"}, "name": "Yixiao Fang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-25T09:14:32.098Z", "hidden": false}, {"_id": "6a3cb91cf3facdb67e9ff242", "name": "Tianyu Hu", "hidden": false}, {"_id": "6a3cb91cf3facdb67e9ff243", "user": {"_id": "64b914c8ace99c0723ad83a9", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64b914c8ace99c0723ad83a9/B4gxNByeVY_xaOcjwiN1j.jpeg", "isPro": false, "fullname": "Wei Cheng", "user": "wchengad", "type": "user", "name": "wchengad"}, "name": "Wei Cheng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-25T09:14:33.906Z", "hidden": false}, {"_id": "6a3cb91cf3facdb67e9ff244", "name": "Ping Huang", "hidden": false}, {"_id": "6a3cb91cf3facdb67e9ff245", "name": "Zheheng Fan", "hidden": false}, {"_id": "6a3cb91cf3facdb67e9ff246", "name": "Gang Yu", "hidden": false}, {"_id": "6a3cb91cf3facdb67e9ff247", "name": "Xingjun Ma", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/647469b9a51711a3b58bda2b/H971Df6p2IGq8gXpvjuJG.mp4"], "publishedAt": "2026-06-24T00:00:00.000Z", "submittedOnDailyAt": "2026-06-25T00:00:00.000Z", "title": "ShutterMuse: Capture-Time Photography Guidance with MLLMs", "submittedOnDailyBy": {"_id": "647469b9a51711a3b58bda2b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/647469b9a51711a3b58bda2b/yeDf8Sa8IDEQyney1dGC9.jpeg", "isPro": false, "fullname": "Yixiao Fang", "user": "fangyixiao", "type": "user", "name": "fangyixiao"}, "summary": "Real-world photography requires capture-time guidance for both camera framing and subject pose. Yet existing aesthetic cropping benchmarks mainly evaluate post-hoc crop prediction and overlook subject-side recommendations, leaving the capture-time guidance capabilities of multimodal large language models (MLLMs) underexplored. To address this gap, we introduce CaptureGuide-Bench, a benchmark with two complementary tasks: photographer-side composition decision and refinement, and subject-side scene-conditioned pose recommendation. Our evaluation reveals limitations: general-purpose MLLMs can make composition decisions but lack precise refinement localization, while specialized aesthetic cropping models localize crops effectively but are limited to refinement; neither provides actionable pose guidance. To support model development, we further construct CaptureGuide-Dataset, comprising 130K samples with textual rationales and structured visual annotations, and develop ShutterMuse, a unified MLLM trained with supervised and reinforcement fine-tuning. Experiments on CaptureGuide-Bench show that ShutterMuse achieves the best overall photographer-side performance among evaluated baselines and competitive subject-side pose recommendation with substantially lower inference cost, demonstrating the potential of MLLMs as interactive assistants for photography during image capture.", "upvotes": 37, "discussionId": "6a3cb91cf3facdb67e9ff248", "projectPage": "https://lijayutnt.github.io/ShutterMuse/", "githubRepo": "https://github.com/lijayuTnT/ShutterMuse", "githubRepoAddedBy": "user", "ai_summary": "Researchers developed a new benchmark and dataset for photography assistance, along with a unified multimodal model that provides both composition guidance and pose recommendations during image capture.", "ai_keywords": ["multimodal large language models", "aesthetic cropping", "visual annotations", "supervised fine-tuning", "reinforcement fine-tuning", "photographer-side composition", "subject-side pose recommendation"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 35, "organization": {"_id": "66e43eae9d477f566f937935", "name": "stepfun-ai", "fullname": "StepFun", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/644f7e6233ac8f46fa0b9e26/CmF2ocXhkr2UtHXgmwq7-.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u5b9e\u6444\u5f71\u9700\u8981\u5728\u62cd\u6444\u65f6\u5bf9\u76f8\u673a\u6784\u56fe\u548c\u4e3b\u4f53\u59ff\u52bf\u63d0\u4f9b\u6307\u5bfc\u3002</li>\n    <li>\u73b0\u6709\u7684\u7f8e\u5b66\u88c1\u526a\u57fa\u51c6\u4e3b\u8981\u8bc4\u4f30\u4e8b\u540e\u88c1\u526a\u9884\u6d4b\uff0c\u5ffd\u89c6\u4e86\u62cd\u6444\u65f6\u7684\u6307\u5bfc\u80fd\u529b\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86CaptureGuide-Bench\u57fa\u51c6\uff0c\u5305\u542b\u6444\u5f71\u5e08\u4fa7\u7684\u6784\u56fe\u51b3\u7b56\u548c\u4e3b\u4f53\u4fa7\u7684\u59ff\u52bf\u63a8\u8350\u4e24\u4e2a\u4efb\u52a1\u3002</li>\n    <li>\u8bc4\u4f30\u53d1\u73b0\uff0c\u901a\u7528\u5927\u578b\u8bed\u8a00\u6a21\u578b\u5728\u6784\u56fe\u51b3\u7b56\u4e0a\u8868\u73b0\u826f\u597d\uff0c\u4f46\u7cbe\u786e\u5b9a\u4f4d\u65b9\u9762\u5b58\u5728\u4e0d\u8db3\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u6784\u5efa\u4e86CaptureGuide-Dataset\uff0c\u5e76\u5f00\u53d1\u4e86ShutterMuse\uff0c\u8868\u73b0\u51fa\u8272\uff0c\u663e\u793a\u4e86\u5927\u578b\u8bed\u8a00\u6a21\u578b\u5728\u6444\u5f71\u4e2d\u7684\u6f5c\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Real-world photography needs guidance on camera framing and how subjects should pose during capture.</li>\n  <li>Current benchmarks mostly focus on post-capture cropping, missing out on helping with real-time decisions.</li>\n  <li>We created CaptureGuide-Bench, which includes tasks for both composition decisions and pose recommendations.</li>\n  <li>Our findings show that while general-purpose models can make composition choices, they struggle with precise adjustments and pose guidance.</li>\n  <li>We also built CaptureGuide-Dataset with 130,000 samples and developed ShutterMuse, a model that performs well in photography assistance.</li>\n</ul>"}, "publishedAt": "2026-06-23T20:00:00.000Z", "title": "ShutterMuse: Capture-Time Photography Guidance with MLLMs", "summary": "Real-world photography requires capture-time guidance for both camera framing and subject pose. Yet existing aesthetic cropping benchmarks mainly evaluate post-hoc crop prediction and overlook subject-side recommendations, leaving the capture-time guidance capabilities of multimodal large language models (MLLMs) underexplored. To address this gap, we introduce CaptureGuide-Bench, a benchmark with two complementary tasks: photographer-side composition decision and refinement, and subject-side scene-conditioned pose recommendation. Our evaluation reveals limitations: general-purpose MLLMs can make composition decisions but lack precise refinement localization, while specialized aesthetic cropping models localize crops effectively but are limited to refinement; neither provides actionable pose guidance. To support model development, we further construct CaptureGuide-Dataset, comprising 130K samples with textual rationales and structured visual annotations, and develop ShutterMuse, a unified MLLM trained with supervised and reinforcement fine-tuning. Experiments on CaptureGuide-Bench show that ShutterMuse achieves the best overall photographer-side performance among evaluated baselines and competitive subject-side pose recommendation with substantially lower inference cost, demonstrating the potential of MLLMs as interactive assistants for photography during image capture.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/647469b9a51711a3b58bda2b/H971Df6p2IGq8gXpvjuJG.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.25763.png", "numComments": 1, "submittedBy": {"_id": "647469b9a51711a3b58bda2b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/647469b9a51711a3b58bda2b/yeDf8Sa8IDEQyney1dGC9.jpeg", "fullname": "Yixiao Fang", "name": "fangyixiao", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "66e43eae9d477f566f937935", "name": "stepfun-ai", "fullname": "StepFun", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/644f7e6233ac8f46fa0b9e26/CmF2ocXhkr2UtHXgmwq7-.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.27313", "authors": [{"_id": "6a3de2d23b43e283349ec181", "name": "Xumin Yu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec182", "name": "Zuyan Liu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec183", "name": "Zhenyu Yang", "hidden": false}, {"_id": "6a3de2d23b43e283349ec184", "name": "Yuhao Dong", "hidden": false}, {"_id": "6a3de2d23b43e283349ec185", "name": "Shengsheng Qian", "hidden": false}, {"_id": "6a3de2d23b43e283349ec186", "name": "Jiwen Lu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec187", "name": "Han Hu", "hidden": false}, {"_id": "6a3de2d23b43e283349ec188", "name": "Yongming Rao", "hidden": false}], "publishedAt": "2026-06-25T00:00:00.000Z", "submittedOnDailyAt": "2026-06-26T00:00:00.000Z", "title": "ViQ: Text-Aligned Visual Quantized Representations at Any Resolution", "submittedOnDailyBy": {"_id": "64f001bfabd9fb1914398bd5", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64f001bfabd9fb1914398bd5/9teH82hkBI4csIz_WQh5q.jpeg", "isPro": false, "fullname": "liuzuyan", "user": "Zuyan", "type": "user", "name": "Zuyan"}, "summary": "A unified representation for text and vision is a natural pursuit, as it enables simpler multimodal modeling and more efficient training. However, representing images as discrete signals in the same way as text inevitably introduces severe information loss. Existing work struggles to balance low-level details and high-level semantics in discrete representations: reconstruction-oriented representations often lack semantic information, whereas semantically stronger features typically suffer from severe loss of detail. We present ViQ, a Visual Quantized Representations framework, which is designed to balance semantics and details in discrete representations while supporting inputs at native resolutions, thereby enabling it to serve as a unified and general discrete representation for arbitrary visual inputs. Our approach structures quantization learning into two stages: text-aligned pre-training and feature discretization. With text-aligned pre-training, we enhance the visual encoder semantic-rich supervision from the pretrained language model and enable it to process native-resolution visual inputs. During discretization, we propose a proximal representation learning strategy to progressively compact the feature space, along with a position-aware head-wise quantization mechanism that enables flexible processing of arbitrary resolutions. Extensive experiments on multimodal tasks demonstrate that ViQ achieves competitive performance compared to state-of-the-art multimodal vision encoders with continuous and high-dimensional visual features, while maintaining high precision in low-level reconstruction. We also show that multimodal training with visual quantized representations largely improves efficiency, yielding up to 20\\%-70\\% acceleration with different base LLMs and training recipes.", "upvotes": 36, "discussionId": "6a3de2d33b43e283349ec189", "githubRepo": "https://github.com/yuxumin/ViQ", "githubRepoAddedBy": "user", "ai_summary": "ViQ presents a visual quantization framework that balances semantic richness and detail preservation in discrete representations, enabling efficient multimodal training with native-resolution inputs.", "ai_keywords": ["visual quantized representations", "text-aligned pre-training", "feature discretization", "proximal representation learning", "position-aware head-wise quantization", "multimodal modeling", "visual encoder", "discrete representations", "semantic richness", "low-level reconstruction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 36, "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86ViQ\u6846\u67b6\uff0c\u65e8\u5728\u5e73\u8861\u79bb\u6563\u8868\u793a\u4e2d\u7684\u8bed\u4e49\u548c\u7ec6\u8282\uff0c\u540c\u65f6\u652f\u6301\u539f\u59cb\u5206\u8fa8\u7387\u7684\u8f93\u5165\u3002</li>\n    <li>\u8be5\u6846\u67b6\u901a\u8fc7\u6587\u672c\u5bf9\u9f50\u7684\u9884\u8bad\u7ec3\u548c\u7279\u5f81\u79bb\u6563\u5316\u4e24\u4e2a\u9636\u6bb5\u6765\u7ed3\u6784\u5316\u91cf\u5316\u5b66\u4e60\u3002</li>\n    <li>\u5728\u6587\u672c\u5bf9\u9f50\u7684\u9884\u8bad\u7ec3\u4e2d\uff0c\u589e\u5f3a\u4e86\u89c6\u89c9\u7f16\u7801\u5668\u7684\u8bed\u4e49\u4e30\u5bcc\u6027\uff0c\u4f7f\u5176\u80fd\u591f\u5904\u7406\u539f\u59cb\u5206\u8fa8\u7387\u7684\u89c6\u89c9\u8f93\u5165\u3002</li>\n    <li>\u79bb\u6563\u5316\u9636\u6bb5\u4f7f\u7528\u4e86\u4e00\u79cd\u6e10\u8fdb\u5f0f\u7279\u5f81\u7a7a\u95f4\u538b\u7f29\u7684\u7b56\u7565\uff0c\u5e76\u5f15\u5165\u4e86\u4f4d\u7f6e\u611f\u77e5\u7684\u91cf\u5316\u673a\u5236\uff0c\u4ee5\u7075\u6d3b\u5904\u7406\u4e0d\u540c\u5206\u8fa8\u7387\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cViQ\u5728\u591a\u6a21\u6001\u4efb\u52a1\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u8bad\u7ec3\u6548\u7387\u63d0\u5347\u53ef\u8fbe20%-70%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>ViQ is a new framework that connects text and images effectively for better training and modeling.</li>\n    <li>It aims to maintain a balance between detailed image information and meaningful semantic content.</li>\n    <li>The framework uses a two-step process: first, it aligns visual data with text for better understanding, then it compresses the image features carefully.</li>\n    <li>ViQ allows for processing images at their original quality and shows strong performance in various tasks compared to other models.</li>\n    <li>It also significantly speeds up training, improving efficiency by 20% to 70% with different language models and methods.</li>\n</ul>"}, "publishedAt": "2026-06-24T20:00:00.000Z", "title": "ViQ: Text-Aligned Visual Quantized Representations at Any Resolution", "summary": "A unified representation for text and vision is a natural pursuit, as it enables simpler multimodal modeling and more efficient training. However, representing images as discrete signals in the same way as text inevitably introduces severe information loss. Existing work struggles to balance low-level details and high-level semantics in discrete representations: reconstruction-oriented representations often lack semantic information, whereas semantically stronger features typically suffer from severe loss of detail. We present ViQ, a Visual Quantized Representations framework, which is designed to balance semantics and details in discrete representations while supporting inputs at native resolutions, thereby enabling it to serve as a unified and general discrete representation for arbitrary visual inputs. Our approach structures quantization learning into two stages: text-aligned pre-training and feature discretization. With text-aligned pre-training, we enhance the visual encoder semantic-rich supervision from the pretrained language model and enable it to process native-resolution visual inputs. During discretization, we propose a proximal representation learning strategy to progressively compact the feature space, along with a position-aware head-wise quantization mechanism that enables flexible processing of arbitrary resolutions. Extensive experiments on multimodal tasks demonstrate that ViQ achieves competitive performance compared to state-of-the-art multimodal vision encoders with continuous and high-dimensional visual features, while maintaining high precision in low-level reconstruction. We also show that multimodal training with visual quantized representations largely improves efficiency, yielding up to 20\\%-70\\% acceleration with different base LLMs and training recipes.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.27313.png", "numComments": 1, "submittedBy": {"_id": "64f001bfabd9fb1914398bd5", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64f001bfabd9fb1914398bd5/9teH82hkBI4csIz_WQh5q.jpeg", "fullname": "liuzuyan", "name": "Zuyan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "isAuthorParticipating": false}],
    "month": [{"paper": {"id": "2606.09967", "authors": [{"_id": "6a28c3c5e7d78ea7587e52bd", "name": "Ming Qian", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52be", "name": "Tianjian Ouyang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52bf", "name": "Mingchao Sun", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c0", "name": "Zijian Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c1", "name": "Jincheng Xiong", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c2", "name": "Jiarong Han", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c3", "name": "Yongchang Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c4", "name": "Jiawei Zhang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c5", "name": "Xu Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c6", "name": "Yu Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c7", "name": "Luyang Tang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c8", "name": "Fei Yu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52c9", "name": "Zengye Ge", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ca", "name": "Mengmeng Du", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cb", "name": "Yuan Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cc", "name": "Nianfei Fan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cd", "name": "Song Wang", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52ce", "name": "Yingliang Peng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52cf", "name": "Chunxue Jia", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d0", "name": "Yang Liu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d1", "name": "Shiying Zeng", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d2", "name": "Haozhe Shi", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d3", "name": "Junnan Lai", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d4", "name": "Hongyu Pan", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d5", "name": "Zheng Wu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d6", "name": "Ning Guo", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d7", "name": "Mu Xu", "hidden": false}, {"_id": "6a28c3c5e7d78ea7587e52d8", "name": "Hang Zhang", "hidden": false}], "publishedAt": "2026-06-08T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "submittedOnDailyBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "isPro": false, "fullname": "qian#143", "user": "qian43", "type": "user", "name": "qian43"}, "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "upvotes": 194, "discussionId": "6a28c3c5e7d78ea7587e52d9", "projectPage": "https://abot-earth.amap.com/", "githubRepo": "https://github.com/amap-cvlab/ABot-Earth-0.5", "githubRepoAddedBy": "user", "ai_summary": "ABot-Earth 0.5 generates realistic 3D environments from satellite imagery using 3D Gaussian Splatting representation, enabling fast synthesis and real-time visualization for Embodied AI applications.", "ai_keywords": ["3D Gaussian Splatting", "generative model", "satellite imagery", "3D environment synthesis", "level-of-detail", "real-time visualization", "Embodied AI", "UAV navigation", "digital earth visualization"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 109, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "summary_zh": "<ul>\n    <li>ABot-Earth 0.5 \u662f\u4e00\u4e2a\u751f\u6210\u6027 3D \u6846\u67b6\uff0c\u53ef\u4ee5\u4ece\u536b\u661f\u56fe\u50cf\u5408\u6210\u5927\u89c4\u6a21\u65e0\u7f1d\u7684 3D \u73af\u5883\u3002</li>\n    <li>\u8be5\u6a21\u578b\u4f7f\u7528 3D \u9ad8\u65af\u6563\u5c04 (3DGS) \u8868\u793a\u6cd5\uff0c\u7ecf\u8fc7\u8bad\u7ec3\u540e\u80fd\u591f\u751f\u6210\u771f\u5b9e\u7684\u51e0\u4f55\u5f62\u72b6\u548c\u7eb9\u7406\u3002</li>\n    <li>\u5408\u6210\u65b0 3D \u573a\u666f\u7684\u901f\u5ea6\u5f88\u5feb\uff0c\u6bcf\u5e73\u65b9\u516c\u91cc\u8017\u65f6\u4e0d\u5230 10 \u5206\u949f\uff0c\u4e14\u5177\u6709\u975e\u5e38\u9ad8\u7684\u771f\u5b9e\u611f\u3002</li>\n    <li>\u6846\u67b6\u8bbe\u8ba1\u4fbf\u4e8e\u4f7f\u7528\uff0c\u652f\u6301\u5b9e\u65f6\u4ea4\u4e92\u53ef\u89c6\u5316\uff0c\u9002\u7528\u4e8e\u57fa\u4e8e\u7f51\u7edc\u7684\u5730\u56fe\u5f15\u64ce\u3002</li>\n    <li>ABot-Earth 0.5 \u964d\u4f4e\u4e86\u5927\u89c4\u6a21 3D \u91cd\u5efa\u7684\u6280\u672f\u548c\u8d22\u52a1\u969c\u788d\uff0c\u6709\u52a9\u4e8e\u63a8\u52a8\u5168\u7403\u6570\u5b57\u5730\u7403\u53ef\u89c6\u5316\u7684\u53d1\u5c55\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>ABot-Earth 0.5 is a tool that creates detailed 3D environments using satellite images.</li>\n    <li>It uses a special model that learns from existing urban 3D designs to generate realistic structures and textures.</li>\n    <li>The system can create new 3D scenes in under 10 minutes for each square kilometer of area.</li>\n    <li>It allows for real-time, interactive viewing on web maps and helps in applications like drone navigation.</li>\n    <li>ABot-Earth 0.5 makes 3D reconstruction easier and cheaper, promoting better global digital earth visualization.</li>\n</ul>"}, "publishedAt": "2026-06-07T20:00:00.000Z", "title": "ABot-Earth 0.5: Generative 3D Earth Model", "summary": "We present ABot-Earth 0.5, a generative 3D framework designed to synthesize vast, seamless 3D environments from ubiquitous, geospatially referenced satellite imagery. To achieve this, we propose a novel generative model formulated directly with the 3D Gaussian Splatting (3DGS) representation. The model is trained on a diverse corpus of existing real-world urban reconstructions, learning to generate realistic geometry and textures. At inference, it synthesizes novel 3D scenes conditioned solely on satellite imagery at a scalable rate of under 10 minutes per square kilometer, while demonstrating exceptional realism. The framework is designed for accessibility, with integrated hierarchical level-of-detail (LOD) structures that permit real-time, interactive visualization on web-based map engines. This high-fidelity simulation sandbox effectively mitigates the sim-to-real domain gap, enabling critical downstream Embodied AI applications like closed-loop UAV navigation. By providing an ultra-low-cost and high-efficiency solution, ABot-Earth 0.5 significantly lowers the technical and financial barriers to large-scale 3D reconstruction and empowers the future of global digital earth visualization.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.09967.png", "numComments": 3, "submittedBy": {"_id": "6433bc32a4c9c55871a42812", "avatarUrl": "/avatars/c27c063d02419b8ba32657514c07e3b2.svg", "fullname": "qian#143", "name": "qian43", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 6, "isUserFollowing": false}, "organization": {"_id": "641415d08900ef6afa2fcb73", "name": "acvlab", "fullname": "Alibaba AMAP CV Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6414106ce7d5f817d204e160/dfveRtrRy8Xn7QpG684zl.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.10651", "authors": [{"_id": "6a28cfb8e7d78ea7587e5406", "name": "Kwai Keye Team", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5407", "name": "Bin Wen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5408", "name": "Changyi Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5409", "name": "Chengru Song", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540a", "name": "Chongling Rao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540b", "name": "Guowang Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540c", "name": "Han Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540d", "name": "Haonan Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540e", "name": "Hengrui Ju", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e540f", "name": "Jiankang Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5410", "name": "Jiapeng Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5411", "name": "Jiawei Yuan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5412", "name": "Kaixuan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5413", "name": "Kaiyu Jiang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5414", "name": "Kun Gai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5415", "name": "Lingzhi Zhou", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5416", "name": "Na Nie", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5417", "name": "Sen Na", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5418", "name": "Tianke Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5419", "name": "Tingting Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541a", "name": "Xuanyu Zheng", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541b", "name": "Yulong Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541c", "name": "Fan Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541d", "name": "Haixuan Gao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541e", "name": "Lele Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e541f", "name": "Mingqiao Liu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5420", "name": "Muxi Diao", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5421", "name": "Qi Zhang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5422", "name": "Qile Su", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5423", "name": "Wei Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5424", "name": "Wentao Hong", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5425", "name": "Xingyu Lu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5426", "name": "Yancheng Long", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5427", "name": "Yankai Yang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5428", "name": "Yingxin Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5429", "name": "Yiyang Fan", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542a", "name": "Yu Xia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542b", "name": "Yuzhe Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542c", "name": "Ziliang Lai", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542d", "name": "Chuan Yi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542e", "name": "Haonan Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e542f", "name": "Tianming Liang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5430", "name": "Weixin Xu", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5431", "name": "Xiaoxiao Ma", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5432", "name": "Yang Tian", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5433", "name": "Yufei Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5434", "name": "Feng Han", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5435", "name": "Hang Li", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5436", "name": "Jing Wang", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5437", "name": "Jinghui Jia", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5438", "name": "Junmin Chen", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e5439", "name": "Junyu Shi", "hidden": false}, {"_id": "6a28cfb8e7d78ea7587e543a", "name": "Ruilin Zhang", "hidden": false}], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-10T00:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "submittedOnDailyBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "isPro": false, "fullname": "Tianming Liang", "user": "liangtm", "type": "user", "name": "liangtm"}, "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "upvotes": 167, "discussionId": "6a28cfb8e7d78ea7587e543b", "projectPage": "https://kwai-keye.github.io/", "githubRepo": "https://github.com/Kwai-Keye/Keye", "githubRepoAddedBy": "user", "ai_summary": "Kwai Keye-VL-2.0-30B-A3B is an open-source Mixture-of-Experts multimodal foundation model that enables long-video understanding and agentic intelligence through DeepSeek Sparse Attention and specialized training infrastructure.", "ai_keywords": ["Mixture-of-Experts", "multimodal foundation model", "DeepSeek Sparse Attention", "GQA-based architectures", "256K context processing", "heterogeneous ViT-LM parallelism", "custom DSA kernels", "Cross-Modal Multi-Teacher On-Policy Distillation", "Context-RL", "Video-RL", "dense token-level teacher feedback", "on-policy rollouts", "agent collaboration", "Code", "Tool", "Search scenarios", "multimodal self-correction"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 785, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "summary_zh": "<ul>\n    <li>\u63a8\u51fa\u4e86Kwai Keye-VL-2.0-30B-A3B\uff0c\u8fd9\u662f\u4e00\u4e2a\u5f00\u6e90\u7684\u6df7\u5408\u4e13\u5bb6\u591a\u6a21\u6001\u57fa\u7840\u6a21\u578b\uff0c\u65e8\u5728\u63d0\u5347\u5bf9\u957f\u89c6\u9891\u7684\u7406\u89e3\u548c\u667a\u80fd\u4ee3\u7406\u80fd\u529b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u91c7\u7528\u4e86DeepSeek\u7a00\u758f\u6ce8\u610f\u529b\uff08DSA\uff09\uff0c\u53ef\u4ee5\u5904\u7406256K\u7684\u957f\u4e0a\u4e0b\u6587\uff0c\u89e3\u51b3\u4e86\u8d85\u957f\u89c6\u9891\u4e2d\u7684\u4fe1\u606f\u5197\u4f59\u548c\u8ba1\u7b97\u6210\u672c\u95ee\u9898\u3002</li>\n    <li>\u5f15\u5165\u4e86\u8de8\u6a21\u6001\u591a\u6559\u5e08\u5728\u7ebf\u84b8\u998f\uff08MOPD\uff09\u548c\u4e0a\u4e0b\u6587\u5f3a\u5316\u5b66\u4e60\uff0c\u4ee5\u89e3\u51b3\u591a\u4efb\u52a1\u5bf9\u9f50\u4e2d\u7684\u707e\u96be\u6027\u9057\u5fd8\u95ee\u9898\u3002</li>\n    <li>\u5728\u89c6\u9891\u7406\u89e3\u3001\u65f6\u95f4\u5b9a\u4f4d\u3001\u63a8\u7406\u4ee5\u53ca\u667a\u80fd\u4ee3\u7406\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cKeye-VL-2.0-30B-A3B\u5728\u540c\u89c4\u6a21\u6a21\u578b\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u7279\u522b\u662f\u5728\u7cbe\u786e\u65f6\u95f4\u5b9a\u4f4d\u548c\u957f\u89c6\u9891\u7406\u89e3\u65b9\u9762\u3002</li>\n    <li>\u6211\u4eec\u53d1\u5e03\u4e86\u6a21\u578b\u68c0\u67e5\u70b9\uff0c\u4ee5\u4fc3\u8fdb\u793e\u533a\u5728\u53ef\u6269\u5c55\u548c\u5f3a\u5927\u7684\u591a\u6a21\u6001\u667a\u80fd\u5e94\u7528\u65b9\u9762\u7684\u8fdb\u5c55\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Kwai Keye-VL-2.0-30B-A3B is an open-source model designed for understanding long videos and improving intelligent agents.</li>\n    <li>It uses a new attention method called DeepSeek Sparse Attention to handle very long video contexts efficiently.</li>\n    <li>The model has a strong training system that boosts performance while reducing computing costs.</li>\n    <li>To prevent losing information when learning multiple tasks, it uses a new technique called Cross-Modal Multi-Teacher On-Policy Distillation.</li>\n    <li>Keye-VL-2.0-30B-A3B has been shown to perform better than similar models in video understanding and reasoning tasks, and its model checkpoints are available for community use.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Kwai Keye-VL-2.0 Technical Report", "summary": "We introduce Kwai Keye-VL-2.0-30B-A3B, an open-source Mixture-of-Experts (MoE) multimodal foundation model designed to advance long-video understanding and agentic intelligence. To address the challenges of ultra-long contexts, information redundancy, and prohibitive computational costs inherent in hour-level videos, Keye-VL-2.0 is the first to adapt DeepSeek Sparse Attention (DSA) to GQA-based multimodal architectures, enabling lossless 256K context processing while capturing critical frames and long-range temporal dependencies. This architecture is underpinned by a highly optimized training and inference infrastructure, including scalable video I/O, heterogeneous ViT-LM parallelism, and custom DSA kernels that significantly maximize throughput and minimize computational overhead. Furthermore, to overcome the algorithmic dilemma of catastrophic forgetting during multi-task alignment, we introduce Cross-Modal Multi-Teacher On-Policy Distillation (MOPD) paired with Context-RL and Video-RL. By distilling dense token-level teacher feedback from on-policy rollouts back into the MoE backbone, which activates only 3B parameters, Keye-VL-2.0 natively empowers advanced agent collaboration across Code, Tool, and Search scenarios with multimodal self-correction. Extensive evaluations across video understanding, temporal grounding, reasoning, STEM, and agent benchmarks demonstrate that Keye-VL-2.0-30B-A3B achieves state-of-the-art performance among models of similar scale, particularly excelling in fine-grained temporal localization on TimeLens and long-video comprehension on Video-MME-v2 and LongVideoBench. We release our model checkpoints to accelerate community progress toward scalable and robust multimodal agentic applications.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.10651.png", "numComments": 1, "submittedBy": {"_id": "66c98c27fafc0fc87c280749", "avatarUrl": "/avatars/c71db3bee0fcd9aabcc38fd871d1cb75.svg", "fullname": "Tianming Liang", "name": "liangtm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "685d2e9b7aa0388f4fcaf7b2", "name": "KwaiKeye", "fullname": "Kwai Keye", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/685ba798484e3233f5ff6f11/gW0pROtvsWctypxYTBbWZ.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.14777", "authors": [{"_id": "6a30c3bfa0d4daae4285fefd", "name": "Dingyu Yao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285fefe", "name": "Junhao Zhou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285feff", "user": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "name": "Chenxu Yang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T16:15:00.215Z", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff00", "name": "Chuanyu Qin", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff01", "name": "Haowen Hou", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff02", "name": "Zheming Liang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff03", "name": "Congcong Wang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff04", "name": "Yuhang Cao", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff05", "name": "Shenglong Ye", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff06", "name": "Shuai Xie", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff07", "name": "Shuhuan Gu", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff08", "name": "Haoyang Huang", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff09", "name": "Qingyi Si", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0a", "name": "Nan Duan", "hidden": false}, {"_id": "6a30c3bfa0d4daae4285ff0b", "user": {"_id": "64b4eec4faa3181a5eab9c46", "avatarUrl": "/avatars/bcc9bf5cbf67546ad2b4c9ec8b96ac96.svg", "isPro": true, "fullname": "Jiaqi Wang", "user": "myownskyW7", "type": "user", "name": "myownskyW7"}, "name": "Jiaqi Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-16T12:05:58.790Z", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "publishedAt": "2026-06-10T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "submittedOnDailyBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "isPro": false, "fullname": "steven young", "user": "iieycx", "type": "user", "name": "iieycx"}, "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "upvotes": 157, "discussionId": "6a30c3bfa0d4daae4285ff0c", "projectPage": "https://joyai-vl-video-future-academy-jd.github.io/JoyAI-VL-Interaction/", "githubRepo": "https://github.com/jd-opensource/JoyAI-VL-Interaction", "githubRepoAddedBy": "user", "ai_summary": "A vision-language model operates continuously in real-time, making autonomous decisions about when to respond or delegate, enabling interactive systems that perceive and act upon environmental changes without user prompting.", "ai_keywords": ["vision-language model", "real-time interaction", "autonomous decision-making", "vision-triggered responsiveness", "time awareness", "background model", "deployable system", "video streaming", "interactive AI", "continuous perception"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 209, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "summary_zh": "<ul>\n    <li>\u73b0\u5b9e\u4e16\u754c\u4e2d\u7684\u8bb8\u591a\u65f6\u523b\u65e0\u9700\u7528\u6237\u53d1\u95ee\uff0c\u6bd4\u5982\u76d1\u63a7\u5668\u4e0a\u7684\u706b\u707e\u6216\u89c6\u9891\u901a\u8bdd\u4e2d\u7684\u8868\u60c5\u3002</li>\n    <li>\u76ee\u524d\u7684\u5927\u578b\u6a21\u578b\u5927\u591a\u662f\u57fa\u4e8e\u63d0\u95ee\u7684\u8bbe\u8ba1\uff0c\u53ea\u6709\u5728\u88ab\u8be2\u95ee\u65f6\u624d\u4f1a\u56de\u5e94\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u6a21\u578b\uff0c\u80fd\u591f\u50cf\u4eba\u4e00\u6837\u5b9e\u65f6\u89c2\u5bdf\uff0c\u5e76\u81ea\u4e3b\u51b3\u5b9a\u4f55\u65f6\u53d1\u8a00\u6216\u4fdd\u6301\u6c89\u9ed8\u3002</li>\n    <li>\u6211\u4eec\u53d1\u5e03\u4e86JoyAI-VL-Interaction\u6a21\u578b\uff0c\u5177\u5907\u5b9e\u65f6\u54cd\u5e94\u80fd\u529b\u548c\u65f6\u95f4\u610f\u8bc6\uff0c\u5e76\u4e14\u80fd\u591f\u5904\u7406\u590d\u6742\u95ee\u9898\u3002</li>\n    <li>\u8be5\u7cfb\u7edf\u80fd\u591f\u5b9e\u65f6\u6d41\u5f0f\u4f20\u8f93\u89c6\u9891\uff0c\u652f\u6301\u591a\u79cd\u63d2\u4ef6\u7ec4\u4ef6\uff0c\u7528\u6237\u8bc4\u4ef7\u4f18\u4e8e\u73b0\u6709\u7684\u89c6\u9891\u901a\u8bdd\u52a9\u624b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current AI models respond only when asked, missing real-time opportunities to interact.</li>\n    <li>The new JoyAI-VL-Interaction model acts like a person, watching and deciding when to respond or stay silent.</li>\n    <li>This model can handle tasks like guiding shoppers or creating lectures spontaneously.</li>\n    <li>It comes with a complete system that streams video, making it truly present in real-world situations.</li>\n    <li>JoyAI-VL-Interaction is preferred by users over existing video-call assistants in various scenarios.</li>\n</ul>"}, "publishedAt": "2026-06-09T20:00:00.000Z", "title": "JoyAI-VL-Interaction: Real-Time Vision-Language Interaction Intelligence", "summary": "Many moments in the real world do not wait for a user to ask. A fire starts on a security monitor, an expression flickers across a video call, or a product a viewer wants flashes by in a livestream. Yet today's large models remain mostly turn-based by design: they answer only when addressed, and even video-call apps that appear interactive still operate as question-answer systems, reacting only when polled or prompted. We argue for a different paradigm: a model that is present in the world like a person. It continuously watches what is happening now, decides on its own whether to speak or stay silent, interacts in real time, and delegates to a background model when the problem is hard. To advance interaction models and their adoption across domains, we make two fully open-sourced contributions. First, we release JoyAI-VL-Interaction, an 8B-scale, vision-first VL-interaction model. The model makes the response decision internally, choosing each second to stay silent, respond, or delegate to a background model, and it excels at vision-triggered responsiveness and time awareness. We pair it with a transferable training recipe, from which capabilities we never trained for emerge, such as guiding a shopper through changing app screens or improvising a lecture from a slide deck. Second, we release a complete, deployable system built around that model. The system streams any ongoing video into the model, making it genuinely present in the world. All other components are pluggable, including ASR/TTS modules, memory, visualization UI, and a background brain that can connect to any API or agent. Across six real-world scenarios, human raters prefer JoyAI-VL-Interaction over the in-app video-call assistants of Doubao and Gemini by a wide margin. To our knowledge, this is the first open, vision-driven interaction model released together with its training recipe, data, and complete deployable system.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/rPwOTrTL9yUkRzOgUfNoM.mp4", "https://cdn-uploads.huggingface.co/production/uploads/66f4d2b62dc07e76a1dc464b/BunI2wEEfCDQcodB7q3uq.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.14777.png", "numComments": 2, "submittedBy": {"_id": "66f4d2b62dc07e76a1dc464b", "avatarUrl": "/avatars/b1884b750a6ec46a83d247e933d59d63.svg", "fullname": "steven young", "name": "iieycx", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "68cb7c874f4a1865540c455c", "name": "jdopensource", "fullname": "JD.com Open Source", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68c0e2ab44ea28a974e3074b/g-4gTubd16qUtwmGZ0n4h.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.18023", "authors": [{"_id": "6a3201f3bc818ff14e453d61", "name": "Jian Yang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d62", "name": "Shawn Guo", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d63", "name": "Wei Zhang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d64", "user": {"_id": "64ab99dcb76bfd863eba64c1", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ab99dcb76bfd863eba64c1/UBXwDPx17X-gl-SzBPvrc.jpeg", "isPro": false, "fullname": "TY.Zheng", "user": "aaabiao", "type": "user", "name": "aaabiao"}, "name": "Tianyu Zheng", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:10.407Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d65", "name": "Yaxin Du", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d66", "name": "Haau-Sing Li", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d67", "user": {"_id": "66a8e2538407031e388c501f", "avatarUrl": "/avatars/d16d51f7b1e111efd6d0985995b614be.svg", "isPro": false, "fullname": "wjj", "user": "wuyuverse", "type": "user", "name": "wuyuverse"}, "name": "Jiajun Wu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-17T11:21:12.507Z", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d68", "name": "Yue Song", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d69", "name": "Yan Xing", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6a", "name": "Qingsong Cai", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6b", "name": "Zelong Huang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6c", "name": "Chuan Hao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6d", "name": "Ran Tao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6e", "name": "Xianglong Liu", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d6f", "name": "Wayne Xin Zhao", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d70", "name": "Mingjie Tang", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d71", "name": "Weifeng Lv", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d72", "name": "Ming Zhou", "hidden": false}, {"_id": "6a3201f3bc818ff14e453d73", "name": "Bryan Dai", "hidden": false}], "publishedAt": "2026-06-16T00:00:00.000Z", "submittedOnDailyAt": "2026-06-17T00:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "upvotes": 113, "discussionId": "6a3201f3bc818ff14e453d74", "ai_summary": "Parallel loop Transformers achieve better code generation performance with two loops due to refined representations, while additional loops cause diminishing returns and increased positional mismatch costs.", "ai_keywords": ["Looped Transformers", "parallel loop Transformers", "cross-loop position offsets", "shared-KV gated sliding-window attention", "loop-count selection", "LoopCoder-v2", "instruction tuning", "SWE-bench", "Multi-SWE"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "summary_zh": "<ul>\n    <li>\u5faa\u73af\u53d8\u6362\u5668\u901a\u8fc7\u91cd\u590d\u5e94\u7528\u5171\u4eab\u6a21\u5757\u6765\u63d0\u5347\u6f5c\u5728\u8ba1\u7b97\u80fd\u529b\uff0c\u4f46\u589e\u52a0\u5faa\u73af\u6b21\u6570\u4f1a\u589e\u52a0\u5ef6\u8fdf\u548c\u5185\u5b58\u6d88\u8017\u3002</li>\n    <li>\u5e76\u884c\u5faa\u73af\u53d8\u6362\u5668\uff08PLT\uff09\u4f7f\u7528\u4ea4\u53c9\u5faa\u73af\u4f4d\u7f6e\u504f\u79fb\u548c\u5171\u4eabKV\u95e8\u63a7\u6ed1\u52a8\u7a97\u53e3\u6ce8\u610f\u529b\u6765\u51cf\u8f7b\u8fd9\u4e9b\u6210\u672c\u3002</li>\n    <li>\u6211\u4eec\u7814\u7a76\u4e86PLT\u7684\u5faa\u73af\u8ba1\u6570\u9009\u62e9\uff0c\u53d1\u73b0\u989d\u5916\u7684\u5faa\u73af\u53ef\u4ee5\u63d0\u5347\u8868\u793a\u80fd\u529b\uff0c\u4f46\u4e5f\u4f1a\u5f15\u5165\u4f4d\u7f6e\u4e0d\u5339\u914d\u3002</li>\n    <li>\u901a\u8fc7\u8bad\u7ec3\u4e0d\u540c\u5faa\u73af\u8ba1\u6570\u7684LoopCoder-v2\uff0c\u53d1\u73b0\u4e24\u6b21\u5faa\u73af\u7684\u6548\u679c\u663e\u8457\u4f18\u4e8e\u4e0d\u5faa\u73af\u7684\u57fa\u7ebf\u3002</li>\n    <li>\u8d85\u8fc7\u4e24\u4e2a\u5faa\u73af\u4f1a\u5bfc\u81f4\u6548\u679c\u4e0b\u964d\uff0c\u8bf4\u660e\u5faa\u73af\u8ba1\u6570\u7684\u5f71\u54cd\u662f\u975e\u5355\u8c03\u7684\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Looped Transformers improve processing by using repeated blocks, but too many loops can slow things down and require more memory.</li>\n    <li>Parallel loop Transformers (PLT) help reduce these costs using techniques like cross-loop position offsets and shared attention mechanisms.</li>\n    <li>We studied how many loops to use in PLT by balancing the benefits of additional loops against the downsides of position mismatches.</li>\n    <li>Training a model called LoopCoder-v2 showed that using two loops significantly improved performance in various coding tasks, but using three or more loops led to worse results.</li>\n    <li>The findings suggest that two loops provide the best balance of refinement and efficiency, while more loops can create problems that outweigh their benefits.</li>\n</ul>"}, "publishedAt": "2026-06-15T20:00:00.000Z", "title": "LoopCoder-v2: Only Loop Once for Efficient Test-Time Computation Scaling", "summary": "Looped Transformers scale latent computation by repeatedly applying shared blocks, but sequential looping increases latency and KV-cache memory with the loop count. Parallel loop Transformers (PLT) alleviate this cost through cross-loop position offsets (CLP) and shared-KV gated sliding-window attention, making loop count a practical design choice. We therefore study PLT loop-count selection through a gain--cost view: an extra loop may refine representations, but CLP also introduces a positional mismatch at each loop boundary. We instantiate this study by training LoopCoder-v2, a family of 7B PLT coders with different loop counts, from scratch on 18T tokens, followed by matched instruction tuning and evaluation. Empirically, the two-loop variant delivers broad gains over the non-looped baseline across code generation, code reasoning, agentic software engineering, and tool-use benchmarks, improving SWE-bench Verified from 43.0 to 64.4 points and Multi-SWE from 14.0 to 31.0 points. In contrast, variants with three or more loops regress, revealing a strongly non-monotonic loop-count effect. Our diagnostics show that loop 2 provides the main productive refinement, while later loops yield diminishing, oscillatory updates and reduced representational diversity. Because the CLP-induced mismatch remains roughly fixed as refinement gains shrink, the offset cost increasingly dominates. This gain--cost trade-off explains PLT's saturation at two loops and provides diagnostics for loop-count selection.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.18023.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 319, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2606.13681", "authors": [{"_id": "6a2b77ca4957fcdd3aac06a4", "user": {"_id": "67580d23f498e0436ce182fb", "avatarUrl": "/avatars/696d1c91dbd43d267747d7e98af096bd.svg", "isPro": false, "fullname": "Jundong Xu", "user": "Aiden0526", "type": "user", "name": "Aiden0526"}, "name": "Jundong Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:31.093Z", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a5", "name": "Qingchuan Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a6", "name": "Jiaying Wu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a7", "name": "Yihuai Lan", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a8", "name": "Shuyue Stella Li", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06a9", "name": "Huichi Zhou", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06aa", "name": "Bowen Jiang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ab", "name": "Lei Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ac", "name": "Jun Wang", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ad", "name": "Anh Tuan Luu", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06ae", "name": "Caiming Xiong", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06af", "name": "Hae Won Park", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b0", "name": "Bryan Hooi", "hidden": false}, {"_id": "6a2b77ca4957fcdd3aac06b1", "name": "Zhiyuan Hu", "hidden": false}], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-12T00:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "submittedOnDailyBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "isPro": false, "fullname": "Zhiyuan Hu", "user": "zhiyuanhucs", "type": "user", "name": "zhiyuanhucs"}, "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "upvotes": 104, "discussionId": "6a2b77ca4957fcdd3aac06b2", "projectPage": "https://aiden0526.github.io/EvoArena/", "githubRepo": "https://github.com/Aiden0526/EvoArena", "githubRepoAddedBy": "user", "ai_summary": "EvoArena benchmark and EvoMem memory paradigm address the challenge of dynamic environments in LLM agents by modeling progressive updates and structured memory evolution, showing improved performance on evolving tasks.", "ai_keywords": ["large language model agents", "EvoArena", "EvoMem", "memory evolution", "environment changes", "progressive updates", "terminal domain", "software domain", "social domain", "chain-level accuracy", "mechanistic analysis"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 8, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "summary_zh": "<ul>\n    <li>\u5927\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u5728\u8bb8\u591a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u826f\u597d\uff0c\u4f46\u5927\u591a\u6570\u8bc4\u4f30\u5047\u8bbe\u73af\u5883\u662f\u9759\u6001\u7684\u3002</li>\n    <li>\u4e3a\u4e86\u5e94\u5bf9\u52a8\u6001\u73af\u5883\u7684\u9700\u6c42\uff0c\u63d0\u51fa\u4e86\u4e00\u4e2a\u65b0\u7684\u57fa\u51c6\u5957\u4ef6EvoArena\uff0c\u6a21\u62df\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>EvoMem\u662f\u4e00\u79cd\u57fa\u4e8e\u8865\u4e01\u7684\u8bb0\u5fc6\u6a21\u578b\uff0c\u8bb0\u5f55\u8bb0\u5fc6\u7684\u6f14\u53d8\uff0c\u5e2e\u52a9\u4ee3\u7406\u7406\u89e3\u73af\u5883\u53d8\u5316\u3002</li>\n    <li>\u5b9e\u9a8c\u663e\u793a\uff0c\u76ee\u524d\u7684\u4ee3\u7406\u5728EvoArena\u4e0a\u7684\u5e73\u5747\u51c6\u786e\u7387\u4e3a39.6%\u3002</li>\n    <li>EvoMem\u63d0\u9ad8\u4e86\u4ee3\u7406\u7684\u8868\u73b0\uff0c\u5e73\u5747\u63d0\u5347\u4e861.5%\u7684\u51c6\u786e\u7387\uff0c\u5e76\u6539\u5584\u4e86\u5176\u4ed6\u6807\u51c6\u57fa\u51c6\u7684\u8868\u73b0\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language model (LLM) agents perform well on tests, but most tests do not consider changing environments.</li>\n    <li>EvoArena is a new benchmark that simulates dynamic environments with updates in different areas like software and social interactions.</li>\n    <li>EvoMem is a memory system that helps agents track changes over time, improving their ability to adapt to new conditions.</li>\n    <li>Current agents only achieve about 39.6% accuracy on EvoArena, but EvoMem boosts their performance by an average of 1.5%.</li>\n    <li>The study shows that understanding and tracking changes in memory is crucial for effective agent performance in real-world situations.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "EvoArena: Tracking Memory Evolution for Robust LLM Agents in Dynamic Environments", "summary": "Large language model (LLM) agents have achieved strong performance on a wide range of benchmarks, yet most evaluations assume static environments. In contrast, real-world deployment is inherently dynamic, requiring agents to continually align their knowledge, skills, and behavior with changing environments and updated task conditions. To address this gap, we introduce EvoArena, a benchmark suite that models environment changes as sequences of progressive updates across terminal, software, and social domains. We further propose EvoMem, a patch-based memory paradigm that records memory evolution as structured update histories, enabling agents to reason about environmental evolution through changes in their memory. Experiments show that current agents struggle on EvoArena, achieving an average accuracy of 39.6% across evolving terminal, software, and social-preference domains. EvoMem consistently improves performance, yielding an average gain of 1.5% on EvoArena and also improving standard benchmarks such as GAIA and LoCoMo by 6.1% and 4.8%. Beyond individual tasks, EvoMem further improves chain-level accuracy by 3.7% on EvoArena, where success requires completing a consecutive sequence of related evolutionary subtasks. Mechanistic analysis shows that EvoMem improves evidence capture in the memory, indicating better preservation of complete evolving environment states. Our results highlight the importance of modeling evolution in both evaluation and memory for reliable agent deployment.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13681.png", "numComments": 1, "submittedBy": {"_id": "64351475901c5734bcb64248", "avatarUrl": "/avatars/12346d4301c1bfb00ce0ea128a93cc15.svg", "fullname": "Zhiyuan Hu", "name": "zhiyuanhucs", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "organization": {"_id": "63728bde14d543d507ae970d", "name": "MIT", "fullname": "Massachusetts Institute of Technology", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/S90qoeEJeEYaYf-c7Zs8g.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2606.11176", "authors": [{"_id": "6a28e548e7d78ea7587e5537", "user": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "name": "Kevin Qinghong Lin", "status": "claimed_verified", "statusLastChangedAt": "2026-06-11T08:42:18.205Z", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5538", "name": "Batu EI", "hidden": false}, {"_id": "6a28e548e7d78ea7587e5539", "name": "Yuhong Shi", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553a", "name": "Pan Lu", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553b", "name": "Philip Torr", "hidden": false}, {"_id": "6a28e548e7d78ea7587e553c", "name": "James Zou", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "publishedAt": "2026-06-09T00:00:00.000Z", "submittedOnDailyAt": "2026-06-16T00:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "submittedOnDailyBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "isPro": false, "fullname": "Qinghong (Kevin) Lin", "user": "KevinQHLin", "type": "user", "name": "KevinQHLin"}, "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "upvotes": 100, "discussionId": "6a28e548e7d78ea7587e553d", "projectPage": "https://data2story.github.io/", "githubRepo": "https://github.com/QinghongLin/data2story-skill", "githubRepoAddedBy": "user", "ai_summary": "A multi-agent framework automates data journalism by generating evidence-grounded, multimodal news stories while maintaining transparency and verifiability.", "ai_keywords": ["multi-agent framework", "data journalism", "evidence-grounded", "multimodal generation", "verifiability", "article generation", "data storytelling"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 45, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "summary_zh": "<ul>\n    <li>\u6570\u636e\u65b0\u95fb\u8bb0\u8005\u7684\u5de5\u4f5c\u662f\u5c06\u539f\u59cb\u4fe1\u606f\u8f6c\u5316\u4e3a\u53ef\u4fe1\u7684\u6545\u4e8b\u3002</li>\n    <li>Data2Story\u662f\u4e00\u4e2a\u591a\u667a\u80fd\u4f53\u6846\u67b6\uff0c\u80fd\u591f\u5c06\u4e0d\u540c\u7684\u4e13\u4e1a\u89d2\u8272\u6574\u5408\u5230\u4e00\u4e2a\u865a\u62df\u65b0\u95fb\u5ba4\u4e2d\u3002</li>\n    <li>\u8be5\u7cfb\u7edf\u63d0\u4f9b\u4e86\u4e24\u9879\u521b\u65b0\uff1a\u4e00\u662f\u6240\u6709\u4e3b\u5f20\u90fd\u6709\u8bc1\u636e\u652f\u6301\uff0c\u4e8c\u662f\u751f\u6210\u591a\u79cd\u5a92\u4f53\u5185\u5bb9\uff0c\u5982\u4e92\u52a8\u5730\u56fe\u548c\u97f3\u9891\u3002</li>\n    <li>Data2Story\u572818\u7bc7\u6587\u7ae0\u7684\u8bc4\u4f30\u4e2d\u8868\u73b0\u826f\u597d\uff0c\u5c24\u5176\u5728\u900f\u660e\u6027\u548c\u53ef\u5ba1\u8ba1\u6027\u65b9\u9762\u3002</li>\n    <li>\u5c3d\u7ba1Data2Story\u8868\u73b0\u51fa\u8272\uff0c\u4eba\u7c7b\u8bb0\u8005\u5728\u7f16\u8f91\u89d2\u5ea6\u3001\u521b\u610f\u8bbe\u8ba1\u548c\u5448\u73b0\u65b9\u9762\u4ecd\u6709\u4f18\u52bf\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Data journalists turn raw data into trustworthy stories for the public.</li>\n    <li>Data2Story is a new tool that combines different roles in a newsroom to create articles from start to finish.</li>\n    <li>It ensures claims in articles are backed by evidence and uses various media formats like maps and audio to enhance storytelling.</li>\n    <li>Data2Story has been tested against expert articles and performs well in areas like clarity and transparency.</li>\n    <li>While it shows strength in evidence-based reporting, human journalists still excel in creativity and design.</li>\n</ul>"}, "publishedAt": "2026-06-08T20:00:00.000Z", "title": "Data Journalist Agent: Transforming Data into Verifiable Multimodal Stories", "summary": "Data tells stories that shape society; the data journalist's job is to turn raw information into stories non-experts can trust. A high-quality news feature takes a newsroom team weeks: hunting for context, running statistics, choosing an angle, and designing visuals. Recent agents handle individual steps well: data-science agents close the analysis loop, while design agents synthesize beautiful websites. But can an agent serve as a data journalist end to end? We introduce Data Journalist Agent (Data2Story), a multi-agent framework that orchestrates specialized roles into a single virtual newsroom. Data2Story contributes two innovations. (i) Claims are evidence-grounded: an Inspector links every number, angle, and asset back to data, code, or an external reference. (ii) Articles are multimodally generative: rather than defaulting to plain text and static charts, Data2Story reasons about what readers will want to see, then deploys multimodal tools, such as interactive maps for geography and audio for music. We evaluate Data2Story on 18 articles, each paired with the originally published expert piece, along four axes: (a) human-agent angle coverage; (b) rubric evaluation with 53 participants across five dimensions; (c) computer-use agents as judges, a cost-saving proxy for how readers navigate interactive articles; and (d) verifiability, where a coding verifier re-executes statements against the data and checks claims against references. Data2Story produces competitive, evidence-traceable multimedia stories, with particular strength in transparency and auditability. Human articles retain an edge in editorial angle, creative design, and presentation. We position Data2Story as a collaborator for journalists, enabling more evidence-based, transparent, and verifiable reporting. Code and demos are available at https://data2story.github.io.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/64440be5af034cdfd69ca3a7/LsAABVvjGPA5Mjio-EkWd.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.11176.png", "numComments": 4, "submittedBy": {"_id": "64440be5af034cdfd69ca3a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64440be5af034cdfd69ca3a7/qmx24QiDFT29vleCxL9TX.jpeg", "fullname": "Qinghong (Kevin) Lin", "name": "KevinQHLin", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 49, "isUserFollowing": false}, "organization": {"_id": "627bbc28fbab61b048eba8b6", "name": "Oxford", "fullname": "University of Oxford", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/68e396f2b5bb631e9b2fac9a/u0ey2LfYu6uG6iu8m_kH7.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.07297", "authors": [{"_id": "6a26b590e4c258a0294923e5", "user": {"_id": "65db54e5ab2f64915c0b9cf0", "avatarUrl": "/avatars/d451523cad8c17cda603eea2961c50ad.svg", "isPro": false, "fullname": "Shaoqiu Zhang", "user": "qiushao", "type": "user", "name": "qiushao"}, "name": "Shaoqiu Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-09T12:45:33.488Z", "hidden": false}, {"_id": "6a26b590e4c258a0294923e6", "name": "Yuhang Wang", "hidden": false}, {"_id": "6a26b590e4c258a0294923e7", "name": "Jialiang Liang", "hidden": false}, {"_id": "6a26b590e4c258a0294923e8", "user": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "isPro": false, "fullname": "Yuling", "user": "YerbaPage", "type": "user", "name": "YerbaPage"}, "name": "Yuling Shi", "status": "claimed_verified", "statusLastChangedAt": "2026-06-09T12:45:35.921Z", "hidden": false}, {"_id": "6a26b590e4c258a0294923e9", "name": "Wenhao Zeng", "hidden": false}, {"_id": "6a26b590e4c258a0294923ea", "name": "Maoquan Wang", "hidden": false}, {"_id": "6a26b590e4c258a0294923eb", "name": "Shilin He", "hidden": false}, {"_id": "6a26b590e4c258a0294923ec", "name": "Ningyuan Xu", "hidden": false}, {"_id": "6a26b590e4c258a0294923ed", "name": "Siyu Ye", "hidden": false}, {"_id": "6a26b590e4c258a0294923ee", "name": "Kai Cai", "hidden": false}, {"_id": "6a26b590e4c258a0294923ef", "name": "Xiaodong Gu", "hidden": false}], "publishedAt": "2026-06-05T00:00:00.000Z", "submittedOnDailyAt": "2026-06-09T00:00:00.000Z", "title": "SWE-Explore: Benchmarking How Coding Agents Explore Repositories", "submittedOnDailyBy": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "isPro": false, "fullname": "Yuling", "user": "YerbaPage", "type": "user", "name": "YerbaPage"}, "summary": "Repository-level coding benchmarks such as SWE-bench have driven a rapid surge in the capabilities of coding agents. Yet they usually treat coding tasks as a holistic, binary prediction problem (e.g., resolved or unresolved), neglecting fine-grained agent capabilities such as repository understanding, context retrieval, code localization, and bug diagnosis. In this paper, we introduce SWE-Explore, a benchmark that isolates the evaluation of repository exploration, a critical capability of coding agents. Given a repository and an issue, SWE-Explore asks an explorer to return a ranked list of relevant code regions under a fixed line budget. SWE-Explore covers 848 issues across 10 programming languages and 203 open-source repositories. For each instance, we derive line-level ground truth from independent agent trajectories that successfully solved the same issue, distilling the specific code regions their solution paths actually consulted. We evaluate exploration along coverage, ranking, and context-efficiency dimensions, showing that these metrics strongly track downstream repair behavior. Across a broad set of retrieval methods, general coding agents, and specialized localizers, we find that agentic explorers form a clear tier above classical retrieval. While file-level localization is already strong for modern methods, line-level coverage and efficient ranking remain the key axes differentiating state-of-the-art explorers.", "upvotes": 98, "discussionId": "6a26b590e4c258a0294923f0", "projectPage": "https://huggingface.co/datasets/SWE-Explore-Bench/SWE-Explore-Bench", "githubRepo": "https://github.com/Qiushao-E/SWE-Explore-Bench", "githubRepoAddedBy": "user", "ai_summary": "SWE-Explore introduces a benchmark for evaluating coding agents' repository exploration capabilities by requiring ranked lists of relevant code regions within line budgets, demonstrating that agentic exploration outperforms traditional retrieval methods.", "ai_keywords": ["repository exploration", "coding agents", "SWE-bench", "SWE-Explore", "line budget", "code localization", "context retrieval", "repository understanding", "bug diagnosis", "retrieval methods", "agentic explorers", "line-level coverage", "ranking", "context-efficiency"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 13, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "summary_zh": "<ul>\n    <li>\u4ecb\u7ecd\u4e86SWE-Explore\u57fa\u51c6\uff0c\u4e13\u6ce8\u4e8e\u8bc4\u4f30\u7f16\u7801\u4ee3\u7406\u7684\u4ee3\u7801\u5e93\u63a2\u7d22\u80fd\u529b\u3002</li>\n    <li>SWE-Explore\u8981\u6c42\u4ee3\u7406\u5728\u56fa\u5b9a\u7684\u884c\u6570\u9884\u7b97\u4e0b\uff0c\u8fd4\u56de\u76f8\u5173\u4ee3\u7801\u533a\u57df\u7684\u6392\u540d\u5217\u8868\u3002</li>\n    <li>\u57fa\u51c6\u8986\u76d6\u4e86848\u4e2a\u95ee\u9898\uff0c\u6d89\u53ca10\u79cd\u7f16\u7a0b\u8bed\u8a00\u548c203\u4e2a\u5f00\u6e90\u4ee3\u7801\u5e93\u3002</li>\n    <li>\u901a\u8fc7\u72ec\u7acb\u4ee3\u7406\u7684\u8f68\u8ff9\u63d0\u53d6\u7ebf\u7ea7\u771f\u76f8\uff0c\u8bc4\u4f30\u63a2\u7d22\u80fd\u529b\u7684\u8986\u76d6\u7387\u3001\u6392\u540d\u548c\u4e0a\u4e0b\u6587\u6548\u7387\u3002</li>\n    <li>\u7814\u7a76\u53d1\u73b0\uff0c\u4ee3\u7406\u63a2\u7d22\u8005\u660e\u663e\u4f18\u4e8e\u4f20\u7edf\u68c0\u7d22\u65b9\u6cd5\uff0c\u884c\u7ea7\u8986\u76d6\u548c\u9ad8\u6548\u6392\u540d\u662f\u533a\u5206\u9876\u5c16\u63a2\u7d22\u8005\u7684\u5173\u952e\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>SWE-Explore is a new benchmark designed to evaluate coding agents' ability to explore code repositories.</li>\n    <li>It focuses on specific tasks like understanding repositories, finding relevant code, and diagnosing bugs, rather than just whether a coding task is completed.</li>\n    <li>The benchmark includes 848 issues from 10 programming languages and 203 open-source repositories.</li>\n    <li>It measures how well agents can find relevant code by looking at coverage, ranking, and efficiency, which are important for fixing issues.</li>\n    <li>The results show that advanced coding agents perform better than traditional methods in exploring code effectively.</li>\n</ul>"}, "publishedAt": "2026-06-04T20:00:00.000Z", "title": "SWE-Explore: Benchmarking How Coding Agents Explore Repositories", "summary": "Repository-level coding benchmarks such as SWE-bench have driven a rapid surge in the capabilities of coding agents. Yet they usually treat coding tasks as a holistic, binary prediction problem (e.g., resolved or unresolved), neglecting fine-grained agent capabilities such as repository understanding, context retrieval, code localization, and bug diagnosis. In this paper, we introduce SWE-Explore, a benchmark that isolates the evaluation of repository exploration, a critical capability of coding agents. Given a repository and an issue, SWE-Explore asks an explorer to return a ranked list of relevant code regions under a fixed line budget. SWE-Explore covers 848 issues across 10 programming languages and 203 open-source repositories. For each instance, we derive line-level ground truth from independent agent trajectories that successfully solved the same issue, distilling the specific code regions their solution paths actually consulted. We evaluate exploration along coverage, ranking, and context-efficiency dimensions, showing that these metrics strongly track downstream repair behavior. Across a broad set of retrieval methods, general coding agents, and specialized localizers, we find that agentic explorers form a clear tier above classical retrieval. While file-level localization is already strong for modern methods, line-level coverage and efficient ranking remain the key axes differentiating state-of-the-art explorers.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.07297.png", "numComments": 1, "submittedBy": {"_id": "645b0c3ec35da9c7afd95421", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/645b0c3ec35da9c7afd95421/vYBrCDagHsXAo6J2p-uG0.jpeg", "fullname": "Yuling", "name": "YerbaPage", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 105, "isUserFollowing": false}, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.19195", "authors": [{"_id": "6a3407a3fc3a8b1102d9442a", "user": {"_id": "66d0ba2420e64fc408564bbb", "avatarUrl": "/avatars/355566cfb6347750a5faab7c87fcb79c.svg", "isPro": false, "fullname": "Anduin Dan", "user": "AnduinD", "type": "user", "name": "AnduinD"}, "name": "Kangsheng Duan", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:45.706Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442b", "user": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "name": "Ziyang Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-06-19T14:20:28.418Z", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442c", "name": "Wenyu Liu", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442d", "name": "Xiaohu Ruan", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442e", "name": "Xiaoxin Chen", "hidden": false}, {"_id": "6a3407a3fc3a8b1102d9442f", "name": "Xinggang Wang", "hidden": false}], "publishedAt": "2026-06-17T00:00:00.000Z", "submittedOnDailyAt": "2026-06-19T00:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "submittedOnDailyBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "isPro": false, "fullname": "Ziyang Xu", "user": "Uyoung", "type": "user", "name": "Uyoung"}, "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "upvotes": 97, "discussionId": "6a3407a3fc3a8b1102d94430", "projectPage": "https://hustvl.github.io/Moebius", "githubRepo": "https://github.com/hustvl/Moebius", "githubRepoAddedBy": "user", "ai_summary": "A lightweight image inpainting framework achieves high-fidelity results with significantly reduced parameters and inference time through novel local-global interaction blocks and adaptive distillation strategies.", "ai_keywords": ["diffusion backbone", "Local-\u03bb Mix Interaction", "L\u03bbMI block", "spatial contexts", "global semantic priors", "fixed-size linear matrices", "representation bottleneck", "adaptive multi-granularity distillation", "latent space", "gradient-based losses", "high-fidelity inpainting", "parameter-efficient fine-tuning"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 52, "summary_zh": "<ul>\n    <li>Moebius\u662f\u4e00\u4e2a\u9ad8\u6548\u7684\u8f7b\u91cf\u7ea7\u56fe\u50cf\u4fee\u590d\u6846\u67b6\uff0c\u65e8\u5728\u964d\u4f4e\u8ba1\u7b97\u6210\u672c\u3002</li>\n    <li>\u901a\u8fc7\u5f15\u5165Local-\u03bb Mix Interaction (L\u03bbMI)\u6a21\u5757\uff0cMoebius\u4f18\u5316\u4e86\u6269\u6563\u6a21\u578b\u7684\u7ed3\u6784\u3002</li>\n    <li>\u8be5\u6846\u67b6\u80fd\u591f\u6709\u6548\u603b\u7ed3\u7a7a\u95f4\u4e0a\u4e0b\u6587\u548c\u5168\u7403\u8bed\u4e49\uff0c\u51cf\u5c11\u53c2\u6570\u6570\u91cf\u3002</li>\n    <li>\u4f7f\u7528\u81ea\u9002\u5e94\u591a\u7c92\u5ea6\u84b8\u998f\u7b56\u7565\uff0cMoebius\u5728\u6f5c\u5728\u7a7a\u95f4\u5185\u8fdb\u884c\u64cd\u4f5c\uff0c\u907f\u514d\u9ad8\u6210\u672c\u7684\u50cf\u7d20\u7a7a\u95f4\u89e3\u7801\u3002</li>\n    <li>Moebius\u7684\u751f\u6210\u8d28\u91cf\u4e0e10B\u7ea7\u7684\u5de5\u4e1a\u6a21\u578b\u76f8\u5f53\uff0c\u4f46\u53c2\u6570\u4ec5\u4e3a2%\uff0c\u5e76\u4e14\u63a8\u7406\u901f\u5ea6\u63d0\u9ad8\u4e8615\u500d\u4ee5\u4e0a\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Moebius is a new, efficient framework for image inpainting that addresses the high costs of current large models.</li>\n    <li>It uses a special design called Local-\u03bb Mix Interaction (L\u03bbMI) to simplify complex data while reducing the number of parameters needed.</li>\n    <li>Moebius combines this design with a smart training strategy that works in a more efficient way to improve image quality.</li>\n    <li>Tests show that Moebius can match or exceed the image quality of much larger models, while using only a tiny fraction of the resources.</li>\n    <li>It is significantly faster, achieving over 15 times quicker processing than traditional models.</li>\n</ul>"}, "publishedAt": "2026-06-16T20:00:00.000Z", "title": "Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance", "summary": "While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-\u03bb Mix Interaction (L\u03bbMI) block. Comprising Local-\u03bb and Interactive-\u03bb modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a >15times acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.19195.png", "numComments": 4, "submittedBy": {"_id": "633d4630e1aec4b8b33ad5b8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/633d4630e1aec4b8b33ad5b8/owFqnyCMW8yuo9VcjA1hx.jpeg", "fullname": "Ziyang Xu", "name": "Uyoung", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2606.13432", "authors": [{"_id": "6a2b941e4957fcdd3aac074c", "name": "Jiwen Liu", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac074d", "user": {"_id": "64e57e521412b511e4388310", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64e57e521412b511e4388310/1DL-B1TJL9jEcnsy4N_46.jpeg", "isPro": false, "fullname": "Shujuan Li", "user": "lisj575", "type": "user", "name": "lisj575"}, "name": "Shujuan Li", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T06:56:24.073Z", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac074e", "name": "Zhixue Fang", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac074f", "name": "Xiaohan Li", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0750", "name": "Yan Zhou", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0751", "name": "Zijie Meng", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0752", "user": {"_id": "65e67be231de1c098be18f5f", "avatarUrl": "/avatars/1dfc363140f5161d8b06ba0ad948530b.svg", "isPro": false, "fullname": "Zhimin Zhang", "user": "zmmm", "type": "user", "name": "zmmm"}, "name": "Zhimin Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-06-15T12:23:04.022Z", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0753", "user": {"_id": "66743477ab975c859114d410", "avatarUrl": "/avatars/ac692cc336e383fb2cb53db6d1e3fe8c.svg", "isPro": false, "fullname": "yawenluo", "user": "yawenluo", "type": "user", "name": "yawenluo"}, "name": "Yawen Luo", "status": "claimed_verified", "statusLastChangedAt": "2026-06-12T08:13:30.433Z", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0754", "name": "Guoxin Zhang", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0755", "name": "Yu-Shen Liu", "hidden": false}, {"_id": "6a2b941e4957fcdd3aac0756", "name": "Pengfei Wan", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66743477ab975c859114d410/DZYTYGj5Ahz1xIFKDRkIZ.mp4"], "publishedAt": "2026-06-11T00:00:00.000Z", "submittedOnDailyAt": "2026-06-15T00:00:00.000Z", "title": "OmniDirector: General Multi-Shot Camera Cloning without Cross-Paired Data", "submittedOnDailyBy": {"_id": "66743477ab975c859114d410", "avatarUrl": "/avatars/ac692cc336e383fb2cb53db6d1e3fe8c.svg", "isPro": false, "fullname": "yawenluo", "user": "yawenluo", "type": "user", "name": "yawenluo"}, "summary": "Cloning camera motion from reference videos is an important task in video generation, as videos provide intuitive and precise control. Existing methods either directly use parametric representations that fail to handle multi-shot generation or synthesize cross-paired data, which suffer from data scarcity, resulting in poor performance in complicated camera motion cloning. To address these issues, we introduce a general camera motion representation that encodes cameras as grid motion videos. This camera grid represents the camera parameters visually and supports the integration of diverse trajectories for multi-shot video generation. Building upon this, we propose OmniDirector, a unified framework trained on a million-scale camera grid-video pairs that coordinates characters, actions, and cameras to provide director-level control for multimodal diffusion transformers. Furthermore, we design a novel hierarchical prompt expansion agent that harmoniously integrates different control signals by systematically describing camera motion and visual content through understanding signal relationships. Extensive experiments demonstrate the superior performance and outstanding controllability of our framework. Project page: https://ymlinfeng.github.io/OmniDirector.github.io/", "upvotes": 91, "discussionId": "6a2b941f4957fcdd3aac0757", "projectPage": "https://ymlinfeng.github.io/OmniDirector.github.io/", "githubRepo": "https://github.com/lisj575/OmniDirector", "githubRepoAddedBy": "user", "ai_summary": "A unified framework for camera motion cloning that uses grid motion videos as representation and integrates multimodal diffusion transformers for enhanced video generation control.", "ai_keywords": ["camera motion cloning", "camera grid", "multimodal diffusion transformers", "hierarchical prompt expansion agent", "video generation", "parametric representations", "cross-paired data", "camera parameters", "grid motion videos", "director-level control"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 27, "organization": {"_id": "662c559b322afcbae51b3c8b", "name": "KlingTeam", "fullname": "Kling Team", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60e272ca6c78a8c122b12127/ZQV1aKLUDPf2rUcxxAqj6.jpeg"}, "summary_zh": "<ul>\n    <li>\u514b\u9686\u53c2\u8003\u89c6\u9891\u4e2d\u7684\u76f8\u673a\u8fd0\u52a8\u5bf9\u89c6\u9891\u751f\u6210\u5f88\u91cd\u8981\uff0c\u56e0\u4e3a\u5b83\u63d0\u4f9b\u76f4\u89c2\u548c\u7cbe\u786e\u7684\u63a7\u5236\u3002</li>\n    <li>\u73b0\u6709\u65b9\u6cd5\u8981\u4e48\u4f7f\u7528\u53c2\u6570\u8868\u793a\uff0c\u65e0\u6cd5\u5904\u7406\u591a\u955c\u5934\u751f\u6210\uff0c\u8981\u4e48\u5408\u6210\u4ea4\u53c9\u914d\u5bf9\u6570\u636e\uff0c\u5bfc\u81f4\u6570\u636e\u7a00\u7f3a\uff0c\u6027\u80fd\u8f83\u5dee\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u901a\u7528\u7684\u76f8\u673a\u8fd0\u52a8\u8868\u793a\uff0c\u5c06\u76f8\u673a\u7f16\u7801\u4e3a\u7f51\u683c\u8fd0\u52a8\u89c6\u9891\uff0c\u652f\u6301\u591a\u955c\u5934\u89c6\u9891\u751f\u6210\u3002</li>\n    <li>\u57fa\u4e8e\u6b64\uff0c\u6211\u4eec\u63d0\u51fa\u4e86OmniDirector\u6846\u67b6\uff0c\u4f7f\u7528\u767e\u4e07\u89c4\u6a21\u7684\u76f8\u673a\u7f51\u683c-\u89c6\u9891\u5bf9\u8fdb\u884c\u8bad\u7ec3\uff0c\u534f\u8c03\u89d2\u8272\u3001\u52a8\u4f5c\u548c\u76f8\u673a\u4ee5\u5b9e\u73b0\u5bfc\u6f14\u7ea7\u63a7\u5236\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u8bbe\u8ba1\u4e86\u4e00\u79cd\u65b0\u9896\u7684\u5c42\u6b21\u5316\u63d0\u793a\u6269\u5c55\u4ee3\u7406\uff0c\u7cfb\u7edf\u5730\u63cf\u8ff0\u76f8\u673a\u8fd0\u52a8\u548c\u89c6\u89c9\u5185\u5bb9\uff0c\u589e\u5f3a\u4e0d\u540c\u63a7\u5236\u4fe1\u53f7\u7684\u6574\u5408\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Cloning camera motion from videos is important for generating videos accurately.</li>\n    <li>Current methods struggle with multi-shot videos and often have data issues, leading to poor results.</li>\n    <li>We introduce a new way to represent camera motion using grid motion videos, which helps in generating multi-shot videos.</li>\n    <li>Our framework, OmniDirector, uses a large dataset to coordinate characters, actions, and cameras for better video control.</li>\n    <li>We created a system that combines different control signals to improve camera motion and visual content understanding.</li>\n</ul>"}, "publishedAt": "2026-06-10T20:00:00.000Z", "title": "OmniDirector: General Multi-Shot Camera Cloning without Cross-Paired Data", "summary": "Cloning camera motion from reference videos is an important task in video generation, as videos provide intuitive and precise control. Existing methods either directly use parametric representations that fail to handle multi-shot generation or synthesize cross-paired data, which suffer from data scarcity, resulting in poor performance in complicated camera motion cloning. To address these issues, we introduce a general camera motion representation that encodes cameras as grid motion videos. This camera grid represents the camera parameters visually and supports the integration of diverse trajectories for multi-shot video generation. Building upon this, we propose OmniDirector, a unified framework trained on a million-scale camera grid-video pairs that coordinates characters, actions, and cameras to provide director-level control for multimodal diffusion transformers. Furthermore, we design a novel hierarchical prompt expansion agent that harmoniously integrates different control signals by systematically describing camera motion and visual content through understanding signal relationships. Extensive experiments demonstrate the superior performance and outstanding controllability of our framework. Project page: https://ymlinfeng.github.io/OmniDirector.github.io/", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66743477ab975c859114d410/DZYTYGj5Ahz1xIFKDRkIZ.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.13432.png", "numComments": 3, "submittedBy": {"_id": "66743477ab975c859114d410", "avatarUrl": "/avatars/ac692cc336e383fb2cb53db6d1e3fe8c.svg", "fullname": "yawenluo", "name": "yawenluo", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "662c559b322afcbae51b3c8b", "name": "KlingTeam", "fullname": "Kling Team", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60e272ca6c78a8c122b12127/ZQV1aKLUDPf2rUcxxAqj6.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2606.24775", "authors": [{"_id": "6a3c9fedf3facdb67e9ff137", "name": "Wei Zhou", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff138", "name": "Xuanhe Zhou", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff139", "name": "Shaokun Han", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13a", "name": "Hongming Xu", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13b", "name": "Guoliang Li", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13c", "name": "Zhiyu Li", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13d", "name": "Feiyu Xiong", "hidden": false}, {"_id": "6a3c9fedf3facdb67e9ff13e", "name": "Fan Wu", "hidden": false}], "publishedAt": "2026-06-23T00:00:00.000Z", "submittedOnDailyAt": "2026-06-25T00:00:00.000Z", "title": "Are We Ready For An Agent-Native Memory System?", "submittedOnDailyBy": {"_id": "68216c63856b96f869d1d116", "avatarUrl": "/avatars/f69026ca75377e6754ab3e317879e35a.svg", "isPro": false, "fullname": "Wei Zhou", "user": "weizhoudb", "type": "user", "name": "weizhoudb"}, "summary": "Memory for large language model (LLM) agents has rapidly evolved from simple retrieval-augmented mechanisms into a data management system that supports persistent information storage, retrieval, update, consolidation, and dynamic lifecycle governance throughout agent execution. Despite this evolution, existing evaluations still benchmark agent memory mainly through end-to-end task success metrics (e.g., F1, BLEU), while treating the underlying system as a monolithic black box. As a result, critical system-level concerns, including operational costs, architectural trade-offs across memory modules, and robustness under dynamic knowledge updates, remain insufficiently explored. In this paper, we present a systematic experimental study of agent memory from a data management perspective. We propose an analytical framework that decomposes agent memory into four core modules: memory representation and storage, extraction, retrieval and routing, and maintenance. Under this framework, we evaluate 12 representative memory systems and two reference baselines across five benchmark workloads spanning 11 datasets. Our extensive end-to-end evaluation shows that no single architecture dominates across all scenarios; instead, effectiveness depends heavily on how well the memory structure aligns with the workload bottleneck. Furthermore, through fine-grained ablation studies, we quantify their individual effects on representation fidelity, retrieval precision, update correctness, and long-horizon stability. Finally, we reveal cost-performance trade-offs under realistic workloads, showing localized maintenance is more cost-efficient than global reorganization. Based on these findings, we identify promising directions towards building truly agent-native memory systems. The code is publicly available at https://github.com/OpenDataBox/MemoryData.", "upvotes": 89, "discussionId": "6a3c9fedf3facdb67e9ff13f", "projectPage": "https://github.com/OpenDataBox/awesome-agent-memory", "githubRepo": "https://github.com/OpenDataBox/MemoryData", "githubRepoAddedBy": "user", "ai_summary": "Large language model agents' memory systems have evolved into complex data management frameworks requiring systematic evaluation across multiple modules and workloads to understand their performance characteristics and trade-offs.", "ai_keywords": ["large language model agents", "memory representation and storage", "extraction", "retrieval and routing", "maintenance", "agent-native memory systems", "data management perspective", "memory modules", "workload bottleneck", "representation fidelity", "retrieval precision", "update correctness", "long-horizon stability", "cost-performance trade-offs"], "ai_summary_model": "Qwen/Qwen2.5-Coder-32B-Instruct", "githubStars": 20, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLM\uff09\u4ee3\u7406\u7684\u8bb0\u5fc6\u7cfb\u7edf\u5df2\u4ece\u7b80\u5355\u7684\u68c0\u7d22\u673a\u5236\u53d1\u5c55\u4e3a\u652f\u6301\u6301\u4e45\u4fe1\u606f\u5b58\u50a8\u548c\u52a8\u6001\u7ba1\u7406\u7684\u6570\u636e\u7ba1\u7406\u7cfb\u7edf\u3002</li>\n    <li>\u73b0\u6709\u8bc4\u4f30\u4e3b\u8981\u901a\u8fc7\u4efb\u52a1\u6210\u529f\u7387\u6765\u8861\u91cf\u4ee3\u7406\u8bb0\u5fc6\uff0c\u672a\u6df1\u5165\u63a2\u8ba8\u7cfb\u7edf\u7ea7\u522b\u7684\u5173\u952e\u95ee\u9898\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u4e86\u4e00\u4e2a\u5206\u6790\u6846\u67b6\uff0c\u5c06\u4ee3\u7406\u8bb0\u5fc6\u5206\u4e3a\u56db\u4e2a\u6838\u5fc3\u6a21\u5757\uff0c\u5e76\u5bf912\u4e2a\u8bb0\u5fc6\u7cfb\u7edf\u8fdb\u884c\u4e86\u8bc4\u4f30\u3002</li>\n    <li>\u7814\u7a76\u53d1\u73b0\u6ca1\u6709\u5355\u4e00\u67b6\u6784\u5728\u6240\u6709\u573a\u666f\u4e2d\u8868\u73b0\u6700\u4f73\uff0c\u6548\u679c\u4f9d\u8d56\u4e8e\u8bb0\u5fc6\u7ed3\u6784\u4e0e\u5de5\u4f5c\u8d1f\u8f7d\u7684\u5339\u914d\u7a0b\u5ea6\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793a\u5c40\u90e8\u7ef4\u62a4\u6bd4\u5168\u5c40\u91cd\u7ec4\u66f4\u5177\u6210\u672c\u6548\u76ca\uff0c\u5e76\u4e3a\u6784\u5efa\u66f4\u597d\u7684\u4ee3\u7406\u8bb0\u5fc6\u7cfb\u7edf\u63d0\u4f9b\u4e86\u65b9\u5411\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Memory for large language model agents has improved to include persistent storage and management of information.</li>\n    <li>Current evaluations of agent memory focus too much on task success metrics and overlook important system-level issues.</li>\n    <li>This paper introduces a framework that breaks down agent memory into four main components for better analysis.</li>\n    <li>Experiments show that no single memory architecture works best for all tasks; effectiveness varies based on specific workloads.</li>\n    <li>The study highlights cost-performance trade-offs and suggests localized maintenance is more efficient than global changes.</li>\n</ul>"}, "publishedAt": "2026-06-22T20:00:00.000Z", "title": "Are We Ready For An Agent-Native Memory System?", "summary": "Memory for large language model (LLM) agents has rapidly evolved from simple retrieval-augmented mechanisms into a data management system that supports persistent information storage, retrieval, update, consolidation, and dynamic lifecycle governance throughout agent execution. Despite this evolution, existing evaluations still benchmark agent memory mainly through end-to-end task success metrics (e.g., F1, BLEU), while treating the underlying system as a monolithic black box. As a result, critical system-level concerns, including operational costs, architectural trade-offs across memory modules, and robustness under dynamic knowledge updates, remain insufficiently explored. In this paper, we present a systematic experimental study of agent memory from a data management perspective. We propose an analytical framework that decomposes agent memory into four core modules: memory representation and storage, extraction, retrieval and routing, and maintenance. Under this framework, we evaluate 12 representative memory systems and two reference baselines across five benchmark workloads spanning 11 datasets. Our extensive end-to-end evaluation shows that no single architecture dominates across all scenarios; instead, effectiveness depends heavily on how well the memory structure aligns with the workload bottleneck. Furthermore, through fine-grained ablation studies, we quantify their individual effects on representation fidelity, retrieval precision, update correctness, and long-horizon stability. Finally, we reveal cost-performance trade-offs under realistic workloads, showing localized maintenance is more cost-efficient than global reorganization. Based on these findings, we identify promising directions towards building truly agent-native memory systems. The code is publicly available at https://github.com/OpenDataBox/MemoryData.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2606.24775.png", "numComments": 3, "submittedBy": {"_id": "68216c63856b96f869d1d116", "avatarUrl": "/avatars/f69026ca75377e6754ab3e317879e35a.svg", "fullname": "Wei Zhou", "name": "weizhoudb", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "organization": {"_id": "63e5ef7bf2e9a8f22c515654", "name": "SJTU", "fullname": "Shanghai Jiao Tong University", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1676013394657-63e5ee22b6a40bf941da0928.png"}, "isAuthorParticipating": false}]
};
